#[pyfunction]
#[pyo3(signature = (a, indices, axis=None))]
fn take(
    py: Python<'_>,
    a: Py<PyAny>,
    indices: Py<PyAny>,
    axis: Option<isize>,
) -> PyResult<Py<PyAny>> {
    let a_for_fallback = a.clone_ref(py);
    let indices_for_fallback = indices.clone_ref(py);
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let kwargs = PyDict::new(py);
        if let Some(axis) = axis {
            kwargs.set_item("axis", axis)?;
        }
        Ok(numpy
            .getattr("take")?
            .call(
                (a_for_fallback.bind(py), indices_for_fallback.bind(py)),
                Some(&kwargs),
            )?
            .unbind())
    };
    let a = extract_numeric_array(py, a.bind(py), "take(a)")?;
    let (indices_shape, flat_indices) =
        extract_take_indices(py, indices.bind(py), "take(indices)")?;
    // numpy.take raises IndexError (not ValueError) for out-of-range index.
    // Our ufunc layer returns Msg("take: index X out of bounds ..."), which
    // map_ufunc_error would flatten to PyValueError. Fall back so the
    // exception type, message, and traceback all match numpy exactly.
    let mut result = match a.take(&flat_indices, axis) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };

    let desired_shape = match axis {
        None => indices_shape.clone(),
        Some(axis) => {
            let ndim = a.shape().len();
            let normalized_axis = if axis < 0 {
                axis + isize::try_from(ndim).map_err(|_| {
                    PyValueError::new_err("take: array rank exceeds signed axis range")
                })?
            } else {
                axis
            };

            if normalized_axis < 0
                || normalized_axis
                    >= isize::try_from(ndim).map_err(|_| {
                        PyValueError::new_err("take: array rank exceeds signed axis range")
                    })?
            {
                return Err(PyValueError::new_err(format!(
                    "take: axis {axis} is out of bounds for array of dimension {ndim}",
                )));
            }

            let normalized_axis = usize::try_from(normalized_axis).map_err(|_| {
                PyValueError::new_err(format!(
                    "take: axis {axis} is out of bounds for array of dimension {ndim}",
                ))
            })?;

            let mut shape =
                Vec::with_capacity(a.shape().len().saturating_sub(1) + indices_shape.len());
            shape.extend_from_slice(&a.shape()[..normalized_axis]);
            shape.extend_from_slice(&indices_shape);
            shape.extend_from_slice(&a.shape()[normalized_axis + 1..]);
            shape
        }
    };

    if result.shape() != desired_shape.as_slice() {
        let reshape_spec = desired_shape
            .iter()
            .map(|&dim| {
                isize::try_from(dim).map_err(|_| {
                    PyValueError::new_err("take: output shape exceeds signed reshape range")
                })
            })
            .collect::<PyResult<Vec<_>>>()?;
        result = result.reshape(&reshape_spec).map_err(map_ufunc_error)?;
    }

    let output = build_numpy_array_from_ufunc(py, &result)?;
    if desired_shape.is_empty() {
        return Ok(output.bind(py).get_item(PyTuple::empty(py))?.unbind());
    }

    Ok(output)
}

#[pyfunction]
#[pyo3(signature = (a, axis=None, keepdims=false))]
fn count_nonzero(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    keepdims: bool,
) -> PyResult<Py<PyAny>> {
    let a_for_fallback = a.clone_ref(py);
    let axis_for_fallback = axis.as_ref().map(|v| v.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let kwargs = PyDict::new(py);
        if let Some(ax) = &axis_for_fallback {
            kwargs.set_item("axis", ax.bind(py))?;
        }
        kwargs.set_item("keepdims", keepdims)?;
        Ok(numpy
            .getattr("count_nonzero")?
            .call((a_for_fallback.bind(py),), Some(&kwargs))?
            .unbind())
    };

    let a_array = extract_numeric_array(py, a.bind(py), "count_nonzero(a)")?;
    let axes = extract_axis_spec(py, axis, "count_nonzero")?;
    // Out-of-bounds / duplicate axes: numpy raises AxisError (a subclass of
    // ValueError). Fall back to numpy so the error type matches exactly.
    if let Some(axes) = axes.as_ref() {
        let ndim = a_array.shape().len();
        if ensure_unique_axes(axes, ndim).is_err() {
            return fallback();
        }
        for &ax in axes {
            if try_normalize_axis(ax, ndim).is_none() {
                return fallback();
            }
        }
    }
    let a = a_array;
    let result = match axes.as_ref() {
        None => a.count_nonzero(None, keepdims),
        Some(axes) if axes.len() == 1 => a.count_nonzero(Some(axes[0]), keepdims),
        Some(axes) => a.count_nonzero_axes(axes, keepdims),
    }
    .map_err(map_ufunc_error)?;

    let output = build_numpy_array_from_ufunc(py, &result)?;
    if result.shape().is_empty() {
        // numpy.count_nonzero(arr, axis=None) returns a numpy.int64 (0-D
        // scalar), NOT a plain Python int — its repr is "np.int64(3)".
        // Unlike numpy.ma.count which *does* return Python int for
        // axis=None, count_nonzero preserves the numpy scalar type.
        // Extract via get_item(()) which yields the 0-D numpy scalar.
        return Ok(output.bind(py).get_item(())?.unbind());
    }

    Ok(output)
}

fn extract_expand_dims_axes(
    py: Python<'_>,
    axis: Py<PyAny>,
    input_ndim: usize,
) -> PyResult<Vec<isize>> {
    let Some(axes) = extract_axis_spec(py, Some(axis), "expand_dims")? else {
        return Err(PyTypeError::new_err(
            "'NoneType' object cannot be interpreted as an integer",
        ));
    };

    let new_ndim = input_ndim + axes.len();
    ensure_unique_axes(&axes, new_ndim)?;
    Ok(axes)
}

#[pyfunction]
fn expand_dims(py: Python<'_>, a: Py<PyAny>, axis: Py<PyAny>) -> PyResult<Py<PyAny>> {
    let a_for_fallback = a.clone_ref(py);
    let axis_for_fallback = axis.clone_ref(py);
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        Ok(numpy
            .getattr("expand_dims")?
            .call1((a_for_fallback.bind(py), axis_for_fallback.bind(py)))?
            .unbind())
    };
    let a = extract_numeric_array(py, a.bind(py), "expand_dims(a)")?;
    let axes = extract_expand_dims_axes(py, axis, a.shape().len())?;
    // Out-of-bounds axis: numpy raises AxisError (subclass of ValueError).
    // Fall back so the error type and message match exactly.
    let new_ndim = a.shape().len() + axes.len();
    for &ax in &axes {
        if try_normalize_axis(ax, new_ndim).is_none() {
            return fallback();
        }
    }
    let result = match axes.as_slice() {
        [axis] => a.expand_dims(*axis).map_err(map_ufunc_error)?,
        axes => a.expand_dims_axes(axes).map_err(map_ufunc_error)?,
    };
    build_numpy_array_from_ufunc(py, &result)
}

