#[pyfunction]
#[pyo3(signature = (iter, dtype, count=-1_i64, *, like=None))]
fn fromiter(
    py: Python<'_>,
    iter: Py<PyAny>,
    dtype: Py<PyAny>,
    count: i64,
    like: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    if let Some(like_val) = like.as_ref()
        && !like_val.bind(py).is_none()
    {
        let kwargs = PyDict::new(py);
        kwargs.set_item("count", count)?;
        kwargs.set_item("like", like_val.bind(py))?;
        return Ok(numpy
            .getattr("fromiter")?
            .call((iter.bind(py), dtype.bind(py)), Some(&kwargs))?
            .unbind());
    }

    let dtype_obj = numpy.getattr("dtype")?.call1((dtype.bind(py),))?;
    let dtype_name = dtype_obj.getattr("name")?.extract::<String>()?;
    let parsed_dtype = DType::parse(&dtype_name).ok_or_else(|| {
        PyTypeError::new_err(format!("fromiter(dtype): unsupported dtype {dtype_name}"))
    })?;
    let scalar_type = dtype_obj.getattr("type")?;

    let storage = match parsed_dtype {
        DType::Bool => ArrayStorage::Bool(collect_fromiter_values(
            iter.bind(py),
            &scalar_type,
            count,
            |value| value.extract::<bool>(),
        )?),
        DType::I8 => ArrayStorage::I8(collect_fromiter_values(
            iter.bind(py),
            &scalar_type,
            count,
            |value| value.extract::<i8>(),
        )?),
        DType::I16 => ArrayStorage::I16(collect_fromiter_values(
            iter.bind(py),
            &scalar_type,
            count,
            |value| value.extract::<i16>(),
        )?),
        DType::I32 => ArrayStorage::I32(collect_fromiter_values(
            iter.bind(py),
            &scalar_type,
            count,
            |value| value.extract::<i32>(),
        )?),
        DType::I64 => ArrayStorage::I64(collect_fromiter_values(
            iter.bind(py),
            &scalar_type,
            count,
            |value| value.extract::<i64>(),
        )?),
        DType::U8 => ArrayStorage::U8(collect_fromiter_values(
            iter.bind(py),
            &scalar_type,
            count,
            |value| value.extract::<u8>(),
        )?),
        DType::U16 => ArrayStorage::U16(collect_fromiter_values(
            iter.bind(py),
            &scalar_type,
            count,
            |value| value.extract::<u16>(),
        )?),
        DType::U32 => ArrayStorage::U32(collect_fromiter_values(
            iter.bind(py),
            &scalar_type,
            count,
            |value| value.extract::<u32>(),
        )?),
        DType::U64 => ArrayStorage::U64(collect_fromiter_values(
            iter.bind(py),
            &scalar_type,
            count,
            |value| value.extract::<u64>(),
        )?),
        DType::F16 => ArrayStorage::F16(collect_fromiter_values(
            iter.bind(py),
            &scalar_type,
            count,
            |value| value.extract::<f32>().map(f16::from_f32),
        )?),
        DType::F32 => ArrayStorage::F32(collect_fromiter_values(
            iter.bind(py),
            &scalar_type,
            count,
            |value| value.extract::<f32>(),
        )?),
        DType::F64 => ArrayStorage::F64(collect_fromiter_values(
            iter.bind(py),
            &scalar_type,
            count,
            |value| value.extract::<f64>(),
        )?),
        DType::Complex64
        | DType::Complex128
        | DType::Str
        | DType::Structured
        | DType::DateTime64
        | DType::TimeDelta64 => {
            let kwargs = PyDict::new(py);
            kwargs.set_item("count", count)?;
            return Ok(numpy
                .getattr("fromiter")?
                .call((iter.bind(py), dtype.bind(py)), Some(&kwargs))?
                .unbind());
        }
    };

    // Rust-owned path for builtin scalar numeric dtypes. This preserves
    // numpy's iterator consumption and short-iterator error surface while
    // materializing through our native dtype/storage layer.
    build_numpy_array_from_storage(py, &[storage.len()], storage)
}

#[pyfunction]
#[pyo3(signature = (string, dtype=None, count=-1_i64, *, sep="", like=None))]
fn fromstring(
    py: Python<'_>,
    string: Py<PyAny>,
    dtype: Option<Py<PyAny>>,
    count: i64,
    sep: &str,
    like: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(dtype_val) = dtype.as_ref() {
            kwargs.set_item("dtype", dtype_val.bind(py))?;
        }
        kwargs.set_item("count", count)?;
        kwargs.set_item("sep", sep)?;
        if let Some(like_val) = like.as_ref() {
            kwargs.set_item("like", like_val.bind(py))?;
        }
        Ok(numpy
            .getattr("fromstring")?
            .call((string.bind(py),), Some(&kwargs))?
            .unbind())
    };

    // Empty `sep` is the deprecated binary path; numpy emits a
    // DeprecationWarning / ValueError we don't want to reproduce here.
    if sep.is_empty() {
        return fallback(py);
    }
    if like.as_ref().is_some_and(|value| !value.bind(py).is_none()) {
        return fallback(py);
    }

    // Accept either str or bytes input (numpy decodes bytes as ASCII).
    let string_bound = string.bind(py);
    let text: String = if let Ok(value) = string_bound.extract::<String>() {
        value
    } else if let Ok(bytes) = string_bound.extract::<Vec<u8>>() {
        match String::from_utf8(bytes) {
            Ok(value) => value,
            Err(_) => return fallback(py),
        }
    } else {
        return fallback(py);
    };

    let dtype_cloned = dtype.as_ref().map(|value| value.clone_ref(py));
    let parsed_dtype = extract_python_dtype(py, dtype_cloned, DType::F64, "fromstring(dtype)")?;
    if !dtype_supported_by_numpy_export_bridge(parsed_dtype) {
        return fallback(py);
    }

    // numpy splits by the exact sep character but trims whitespace from
    // each emitted token. For whitespace-only sep, runs of whitespace
    // collapse into a single delimiter.
    let trimmed = text.trim();
    let tokens: Vec<&str> = if sep.chars().all(char::is_whitespace) {
        trimmed.split_whitespace().collect()
    } else {
        trimmed
            .split(sep)
            .map(|part| part.trim())
            .filter(|part| !part.is_empty())
            .collect()
    };

    let limit: Option<usize> = if count == -1 {
        None
    } else if count < 0 {
        Some(0)
    } else {
        Some(count as usize)
    };
    let effective = match limit {
        Some(n) => &tokens[..tokens.len().min(n)],
        None => tokens.as_slice(),
    };

    let storage = match parsed_dtype {
        DType::Bool => {
            let mut values = Vec::with_capacity(effective.len());
            for tok in effective {
                match tok.parse::<i64>() {
                    Ok(value) => values.push(value != 0),
                    Err(_) => match tok.parse::<f64>() {
                        Ok(value) => values.push(value != 0.0),
                        Err(_) => return fallback(py),
                    },
                }
            }
            ArrayStorage::Bool(values)
        }
        DType::I8
        | DType::I16
        | DType::I32
        | DType::I64
        | DType::U8
        | DType::U16
        | DType::U32
        | DType::U64 => {
            let mut longs = Vec::with_capacity(effective.len());
            for tok in effective {
                // Accept "1.0" style integer-valued floats for int dtypes
                // (matches numpy's accept-and-truncate behavior).
                match tok.parse::<i64>() {
                    Ok(value) => longs.push(value),
                    Err(_) => match tok.parse::<f64>() {
                        Ok(value) if value.fract() == 0.0 && value.is_finite() => {
                            longs.push(value as i64);
                        }
                        _ => return fallback(py),
                    },
                }
            }
            // Cast longs into the requested integer dtype.
            match parsed_dtype {
                DType::I8 => ArrayStorage::I8(longs.into_iter().map(|v| v as i8).collect()),
                DType::I16 => ArrayStorage::I16(longs.into_iter().map(|v| v as i16).collect()),
                DType::I32 => ArrayStorage::I32(longs.into_iter().map(|v| v as i32).collect()),
                DType::I64 => ArrayStorage::I64(longs),
                DType::U8 => ArrayStorage::U8(longs.into_iter().map(|v| v as u8).collect()),
                DType::U16 => ArrayStorage::U16(longs.into_iter().map(|v| v as u16).collect()),
                DType::U32 => ArrayStorage::U32(longs.into_iter().map(|v| v as u32).collect()),
                DType::U64 => ArrayStorage::U64(longs.into_iter().map(|v| v as u64).collect()),
                _ => unreachable!(),
            }
        }
        DType::F16 | DType::F32 | DType::F64 => {
            let mut floats = Vec::with_capacity(effective.len());
            for tok in effective {
                match tok.parse::<f64>() {
                    Ok(value) => floats.push(value),
                    Err(_) => return fallback(py),
                }
            }
            match parsed_dtype {
                DType::F16 => ArrayStorage::F16(floats.into_iter().map(f16::from_f64).collect()),
                DType::F32 => ArrayStorage::F32(floats.into_iter().map(|v| v as f32).collect()),
                DType::F64 => ArrayStorage::F64(floats),
                _ => unreachable!(),
            }
        }
        _ => return fallback(py),
    };

    let shape = vec![effective.len()];
    build_numpy_array_from_storage(py, &shape, storage)
}

#[pyfunction]
#[pyo3(signature = (buffer, dtype=None, count=-1_i64, offset=0_i64, *, like=None))]
fn frombuffer(
    py: Python<'_>,
    buffer: Py<PyAny>,
    dtype: Option<Py<PyAny>>,
    count: i64,
    offset: i64,
    like: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    if let Some(like_val) = like.as_ref()
        && !like_val.bind(py).is_none()
    {
        let kwargs = PyDict::new(py);
        if let Some(dtype_val) = dtype.as_ref() {
            kwargs.set_item("dtype", dtype_val.bind(py))?;
        }
        kwargs.set_item("count", count)?;
        kwargs.set_item("offset", offset)?;
        kwargs.set_item("like", like_val.bind(py))?;
        return Ok(numpy
            .getattr("frombuffer")?
            .call((buffer.bind(py),), Some(&kwargs))?
            .unbind());
    }

    let parsed_dtype = extract_python_dtype(py, dtype, DType::F64, "frombuffer(dtype)")?;
    if dtype_item_size(parsed_dtype).is_none() {
        let kwargs = PyDict::new(py);
        kwargs.set_item("dtype", parsed_dtype.name())?;
        kwargs.set_item("count", count)?;
        kwargs.set_item("offset", offset)?;
        return Ok(numpy
            .getattr("frombuffer")?
            .call((buffer.bind(py),), Some(&kwargs))?
            .unbind());
    };

    let bytes = collect_frombuffer_bytes(py, buffer.bind(py), offset)?;
    let storage = storage_from_bytes(&bytes, parsed_dtype, count)?;

    build_numpy_array_from_storage(py, &[storage.len()], storage)
}

#[pyfunction]
#[pyo3(signature = (a, b, max_work=-1_i64))]
fn shares_memory(py: Python<'_>, a: Py<PyAny>, b: Py<PyAny>, max_work: i64) -> PyResult<Py<PyAny>> {
    // Passthrough to np.shares_memory so the exact overlap solver (when
    // max_work permits it), view/copy behavior, stride-based disjointness,
    // and max_work kwarg surface all match numpy exactly. Unlike
    // may_share_memory, shares_memory defaults to max_work=-1 (solve).
    let numpy = py.import("numpy")?;
    let kwargs = PyDict::new(py);
    kwargs.set_item("max_work", max_work)?;
    Ok(numpy
        .getattr("shares_memory")?
        .call((a.bind(py), b.bind(py)), Some(&kwargs))?
        .unbind())
}

#[pyfunction]
#[pyo3(signature = (a, a_min, a_max, out=None, **kwargs))]
fn clip(
    py: Python<'_>,
    a: Py<PyAny>,
    a_min: Py<PyAny>,
    a_max: Py<PyAny>,
    out: Option<Py<PyAny>>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    // Native clip via UFuncArray::clip for real f64/f32/int scalar min &
    // max on real numeric inputs. One-sided None bounds, broadcast min/max
    // arrays, complex inputs, explicit `out` buffers, and any extra
    // kwargs (casting, where, dtype, …) fall back to np.clip so numpy's
    // full dispatch surface is preserved exactly.
    let numpy = py.import("numpy")?;
    let clip_fn = numpy.getattr("clip")?;
    let a_for_fallback = a.clone_ref(py);
    let a_min_for_fallback = a_min.clone_ref(py);
    let a_max_for_fallback = a_max.clone_ref(py);
    let out_for_fallback = out.as_ref().map(|v| v.clone_ref(py));
    let kwargs_snapshot: Option<Py<PyDict>> = kwargs.map(|k| k.clone().unbind());
    let fallback = || -> PyResult<Py<PyAny>> {
        let call_kwargs = PyDict::new(py);
        if let Some(out) = out_for_fallback.as_ref() {
            call_kwargs.set_item("out", out.bind(py))?;
        }
        if let Some(k) = kwargs_snapshot.as_ref() {
            for (key, value) in k.bind(py).iter() {
                call_kwargs.set_item(key, value)?;
            }
        }
        Ok(clip_fn
            .call(
                (
                    a_for_fallback.bind(py),
                    a_min_for_fallback.bind(py),
                    a_max_for_fallback.bind(py),
                ),
                Some(&call_kwargs),
            )?
            .unbind())
    };

    // Bail to numpy on `out`, None bounds, or any extra kwargs — these
    // exercise the broader clip surface.
    if out.as_ref().is_some_and(|v| !v.bind(py).is_none())
        || a_min.bind(py).is_none()
        || a_max.bind(py).is_none()
        || kwargs.is_some_and(|k| !k.is_empty())
    {
        return fallback();
    }

    // Both bounds must be real scalars.
    let Ok(min_val) = a_min.bind(py).extract::<f64>() else {
        return fallback();
    };
    let Ok(max_val) = a_max.bind(py).extract::<f64>() else {
        return fallback();
    };

    let array = match extract_precise_numeric_array(py, a.bind(py), "clip(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    if matches!(array.dtype(), DType::Complex64 | DType::Complex128) {
        return fallback();
    }
    let result = array.clip(min_val, max_val);
    build_numpy_array_from_ufunc(py, &result)
}

