#[allow(dead_code)]
fn validate_trim_zeros_mode(trim: &str) -> PyResult<()> {
    if trim.is_empty() || trim.chars().any(|ch| ch != 'f' && ch != 'b') {
        return Err(PyValueError::new_err(format!(
            "unexpected character(s) in `trim`: '{trim}'"
        )));
    }

    Ok(())
}

