#[pyfunction]
#[pyo3(signature = (a, copy=true))]
fn masked_invalid(py: Python<'_>, a: Py<PyAny>, copy: bool) -> PyResult<Py<PyAny>> {
    let a_for_fallback = a.clone_ref(py);
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let masked_invalid_fn = numpy.getattr("ma")?.getattr("masked_invalid")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item("copy", copy)?;
        Ok(masked_invalid_fn
            .call((a_for_fallback.bind(py),), Some(&kwargs))?
            .unbind())
    };

    if !copy {
        return fallback();
    }

    let numpy = py.import("numpy")?;
    let builtins = py.import("builtins")?;
    let asanyarray = numpy.call_method1("asanyarray", (a.bind(py),))?;
    let masked_array_type = numpy.getattr("ma")?.getattr("MaskedArray")?;
    let input_is_masked = builtins
        .call_method1("isinstance", (&asanyarray, masked_array_type))?
        .extract::<bool>()?;

    let Some(masked) = extract_numeric_masked_array(py, a.bind(py), "masked_invalid(a)")? else {
        return fallback();
    };
    if matches!(
        masked.data().dtype(),
        DType::Complex64
            | DType::Complex128
            | DType::DateTime64
            | DType::TimeDelta64
            | DType::Str
            | DType::Structured
    ) {
        return fallback();
    }

    let invalid = masked
        .data()
        .elementwise_unary(UnaryOp::Isfinite)
        .elementwise_unary(UnaryOp::LogicalNot);
    let result = MaskedArray::new(
        masked.data().clone(),
        ma_mask_or(masked.mask(), Some(&invalid)),
        None,
    )
    .map_err(|err| map_ma_error("masked_invalid", err))?;
    let py_result = build_numpy_masked_array(py, &result)?;
    if input_is_masked {
        py_result
            .bind(py)
            .call_method1("set_fill_value", (asanyarray.getattr("fill_value")?,))?;
    }
    Ok(py_result)
}

#[pyfunction]
#[pyo3(signature = (a, mask=None, copy=true, fill_value=None))]
fn fix_invalid(
    py: Python<'_>,
    a: Py<PyAny>,
    mask: Option<Py<PyAny>>,
    copy: bool,
    fill_value: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let a_for_fallback = a.clone_ref(py);
    let mask_for_fallback = mask.as_ref().map(|value| value.clone_ref(py));
    let fill_value_for_fallback = fill_value.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let fix_invalid_fn = numpy.getattr("ma")?.getattr("fix_invalid")?;
        let kwargs = PyDict::new(py);
        if let Some(mask_val) = &mask_for_fallback {
            kwargs.set_item("mask", mask_val.bind(py))?;
        }
        kwargs.set_item("copy", copy)?;
        if let Some(fill_value_val) = &fill_value_for_fallback {
            kwargs.set_item("fill_value", fill_value_val.bind(py))?;
        }
        Ok(fix_invalid_fn
            .call((a_for_fallback.bind(py),), Some(&kwargs))?
            .unbind())
    };

    if !copy {
        return fallback();
    }

    let numpy = py.import("numpy")?;
    let builtins = py.import("builtins")?;
    let asanyarray = numpy.call_method1("asanyarray", (a.bind(py),))?;
    let masked_array_type = numpy.getattr("ma")?.getattr("MaskedArray")?;
    let input_is_masked = builtins
        .call_method1("isinstance", (&asanyarray, masked_array_type))?
        .extract::<bool>()?;

    let Some(masked) = extract_numeric_masked_array(py, a.bind(py), "fix_invalid(a)")? else {
        return fallback();
    };
    let extra_mask = match mask.as_ref() {
        Some(mask_val) => match extract_mask_operand(py, mask_val.bind(py), "fix_invalid(mask)") {
            Ok(mask) => mask,
            Err(_) => return fallback(),
        },
        None => None,
    };
    let resolved_fill_value = match fill_value.as_ref() {
        Some(value) => {
            match extract_precise_numeric_array(py, value.bind(py), "fix_invalid(fill_value)") {
                Ok(fill_value) if fill_value.shape().is_empty() => fill_value.values()[0],
                _ => return fallback(),
            }
        }
        None => masked.fill_value(),
    };

    let merged_mask = ma_mask_or(masked.mask(), extra_mask.as_ref());
    let mut fixed = MaskedArray::new(
        masked.data().clone(),
        merged_mask,
        Some(resolved_fill_value),
    )
    .map_err(|err| map_ma_error("fix_invalid", err))?;
    fixed.fix_invalid();

    let result = build_numpy_masked_array(py, &fixed)?;
    // numpy.ma.fix_invalid(a, fill_value=F) uses F as a REPLACEMENT value
    // for invalid entries in .data — it does NOT set the output's
    // .fill_value attribute from that argument. The output's fill_value
    // is inherited from the input (if a was already a MaskedArray) or
    // left at the dtype default. Only propagate when the input was
    // already masked so its fill_value survives the rust-port path.
    if input_is_masked {
        result.bind(py).setattr("fill_value", resolved_fill_value)?;
    }
    Ok(result)
}

fn minimum_fill_value_for_supported_dtype(py: Python<'_>, dtype: DType) -> PyResult<Py<PyAny>> {
    Ok(match dtype {
        DType::Bool => 1_i64.into_pyobject(py)?.into_any().unbind(),
        DType::I8 => i8::MAX.into_pyobject(py)?.into_any().unbind(),
        DType::I16 => i16::MAX.into_pyobject(py)?.into_any().unbind(),
        DType::I32 => i32::MAX.into_pyobject(py)?.into_any().unbind(),
        DType::I64 => i64::MAX.into_pyobject(py)?.into_any().unbind(),
        DType::U8 => u8::MAX.into_pyobject(py)?.into_any().unbind(),
        DType::U16 => u16::MAX.into_pyobject(py)?.into_any().unbind(),
        DType::U32 => u32::MAX.into_pyobject(py)?.into_any().unbind(),
        DType::U64 => u64::MAX.into_pyobject(py)?.into_any().unbind(),
        DType::F16 | DType::F32 | DType::F64 => {
            f64::INFINITY.into_pyobject(py)?.into_any().unbind()
        }
        DType::Complex64 | DType::Complex128 => py
            .import("builtins")?
            .getattr("complex")?
            .call1((f64::INFINITY, f64::INFINITY))?
            .unbind(),
        DType::DateTime64 | DType::TimeDelta64 => i64::MAX.into_pyobject(py)?.into_any().unbind(),
        DType::Str | DType::Structured => py.None(),
    })
}

#[pyfunction]
#[pyo3(signature = (obj,))]
fn minimum_fill_value(py: Python<'_>, obj: Py<PyAny>) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let builtins = py.import("builtins")?;
    let bound = obj.bind(py);
    let dtype = if builtins
        .call_method1("isinstance", (bound, numpy.getattr("dtype")?))?
        .extract::<bool>()?
    {
        bound.clone()
    } else {
        numpy.call_method1("asarray", (bound,))?.getattr("dtype")?
    };

    if !dtype.getattr("names")?.is_none() {
        return Ok(numpy
            .getattr("ma")?
            .getattr("minimum_fill_value")?
            .call1((bound,))?
            .unbind());
    }

    let kind = dtype.getattr("kind")?.extract::<String>()?;
    if matches!(kind.as_str(), "O" | "S" | "U" | "V") {
        return Ok(py.None());
    }

    let parsed_dtype = match kind.as_str() {
        "M" => DType::DateTime64,
        "m" => DType::TimeDelta64,
        _ => {
            let name = dtype.getattr("name")?.extract::<String>()?;
            DType::parse(&name).ok_or_else(|| {
                PyTypeError::new_err(format!("minimum_fill_value: unsupported dtype {name}"))
            })?
        }
    };

    minimum_fill_value_for_supported_dtype(py, parsed_dtype)
}

fn maximum_fill_value_for_supported_dtype(py: Python<'_>, dtype: DType) -> PyResult<Py<PyAny>> {
    // Mirror ma_maximum_fill_value_for_dtype exactly: opposite polarity of
    // minimum_fill_value. Bool → False, signed ints → MIN, unsigned ints →
    // 0, floats → -inf, complex → (-inf, -inf), datetime/timedelta →
    // -i64::MAX (one past NaT so reductions avoid the sentinel).
    Ok(match dtype {
        DType::Bool => 0_i64.into_pyobject(py)?.into_any().unbind(),
        DType::I8 => i8::MIN.into_pyobject(py)?.into_any().unbind(),
        DType::I16 => i16::MIN.into_pyobject(py)?.into_any().unbind(),
        DType::I32 => i32::MIN.into_pyobject(py)?.into_any().unbind(),
        DType::I64 => i64::MIN.into_pyobject(py)?.into_any().unbind(),
        DType::U8 => 0_u8.into_pyobject(py)?.into_any().unbind(),
        DType::U16 => 0_u16.into_pyobject(py)?.into_any().unbind(),
        DType::U32 => 0_u32.into_pyobject(py)?.into_any().unbind(),
        DType::U64 => 0_u64.into_pyobject(py)?.into_any().unbind(),
        DType::F16 | DType::F32 | DType::F64 => {
            f64::NEG_INFINITY.into_pyobject(py)?.into_any().unbind()
        }
        DType::Complex64 | DType::Complex128 => py
            .import("builtins")?
            .getattr("complex")?
            .call1((f64::NEG_INFINITY, f64::NEG_INFINITY))?
            .unbind(),
        DType::DateTime64 | DType::TimeDelta64 => {
            (-i64::MAX).into_pyobject(py)?.into_any().unbind()
        }
        DType::Str | DType::Structured => py.None(),
    })
}

#[pyfunction]
#[pyo3(signature = (obj,))]
fn maximum_fill_value(py: Python<'_>, obj: Py<PyAny>) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let builtins = py.import("builtins")?;
    let bound = obj.bind(py);
    let dtype = if builtins
        .call_method1("isinstance", (bound, numpy.getattr("dtype")?))?
        .extract::<bool>()?
    {
        bound.clone()
    } else {
        numpy.call_method1("asarray", (bound,))?.getattr("dtype")?
    };

    // Structured dtypes fall back to numpy (compound field unpacking).
    if !dtype.getattr("names")?.is_none() {
        return Ok(numpy
            .getattr("ma")?
            .getattr("maximum_fill_value")?
            .call1((bound,))?
            .unbind());
    }

    let kind = dtype.getattr("kind")?.extract::<String>()?;
    if matches!(kind.as_str(), "O" | "S" | "U" | "V") {
        return Ok(py.None());
    }

    let parsed_dtype = match kind.as_str() {
        "M" => DType::DateTime64,
        "m" => DType::TimeDelta64,
        _ => {
            let name = dtype.getattr("name")?.extract::<String>()?;
            DType::parse(&name).ok_or_else(|| {
                PyTypeError::new_err(format!("maximum_fill_value: unsupported dtype {name}"))
            })?
        }
    };

    maximum_fill_value_for_supported_dtype(py, parsed_dtype)
}

#[pyfunction]
#[pyo3(signature = (a, rcond=None, hermitian=false, **kwargs))]
fn pinv(
    py: Python<'_>,
    a: Py<PyAny>,
    rcond: Option<Py<PyAny>>,
    hermitian: bool,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    let rcond = OptionalFloatKwarg::parse(py, rcond, "rcond")?;
    let rtol = parse_pinv_rtol_kwarg(py, kwargs)?;
    let array = extract_numeric_array(py, a.bind(py), "pinv(a)")?;
    let shape = array.shape();

    if shape.len() == 2
        && !matches!(array.dtype(), DType::Complex64 | DType::Complex128)
        && (!hermitian || shape[0] == shape[1])
    {
        let values = if hermitian {
            pinv_hermitian_nxn_with_tolerance_aliases(
                array.values(),
                shape[0],
                rcond.as_rcond(),
                rtol.as_rtol(),
            )
        } else {
            pinv_mxn_with_tolerance_aliases(
                array.values(),
                shape[0],
                shape[1],
                rcond.as_rcond(),
                rtol.as_rtol(),
            )
        }
        .map_err(map_ufunc_error)?;
        let result = UFuncArray::new(vec![shape[1], shape[0]], values, DType::F64)
            .map_err(map_ufunc_error)?;
        return build_numpy_array_from_ufunc(py, &result);
    }

    let numpy = py.import("numpy")?;
    let pinv_fn = numpy.getattr("linalg")?.getattr("pinv")?;
    let kwargs = PyDict::new(py);
    rcond.set_on_kwargs(&kwargs, "rcond")?;
    kwargs.set_item("hermitian", hermitian)?;
    rtol.set_on_kwargs(&kwargs, "rtol")?;
    Ok(pinv_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
}

