#[pyfunction]
#[pyo3(signature = (*args, **kwargs))]
fn cholesky(
    py: Python<'_>,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    match args.len() {
        0 => {
            return Err(PyTypeError::new_err(
                "cholesky() missing 1 required positional argument: 'a'",
            ));
        }
        1 => {}
        count => {
            return Err(PyTypeError::new_err(format!(
                "cholesky() takes 1 positional argument but {count} were given"
            )));
        }
    }

    let numpy = py.import("numpy")?;
    let cholesky_fn = numpy.getattr("linalg")?.getattr("cholesky")?;
    let a = args.get_item(0)?.unbind();
    let call_kwargs = PyDict::new(py);
    let mut saw_upper = false;
    if let Some(kwargs) = kwargs {
        for (key, value) in kwargs.iter() {
            let name = key.extract::<String>()?;
            match name.as_str() {
                "upper" => {
                    call_kwargs.set_item("upper", value)?;
                    saw_upper = true;
                }
                _ => {
                    return Err(PyTypeError::new_err(format!(
                        "cholesky() got an unexpected keyword argument '{name}'"
                    )));
                }
            }
        }
    }
    if !saw_upper {
        call_kwargs.set_item("upper", false)?;
    }

    let upper = call_kwargs
        .get_item("upper")?
        .expect("upper kwarg is always present")
        .extract::<bool>()?;
    let a_for_fallback = a.clone_ref(py);
    let fallback = || -> PyResult<Py<PyAny>> {
        Ok(cholesky_fn
            .call((a_for_fallback.bind(py),), Some(&call_kwargs))?
            .unbind())
    };

    let array = match extract_precise_numeric_array(py, a.bind(py), "cholesky(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let shape = array.shape();
    if shape.len() != 2
        || shape[0] != shape[1]
        || array.has_integer_sidecar()
        || array.values().iter().any(|value| !value.is_finite())
        || !matches!(array.dtype(), DType::F64)
    {
        return fallback();
    }

    let result = match array.cholesky_with_upper(upper) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    build_numpy_array_from_ufunc(py, &result)
}

#[pyfunction]
#[pyo3(signature = (a, b))]
fn solve(py: Python<'_>, a: Py<PyAny>, b: Py<PyAny>) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let solve_fn = numpy.getattr("linalg")?.getattr("solve")?;
    let a_for_fallback = a.clone_ref(py);
    let b_for_fallback = b.clone_ref(py);
    let fallback = || -> PyResult<Py<PyAny>> {
        Ok(solve_fn
            .call1((a_for_fallback.bind(py), b_for_fallback.bind(py)))?
            .unbind())
    };

    let a = match extract_precise_numeric_array(py, a.bind(py), "solve(a, b)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let b = match extract_precise_numeric_array(py, b.bind(py), "solve(a, b)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };

    let a_shape = a.shape();
    let b_shape = b.shape();
    if a_shape.len() != 2
        || a_shape[0] != a_shape[1]
        || !matches!(a.dtype(), DType::F64)
        || !matches!(b.dtype(), DType::F64)
        || a.has_integer_sidecar()
        || b.has_integer_sidecar()
        || a.values().iter().any(|value| !value.is_finite())
        || b.values().iter().any(|value| !value.is_finite())
    {
        return fallback();
    }

    let result = match b_shape.len() {
        1 => match a.solve(&b) {
            Ok(result) => result,
            Err(_) => return fallback(),
        },
        2 => match a.solve_multi(&b) {
            Ok(result) => result,
            Err(_) => return fallback(),
        },
        _ => return fallback(),
    };
    build_numpy_array_from_ufunc(py, &result)
}

