#[pyfunction]
#[pyo3(signature = (a, bins=None, range=None, density=None, weights=None))]
fn histogram(
    py: Python<'_>,
    a: Py<PyAny>,
    bins: Option<Py<PyAny>>,
    range: Option<Py<PyAny>>,
    density: Option<Py<PyAny>>,
    weights: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        let histogram_fn = numpy.getattr("histogram")?;
        let kwargs = PyDict::new(py);
        if let Some(bins_val) = bins.as_ref() {
            kwargs.set_item("bins", bins_val.bind(py))?;
        }
        if let Some(range_val) = range.as_ref() {
            kwargs.set_item("range", range_val.bind(py))?;
        }
        if let Some(density_val) = density.as_ref() {
            kwargs.set_item("density", density_val.bind(py))?;
        }
        if let Some(weights_val) = weights.as_ref() {
            kwargs.set_item("weights", weights_val.bind(py))?;
        }
        Ok(histogram_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
    };

    // Native path only handles int bins without range/weights/density —
    // everything else lands on numpy.
    if range.as_ref().is_some_and(|v| !v.bind(py).is_none())
        || density.as_ref().is_some_and(|v| !v.bind(py).is_none())
        || weights.as_ref().is_some_and(|v| !v.bind(py).is_none())
    {
        return fallback(py);
    }
    let nbins: usize = match bins.as_ref() {
        Some(v) => {
            let b = v.bind(py);
            if b.is_none() {
                10
            } else if let Ok(n) = b.extract::<i64>() {
                if n <= 0 {
                    return fallback(py);
                }
                n as usize
            } else {
                // Explicit edges array or estimator string: delegate.
                return fallback(py);
            }
        }
        None => 10,
    };

    let native = match extract_precise_numeric_array(py, a.bind(py), "histogram(a)") {
        Ok(value) => value,
        Err(_) => return fallback(py),
    };
    if native.has_integer_sidecar()
        || matches!(native.dtype(), DType::Complex64 | DType::Complex128)
        || native.shape().len() != 1
    {
        return fallback(py);
    }
    // Reject non-finite inputs so we match numpy's ValueError surface
    // for autorange without inadvertently producing nonsense buckets.
    if native.values().iter().any(|v| !v.is_finite()) {
        return fallback(py);
    }

    let (counts, edges) = match native.histogram(nbins) {
        Ok(value) => value,
        Err(_) => return fallback(py),
    };
    // UFuncArray::histogram returns counts with DType::I64 but stored as
    // f64 values — build_numpy_array_from_ufunc emits an int64 ndarray.
    // Bridge each component through the C-order export helpers.
    let counts_py = build_numpy_array_from_ufunc(py, &counts)?;
    let edges_py = build_numpy_array_from_ufunc(py, &edges)?;
    Ok(PyTuple::new(py, [counts_py.bind(py), edges_py.bind(py)])?
        .into_any()
        .unbind())
}

#[pyfunction]
#[pyo3(signature = (f, *varargs, axis=None, edge_order=1))]
fn gradient(
    py: Python<'_>,
    f: Py<PyAny>,
    varargs: &Bound<'_, PyTuple>,
    axis: Option<Py<PyAny>>,
    edge_order: usize,
) -> PyResult<Py<PyAny>> {
    // Passthrough to np.gradient so spacing-argument handling, axis
    // selection, return-shape conventions, and boundary schemes match
    // NumPy exactly.
    let numpy = py.import("numpy")?;
    let gradient_fn = numpy.getattr("gradient")?;
    let mut positional: Vec<Py<PyAny>> = Vec::with_capacity(varargs.len() + 1);
    positional.push(f);
    for arg in varargs.iter() {
        positional.push(arg.unbind());
    }
    let args = PyTuple::new(py, positional.iter().map(|item| item.bind(py)))?;
    let kwargs = PyDict::new(py);
    if let Some(axis_val) = axis {
        kwargs.set_item("axis", axis_val.bind(py))?;
    }
    if edge_order != 1 {
        kwargs.set_item("edge_order", edge_order)?;
    }
    Ok(gradient_fn.call(args, Some(&kwargs))?.unbind())
}

#[pyfunction]
#[pyo3(signature = (a, n=1, axis=-1, *varargs, **kwargs))]
fn diff(
    py: Python<'_>,
    a: Py<PyAny>,
    n: i64,
    axis: i64,
    varargs: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let diff_fn = numpy.getattr("diff")?;
    let fallback = || -> PyResult<Py<PyAny>> {
        let mut positional: Vec<Py<PyAny>> = Vec::with_capacity(varargs.len() + 3);
        positional.push(a.clone_ref(py));
        positional.push(n.into_pyobject(py)?.into_any().unbind());
        positional.push(axis.into_pyobject(py)?.into_any().unbind());
        for arg in varargs.iter() {
            positional.push(arg.unbind());
        }
        let args = PyTuple::new(py, positional.iter().map(|item| item.bind(py)))?;
        let call_kwargs = PyDict::new(py);
        if let Some(kwargs) = kwargs {
            for (key, value) in kwargs.iter() {
                call_kwargs.set_item(key, value)?;
            }
        }
        Ok(diff_fn.call(args, Some(&call_kwargs))?.unbind())
    };

    if varargs.len() > 0 || kwargs.is_some_and(|kwargs| !kwargs.is_empty()) {
        return fallback();
    }

    let Ok(n) = usize::try_from(n) else {
        return fallback();
    };
    let a = match extract_numeric_array(py, a.bind(py), "diff(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let result = match a.diff(n, Some(axis as isize)) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    build_numpy_array_from_ufunc(py, &result)
}

#[pyfunction]
#[pyo3(signature = (a, shift, axis=None))]
fn roll(
    py: Python<'_>,
    a: Py<PyAny>,
    shift: Py<PyAny>,
    axis: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    // Native roll via UFuncArray::roll / roll_multi for real/complex
    // numeric inputs. Scalar shift with scalar-or-None axis routes
    // through roll; tuple-of-shifts with tuple-of-axes routes through
    // roll_multi; mismatched tuples, non-int shifts, non-numeric dtypes
    // fall back to np.roll so numpy's dispatch surface stays exact.
    let numpy = py.import("numpy")?;
    let roll_fn = numpy.getattr("roll")?;
    let a_for_fallback = a.clone_ref(py);
    let shift_for_fallback = shift.clone_ref(py);
    let axis_for_fallback = axis.as_ref().map(|v| v.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(axis_val) = axis_for_fallback.as_ref() {
            kwargs.set_item("axis", axis_val.bind(py))?;
        }
        Ok(roll_fn
            .call(
                (a_for_fallback.bind(py), shift_for_fallback.bind(py)),
                Some(&kwargs),
            )?
            .unbind())
    };

    let array = match extract_precise_numeric_array(py, a.bind(py), "roll(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };

    // Scalar shift path.
    if let Ok(shift_scalar) = shift.bind(py).extract::<i64>() {
        let axis_scalar: Option<isize> = match axis.as_ref() {
            None => None,
            Some(value) => {
                let bound = value.bind(py);
                if bound.is_none() {
                    None
                } else if let Ok(axis_int) = bound.extract::<i64>() {
                    Some(axis_int as isize)
                } else {
                    return fallback();
                }
            }
        };
        let result = match array.roll(shift_scalar as isize, axis_scalar) {
            Ok(result) => result,
            Err(_) => return fallback(),
        };
        return build_numpy_array_from_ufunc(py, &result);
    }

    // Tuple/list shift path — requires explicit axis tuple of matching length.
    let Ok(shifts) = shift.bind(py).extract::<Vec<i64>>() else {
        return fallback();
    };
    let Some(axis_obj) = axis.as_ref() else {
        return fallback();
    };
    let Ok(axes) = axis_obj.bind(py).extract::<Vec<i64>>() else {
        return fallback();
    };
    if axes.len() != shifts.len() {
        return fallback();
    }
    let shifts_isize: Vec<isize> = shifts.iter().map(|&s| s as isize).collect();
    let axes_isize: Vec<isize> = axes.iter().map(|&a| a as isize).collect();
    let result = match array.roll_multi(&shifts_isize, &axes_isize) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    build_numpy_array_from_ufunc(py, &result)
}

#[pyfunction]
#[pyo3(signature = (a, bins=None, range=None, weights=None))]
fn histogram_bin_edges(
    py: Python<'_>,
    a: Py<PyAny>,
    bins: Option<Py<PyAny>>,
    range: Option<Py<PyAny>>,
    weights: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        let histogram_bin_edges_fn = numpy.getattr("histogram_bin_edges")?;
        let kwargs = PyDict::new(py);
        if let Some(bins_val) = bins.as_ref() {
            kwargs.set_item("bins", bins_val.bind(py))?;
        }
        if let Some(range_val) = range.as_ref() {
            kwargs.set_item("range", range_val.bind(py))?;
        }
        if let Some(weights_val) = weights.as_ref() {
            kwargs.set_item("weights", weights_val.bind(py))?;
        }
        Ok(histogram_bin_edges_fn
            .call((a.bind(py),), Some(&kwargs))?
            .unbind())
    };

    // Weights only affect estimator-driven bin-width choice; with explicit
    // int bins + range they're ignored. Since our native path supports
    // exactly that combo, pass through weights without using them.
    // Delegate when a string estimator or non-int bins sequence lands that
    // we don't reproduce.
    let bins_bound = bins.as_ref().map(|v| v.bind(py));
    let range_bound = range.as_ref().map(|v| v.bind(py));
    let weights_bound = weights.as_ref().map(|v| v.bind(py));

    // Case 1: explicit array-like bins → return the edges coerced through
    // numpy.asarray. This preserves identity when bins is already an
    // ndarray (matches numpy's behavior).
    if let Some(bins_val) = bins_bound
        && !bins_val.is_instance_of::<pyo3::types::PyInt>()
        && !bins_val.is_instance_of::<pyo3::types::PyString>()
        && !bins_val.is_none()
    {
        // Must be array-like. numpy.asarray to enforce dtype coercion.
        // Weights are ignored with explicit edges (documented).
        return Ok(numpy.call_method1("asarray", (bins_val,))?.unbind());
    }

    // Case 2: int bins (default 10 when bins is None or missing) with
    // no estimator. Range may or may not be present.
    if bins_bound
        .map(|v| v.is_none() || v.is_instance_of::<pyo3::types::PyInt>())
        .unwrap_or(true)
    {
        if weights_bound.is_some_and(|w| !w.is_none()) {
            // weights are ignored with int bins per numpy docs, but our
            // extraction below doesn't use them — confirm they at least
            // parse as numeric so we don't silently accept garbage.
            if extract_precise_numeric_array(
                py,
                weights_bound.unwrap(),
                "histogram_bin_edges(weights)",
            )
            .is_err()
            {
                return fallback(py);
            }
        }
        let nbins: i64 = match bins_bound {
            Some(v) if !v.is_none() => match v.extract::<i64>() {
                Ok(n) if n > 0 => n,
                _ => return fallback(py),
            },
            _ => 10,
        };

        let a_bound = a.bind(py);
        let (amin, amax) = if let Some(range_val) = range_bound
            && !range_val.is_none()
        {
            // range is a 2-tuple.
            match range_val.extract::<(f64, f64)>() {
                Ok((lo, hi)) if hi >= lo && lo.is_finite() && hi.is_finite() => (lo, hi),
                _ => return fallback(py),
            }
        } else {
            // Derive from input data via numpy.min / numpy.max to match
            // exactly (including 0-element handling: numpy returns
            // [0, 0.25, 0.5, 0.75, 1.0] for bins=4, which is linspace(0,1,5)).
            let native = match extract_precise_numeric_array(py, a_bound, "histogram_bin_edges(a)")
            {
                Ok(value) => value,
                Err(_) => return fallback(py),
            };
            if native.has_integer_sidecar()
                || matches!(native.dtype(), DType::Complex64 | DType::Complex128)
            {
                return fallback(py);
            }
            let values = native.values();
            if values.is_empty() {
                (0.0_f64, 1.0_f64)
            } else {
                let mut lo = f64::INFINITY;
                let mut hi = f64::NEG_INFINITY;
                for &v in values.iter() {
                    if !v.is_finite() {
                        // numpy raises on non-finite values when using
                        // an estimator string; with int bins it's fine,
                        // but we also see NaN propagation issues — keep
                        // the fallback for non-finite input to stay safe.
                        return fallback(py);
                    }
                    if v < lo {
                        lo = v;
                    }
                    if v > hi {
                        hi = v;
                    }
                }
                if lo == hi {
                    (lo - 0.5, hi + 0.5)
                } else {
                    (lo, hi)
                }
            }
        };

        let edges =
            match UFuncArray::linspace_endpoint(amin, amax, (nbins + 1) as usize, true, DType::F64)
            {
                Ok(value) => value,
                Err(_) => return fallback(py),
            };
        return build_numpy_array_from_ufunc(py, &edges);
    }

    // String estimators ('fd', 'auto', 'sturges', ...) need numpy.
    fallback(py)
}

#[pyfunction]
#[pyo3(signature = (a, order="C"))]
fn ravel(py: Python<'_>, a: Py<PyAny>, order: &str) -> PyResult<Py<PyAny>> {
    // Native ravel via UFuncArray::ravel for real/complex numeric arrays
    // with default C-order flattening. F-order, 'A', 'K' and non-numeric
    // (object, string, structured) inputs fall back to np.ravel so
    // numpy's order-sensitive behavior and dispatch surface are preserved
    // exactly.
    let numpy = py.import("numpy")?;
    let a_for_fallback = a.clone_ref(py);
    let fallback = || -> PyResult<Py<PyAny>> {
        Ok(numpy
            .getattr("ravel")?
            .call1((a_for_fallback.bind(py), order))?
            .unbind())
    };
    if order != "C" {
        return fallback();
    }
    let array = match extract_precise_numeric_array(py, a.bind(py), "ravel(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let result = array.ravel();
    build_numpy_array_from_ufunc(py, &result)
}

