#[pyfunction]
#[pyo3(signature = (a, axis=None))]
fn squeeze(py: Python<'_>, a: Py<PyAny>, axis: Option<Py<PyAny>>) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let squeeze_fn = numpy.getattr("squeeze")?;
    let axis_for_parse = axis.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(axis_val) = axis.as_ref() {
            kwargs.set_item("axis", axis_val.bind(py))?;
        }
        Ok(squeeze_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
    };

    let a = match extract_numeric_array(py, a.bind(py), "squeeze(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let axes = match extract_axis_spec(py, axis_for_parse, "squeeze") {
        Ok(axes) => axes,
        Err(_) => return fallback(),
    };
    let result = match axes {
        None => a.squeeze(None),
        Some(axes) if axes.is_empty() => Ok(a.clone()),
        Some(axes) if axes.len() == 1 => a.squeeze(Some(axes[0])),
        Some(axes) => a.squeeze_axes(&axes),
    };
    let result = match result {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    build_numpy_array_from_ufunc(py, &result)
}

#[pyfunction]
#[pyo3(signature = (m, k=1, axes=(0, 1)))]
fn rot90(py: Python<'_>, m: Py<PyAny>, k: i64, axes: (i64, i64)) -> PyResult<Py<PyAny>> {
    // Native rot90 via UFuncArray::rot90_axes for real/complex numeric
    // inputs. Axis validation errors, repeated-axes rejection, and
    // non-numeric / 1-D inputs fall back to np.rot90 so numpy's error
    // surface and dispatch stay exact.
    let numpy = py.import("numpy")?;
    let m_for_fallback = m.clone_ref(py);
    let fallback = || -> PyResult<Py<PyAny>> {
        Ok(numpy
            .getattr("rot90")?
            .call1((m_for_fallback.bind(py), k, axes))?
            .unbind())
    };
    let Ok(k_i32) = i32::try_from(k) else {
        return fallback();
    };
    let array = match extract_precise_numeric_array(py, m.bind(py), "rot90(m)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let result = match array.rot90_axes(k_i32, (axes.0 as isize, axes.1 as isize)) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    build_numpy_array_from_ufunc(py, &result)
}

