#[pyfunction]
#[pyo3(signature = (a, n=None, axis=-1, norm=None, out=None))]
fn fft(
    py: Python<'_>,
    a: Py<PyAny>,
    n: Option<usize>,
    axis: i64,
    norm: Option<String>,
    out: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    // Passthrough to np.fft.fft so the optional truncation/zero-padding
    // length n, axis selector, norm conventions ('backward'/'ortho'/
    // 'forward'), optional `out=` destination, and complex output dtype
    // all match numpy exactly.
    let numpy = py.import("numpy")?;
    let fft_fn = numpy.getattr("fft")?.getattr("fft")?;
    let kwargs = PyDict::new(py);
    if let Some(n_val) = n {
        kwargs.set_item("n", n_val)?;
    }
    kwargs.set_item("axis", axis)?;
    if let Some(norm_val) = norm {
        kwargs.set_item("norm", norm_val)?;
    }
    if let Some(out_val) = out {
        kwargs.set_item("out", out_val.bind(py))?;
    }
    Ok(fft_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
}

#[pyfunction]
#[pyo3(signature = (a, fill_value=None))]
fn filled(py: Python<'_>, a: Py<PyAny>, fill_value: Option<Py<PyAny>>) -> PyResult<Py<PyAny>> {
    let fill_value_for_fallback = fill_value.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let filled_fn = numpy.getattr("ma")?.getattr("filled")?;
        let kwargs = PyDict::new(py);
        if let Some(value) = &fill_value_for_fallback {
            kwargs.set_item("fill_value", value.bind(py))?;
        }
        Ok(filled_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
    };

    let Some(masked) = extract_numeric_masked_array(py, a.bind(py), "filled")? else {
        return fallback();
    };
    let fill_value = match fill_value.as_ref() {
        Some(value) => {
            match extract_filled_scalar_storage(py, value.bind(py), "filled(fill_value)")? {
                Some(fill_value) => fill_value,
                None => return fallback(),
            }
        }
        None => FilledScalarStorage::Storage(ArrayStorage::F64(vec![masked.fill_value()])),
    };

    if dtype_is_unsigned_integer(masked.dtype()) {
        match &fill_value {
            FilledScalarStorage::PythonFloat(value) if *value < 0.0 => return fallback(),
            FilledScalarStorage::PythonInt(ArrayStorage::I64(values)) if values[0] < 0 => {
                return fallback();
            }
            _ => {}
        }
    }

    let result = masked
        .filled_with_storage(fill_value.into_storage())
        .map_err(|err| map_ufunc_error(format!("filled: {err}")))?;
    build_numpy_scalar_or_array(py, &result)
}

#[pyfunction]
#[pyo3(signature = (a,))]
fn getmask(py: Python<'_>, a: Py<PyAny>) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let builtins = py.import("builtins")?;
    let asanyarray = numpy.call_method1("asanyarray", (a.bind(py),))?;
    let masked_array_type = numpy.getattr("ma")?.getattr("MaskedArray")?;
    let is_masked_array = builtins
        .call_method1("isinstance", (&asanyarray, masked_array_type))?
        .extract::<bool>()?;
    if is_masked_array {
        return Ok(asanyarray.getattr("mask")?.unbind());
    }
    Ok(numpy.getattr("ma")?.getattr("nomask")?.unbind())
}

#[pyfunction]
#[pyo3(signature = (x,))]
fn is_masked(py: Python<'_>, x: Py<PyAny>) -> PyResult<Py<PyAny>> {
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        Ok(numpy
            .getattr("ma")?
            .getattr("is_masked")?
            .call1((x.bind(py),))?
            .unbind())
    };

    let (is_masked_array, mask, shape) = match extract_mask_metadata(py, x.bind(py), "is_masked") {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    let masked = if is_masked_array {
        let data = build_boolean_array(&shape, false, "is_masked")?;
        let array =
            MaskedArray::new(data, mask, None).map_err(|err| map_ma_error("is_masked", err))?;
        ma_is_masked(&array)
    } else {
        false
    };
    Ok(py
        .import("builtins")?
        .getattr("bool")?
        .call1((masked,))?
        .unbind())
}

#[pyfunction]
#[pyo3(signature = (m1, m2, copy=false, shrink=true))]
fn mask_or(
    py: Python<'_>,
    m1: Py<PyAny>,
    m2: Py<PyAny>,
    copy: bool,
    shrink: bool,
) -> PyResult<Py<PyAny>> {
    let m1_for_fallback = m1.clone_ref(py);
    let m2_for_fallback = m2.clone_ref(py);
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let mask_or_fn = numpy.getattr("ma")?.getattr("mask_or")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item("copy", copy)?;
        kwargs.set_item("shrink", shrink)?;
        Ok(mask_or_fn
            .call(
                (m1_for_fallback.bind(py), m2_for_fallback.bind(py)),
                Some(&kwargs),
            )?
            .unbind())
    };

    let left = match extract_mask_operand(py, m1.bind(py), "mask_or(m1)") {
        Ok(mask) => mask,
        Err(_) => return fallback(),
    };
    let right = match extract_mask_operand(py, m2.bind(py), "mask_or(m2)") {
        Ok(mask) => mask,
        Err(_) => return fallback(),
    };
    if let (Some(left), Some(right)) = (&left, &right)
        && left.shape() != right.shape()
    {
        return fallback();
    }

    let Some(result) = ma_mask_or(left.as_ref(), right.as_ref()) else {
        return Ok(py
            .import("numpy")?
            .getattr("ma")?
            .getattr("nomask")?
            .unbind());
    };
    if shrink && result.values().iter().all(|&value| value == 0.0) {
        return Ok(py
            .import("numpy")?
            .getattr("ma")?
            .getattr("nomask")?
            .unbind());
    }

    let output = build_numpy_array_from_ufunc(py, &result)?;
    if !copy && left.is_none() && right.is_none() {
        return Ok(py
            .import("numpy")?
            .getattr("ma")?
            .getattr("nomask")?
            .unbind());
    }
    Ok(output)
}

#[pyfunction]
#[pyo3(signature = (a, axis=None, keepdims=None))]
fn ma_count(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    keepdims: Option<bool>,
) -> PyResult<Py<PyAny>> {
    let axis_for_parse = axis.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let count_fn = numpy.getattr("ma")?.getattr("count")?;
        let kwargs = PyDict::new(py);
        if let Some(axis_val) = axis.as_ref() {
            kwargs.set_item("axis", axis_val.bind(py))?;
        }
        if let Some(keepdims_val) = keepdims {
            kwargs.set_item("keepdims", keepdims_val)?;
        }
        Ok(count_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
    };

    let keepdims = keepdims.unwrap_or(false);
    let axis_spec = match extract_axis_spec(py, axis_for_parse, "ma_count") {
        Ok(spec) => spec,
        Err(_) => return fallback(),
    };
    let (_, mask, shape) = match extract_mask_metadata(py, a.bind(py), "ma_count") {
        Ok(metadata) => metadata,
        Err(_) => return fallback(),
    };
    let axes = match axis_spec.as_ref() {
        Some(axes) => {
            if ensure_unique_axes(axes, shape.len()).is_err() {
                return fallback();
            }
            let mut normalized = Vec::with_capacity(axes.len());
            for &axis in axes {
                match try_normalize_axis(axis, shape.len()) {
                    Some(axis) => normalized.push(axis),
                    None => return fallback(),
                }
            }
            Some(normalized)
        }
        None => {
            if keepdims && shape.is_empty() {
                return fallback();
            }
            None
        }
    };

    let counts = count_valid_elements(&shape, mask.as_ref(), axes.as_deref(), keepdims)?;
    build_numpy_scalar_or_array(py, &counts)
}

#[pyfunction]
#[pyo3(signature = (a, axis=None, out=None, overwrite_input=false, keepdims=false))]
fn median(
    py: Python<'_>,
    a: Py<PyAny>,
    axis: Option<Py<PyAny>>,
    out: Option<Py<PyAny>>,
    overwrite_input: bool,
    keepdims: bool,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let median_fn = numpy.getattr("median")?;
    let axis_for_parse = axis.as_ref().map(|value| value.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(axis_val) = axis.as_ref() {
            kwargs.set_item("axis", axis_val.bind(py))?;
        }
        if let Some(out_val) = out.as_ref() {
            kwargs.set_item("out", out_val.bind(py))?;
        }
        kwargs.set_item("overwrite_input", overwrite_input)?;
        kwargs.set_item("keepdims", keepdims)?;
        Ok(median_fn.call((a.bind(py),), Some(&kwargs))?.unbind())
    };

    if out.as_ref().is_some_and(|value| !value.bind(py).is_none()) || overwrite_input || keepdims {
        return fallback();
    }

    let a = match extract_numeric_array(py, a.bind(py), "median(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let axis = match extract_axis_spec(py, axis_for_parse, "median") {
        Ok(None) => None,
        Ok(Some(axes)) if axes.len() == 1 => Some(axes[0]),
        Ok(Some(_)) => return fallback(),
        Err(_) => return fallback(),
    };
    let result = match a.median(axis) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    let output = build_numpy_array_from_ufunc(py, &result)?;
    if result.shape().is_empty() {
        return Ok(output.bind(py).get_item(())?.unbind());
    }
    Ok(output)
}

// Compute the unweighted covariance matrix following numpy's own algorithm:
// stack y onto m when present, transpose to rowvar=True orientation,
// reshape 1-D inputs to (1, n_obs), subtract the per-row mean, then
// return (X @ X.T) / (n_obs - ddof). Returns Err(fallback) for shapes
// that numpy handles via special-cases this path doesn't reproduce.
fn native_cov_unweighted(
    py: Python<'_>,
    m: &Bound<'_, PyAny>,
    y: Option<&Bound<'_, PyAny>>,
    rowvar: bool,
    ddof: usize,
) -> PyResult<Option<UFuncArray>> {
    let m_arr = match extract_precise_numeric_array(py, m, "cov(m)") {
        Ok(value) => value,
        Err(_) => return Ok(None),
    };
    if m_arr.has_integer_sidecar() || matches!(m_arr.dtype(), DType::Complex64 | DType::Complex128)
    {
        return Ok(None);
    }

    let y_arr = match y {
        Some(y_val) if !y_val.is_none() => {
            match extract_precise_numeric_array(py, y_val, "cov(y)") {
                Ok(value)
                    if !value.has_integer_sidecar()
                        && !matches!(value.dtype(), DType::Complex64 | DType::Complex128) =>
                {
                    Some(value)
                }
                _ => return Ok(None),
            }
        }
        _ => None,
    };

    // Normalize m to 2-D: 1-D becomes a single row (rowvar=True orientation).
    let to_2d = |arr: UFuncArray| -> Option<UFuncArray> {
        match arr.shape().len() {
            1 => {
                let n = arr.shape()[0] as isize;
                arr.reshape(&[1, n]).ok()
            }
            2 => Some(arr),
            _ => None,
        }
    };
    let Some(m_2d) = to_2d(m_arr) else {
        return Ok(None);
    };
    let stacked = if let Some(y_arr) = y_arr {
        let Some(y_2d) = to_2d(y_arr) else {
            return Ok(None);
        };
        let cat_axis: isize = if rowvar { 0 } else { 1 };
        match UFuncArray::concatenate(&[&m_2d, &y_2d], cat_axis) {
            Ok(value) => value,
            Err(_) => return Ok(None),
        }
    } else {
        m_2d
    };

    // After stacking: if rowvar=False and we have more than one row, transpose
    // so rows are variables. Matches numpy's `if not rowvar and X.shape[0] != 1: X = X.T`.
    let oriented = if !rowvar && stacked.shape()[0] != 1 {
        match stacked.transpose(None) {
            Ok(value) => value,
            Err(_) => return Ok(None),
        }
    } else {
        stacked
    };

    let n_vars = oriented.shape()[0];
    let n_obs = oriented.shape()[1];
    if n_obs == 0 || n_vars == 0 {
        return Ok(None);
    }
    if n_obs <= ddof {
        return Ok(None);
    }

    // avg = mean(X, axis=1), reshape to (n_vars, 1) and subtract (broadcasts).
    let avg = match oriented.reduce_mean(Some(1), true) {
        Ok(value) => value,
        Err(_) => return Ok(None),
    };
    let centered = match oriented.elementwise_binary(&avg, BinaryOp::Sub) {
        Ok(value) => value,
        Err(_) => return Ok(None),
    };

    // cov = X @ X.T / (n_obs - ddof)
    let x_t = match centered.transpose(None) {
        Ok(value) => value,
        Err(_) => return Ok(None),
    };
    let product = match centered.matmul(&x_t) {
        Ok(value) => value,
        Err(_) => return Ok(None),
    };
    // numpy multiplies by (1 / fact) rather than dividing by fact so that
    // ULP rounding matches `c *= true_divide(1, fact)` from np.cov.
    let fact = (n_obs - ddof) as f64;
    let inv_fact = 1.0_f64 / fact;
    let scale = match UFuncArray::full(product.shape().to_vec(), inv_fact, product.dtype()) {
        Ok(value) => value,
        Err(_) => return Ok(None),
    };
    let result = match product.elementwise_binary(&scale, BinaryOp::Mul) {
        Ok(value) => value,
        Err(_) => return Ok(None),
    };
    Ok(Some(result))
}

#[pyfunction]
#[pyo3(signature = (m, y=None, rowvar=true, bias=false, ddof=None, fweights=None, aweights=None))]
#[allow(clippy::too_many_arguments)]
fn cov(
    py: Python<'_>,
    m: Py<PyAny>,
    y: Option<Py<PyAny>>,
    rowvar: bool,
    bias: bool,
    ddof: Option<Py<PyAny>>,
    fweights: Option<Py<PyAny>>,
    aweights: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        let cov_fn = numpy.getattr("cov")?;
        let kwargs = PyDict::new(py);
        if let Some(y_val) = y.as_ref() {
            kwargs.set_item("y", y_val.bind(py))?;
        }
        kwargs.set_item("rowvar", rowvar)?;
        kwargs.set_item("bias", bias)?;
        if let Some(ddof_val) = ddof.as_ref() {
            kwargs.set_item("ddof", ddof_val.bind(py))?;
        }
        if let Some(fweights_val) = fweights.as_ref() {
            kwargs.set_item("fweights", fweights_val.bind(py))?;
        }
        if let Some(aweights_val) = aweights.as_ref() {
            kwargs.set_item("aweights", aweights_val.bind(py))?;
        }
        Ok(cov_fn.call((m.bind(py),), Some(&kwargs))?.unbind())
    };

    if fweights
        .as_ref()
        .is_some_and(|value| !value.bind(py).is_none())
        || aweights
            .as_ref()
            .is_some_and(|value| !value.bind(py).is_none())
    {
        return fallback(py);
    }

    // Resolve ddof. numpy: ddof defaults to 0 when bias=True else 1; if
    // caller passes ddof explicitly (non-None), it wins.
    let resolved_ddof = match ddof.as_ref() {
        Some(value) if !value.bind(py).is_none() => match value.bind(py).extract::<i64>() {
            Ok(d) if d >= 0 => d as usize,
            _ => return fallback(py),
        },
        _ => {
            if bias {
                0
            } else {
                1
            }
        }
    };

    let m_bound = m.bind(py);
    let y_binding = y.as_ref().map(|value| value.bind(py));
    let native = match native_cov_unweighted(py, m_bound, y_binding, rowvar, resolved_ddof) {
        Ok(Some(value)) => value,
        _ => return fallback(py),
    };

    // numpy returns c.squeeze() — 1-D input yields a 0-d scalar.
    let shape = native.shape().to_vec();
    let trivial_scalar = shape.iter().all(|&dim| dim == 1);
    let output = build_numpy_array_from_ufunc(py, &native)?;
    if trivial_scalar {
        return Ok(output.bind(py).call_method0("squeeze")?.unbind());
    }
    Ok(output)
}

#[pyfunction]
#[pyo3(signature = (x, y=None, rowvar=true, bias=None, ddof=None, dtype=None))]
fn corrcoef(
    py: Python<'_>,
    x: Py<PyAny>,
    y: Option<Py<PyAny>>,
    rowvar: bool,
    bias: Option<Py<PyAny>>,
    ddof: Option<Py<PyAny>>,
    dtype: Option<Py<PyAny>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        let corrcoef_fn = numpy.getattr("corrcoef")?;
        let kwargs = PyDict::new(py);
        if let Some(y_val) = y.as_ref() {
            kwargs.set_item("y", y_val.bind(py))?;
        }
        kwargs.set_item("rowvar", rowvar)?;
        if let Some(bias_val) = bias.as_ref() {
            kwargs.set_item("bias", bias_val.bind(py))?;
        }
        if let Some(ddof_val) = ddof.as_ref() {
            kwargs.set_item("ddof", ddof_val.bind(py))?;
        }
        if let Some(dtype_val) = dtype.as_ref() {
            kwargs.set_item("dtype", dtype_val.bind(py))?;
        }
        Ok(corrcoef_fn.call((x.bind(py),), Some(&kwargs))?.unbind())
    };

    // dtype kwarg affects the cov computation path (cast before average);
    // keep numpy in charge of that surface.
    if dtype
        .as_ref()
        .is_some_and(|value| !value.bind(py).is_none())
    {
        return fallback(py);
    }

    // Compute the underlying covariance natively. numpy.corrcoef always
    // uses the default ddof (1) / bias (False) for its internal cov call
    // regardless of the (deprecated) bias/ddof args passed in.
    let x_bound = x.bind(py);
    let y_binding = y.as_ref().map(|value| value.bind(py));
    let cov_array = match native_cov_unweighted(py, x_bound, y_binding, rowvar, 1) {
        Ok(Some(value)) => value,
        _ => return fallback(py),
    };

    // Extract the diagonal (variances), compute 1/sqrt, and normalize the
    // covariance matrix by the outer product of 1/stddev. numpy follows
    // `c /= stddev[:, None]; c /= stddev[None, :]; clip c to [-1, 1]`.
    let shape = cov_array.shape().to_vec();
    if shape.len() != 2 || shape[0] != shape[1] {
        return fallback(py);
    }
    let n_vars = shape[0];
    let diag: Vec<f64> = (0..n_vars)
        .map(|i| cov_array.values()[i * n_vars + i])
        .collect();
    let mut stddev = Vec::with_capacity(n_vars);
    for &value in &diag {
        if !value.is_finite() || value < 0.0 {
            return fallback(py);
        }
        stddev.push(value.sqrt());
    }

    let mut output = cov_array.values().to_vec();
    for row in 0..n_vars {
        let row_scale = stddev[row];
        if row_scale == 0.0 {
            return fallback(py);
        }
        for (col, &col_scale) in stddev.iter().enumerate().take(n_vars) {
            if col_scale == 0.0 {
                return fallback(py);
            }
            let idx = row * n_vars + col;
            // numpy performs the two divides sequentially so ULP drift
            // matches `c /= stddev[:, None]` then `c /= stddev[None, :]`.
            output[idx] /= row_scale;
            output[idx] /= col_scale;
            // Clip to [-1, 1] — numpy.corrcoef guards against small
            // numerical drift that pushes values just past the limits.
            output[idx] = output[idx].clamp(-1.0, 1.0);
        }
    }

    let result = match UFuncArray::from_storage(shape, ArrayStorage::F64(output)) {
        Ok(value) => value,
        Err(_) => return fallback(py),
    };
    build_numpy_array_from_ufunc(py, &result)
}

#[pyfunction]
#[pyo3(signature = (a, b, fill_value=true))]
fn allequal(py: Python<'_>, a: Py<PyAny>, b: Py<PyAny>, fill_value: bool) -> PyResult<Py<PyAny>> {
    let a_for_fallback = a.clone_ref(py);
    let b_for_fallback = b.clone_ref(py);
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let allequal_fn = numpy.getattr("ma")?.getattr("allequal")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item("fill_value", fill_value)?;
        Ok(allequal_fn
            .call(
                (a_for_fallback.bind(py), b_for_fallback.bind(py)),
                Some(&kwargs),
            )?
            .unbind())
    };

    let Some(a_masked) = extract_numeric_masked_array(py, a.bind(py), "allequal(a)")? else {
        return fallback();
    };
    let Some(b_masked) = extract_numeric_masked_array(py, b.bind(py), "allequal(b)")? else {
        return fallback();
    };

    if a_masked.data().shape() != b_masked.data().shape() {
        return Ok(PyBool::new(py, false).to_owned().into_any().unbind());
    }

    let a_mask = a_masked.mask().map(|mask| mask.values());
    let b_mask = b_masked.mask().map(|mask| mask.values());
    let equal = a_masked
        .data()
        .values()
        .iter()
        .zip(b_masked.data().values().iter())
        .enumerate()
        .all(|(idx, (&lhs, &rhs))| {
            let lhs_masked = a_mask.as_ref().is_some_and(|mask| mask[idx] != 0.0);
            let rhs_masked = b_mask.as_ref().is_some_and(|mask| mask[idx] != 0.0);
            match (lhs_masked, rhs_masked) {
                // numpy.ma.allequal treats any masked entry as fill_value
                // (controls whether masked positions count as equal). When
                // fill_value=False, both-masked should return False too,
                // not True as a naive "both masked ⇒ trivially equal".
                (true, true) | (true, false) | (false, true) => fill_value,
                (false, false) => !lhs.is_nan() && !rhs.is_nan() && lhs == rhs,
            }
        });

    Ok(PyBool::new(py, equal).to_owned().into_any().unbind())
}

