#[pyfunction]
#[pyo3(signature = (a, reps))]
fn tile(py: Python<'_>, a: Py<PyAny>, reps: Py<PyAny>) -> PyResult<Py<PyAny>> {
    // Native tile via UFuncArray::tile for real numeric arrays with
    // non-negative integer reps. Complex / structured / object / negative
    // reps / non-integer reps fall back to np.tile so numpy's broader
    // dispatch surface (scalar reps, batched handling, object dtype) is
    // preserved exactly.
    let numpy = py.import("numpy")?;
    let a_for_fallback = a.clone_ref(py);
    let reps_for_fallback = reps.clone_ref(py);
    let fallback = || -> PyResult<Py<PyAny>> {
        Ok(numpy
            .getattr("tile")?
            .call1((a_for_fallback.bind(py), reps_for_fallback.bind(py)))?
            .unbind())
    };

    // Normalize reps to Vec<usize>. Accept scalar int or 1-D iterable.
    let reps_bound = reps.bind(py);
    let reps_vec: Vec<usize> = if let Ok(scalar) = reps_bound.extract::<i64>() {
        if scalar < 0 {
            return fallback();
        }
        vec![scalar as usize]
    } else if let Ok(list) = reps_bound.extract::<Vec<i64>>() {
        if list.iter().any(|&v| v < 0) {
            return fallback();
        }
        list.iter().map(|&v| v as usize).collect()
    } else {
        return fallback();
    };

    let array = match extract_precise_numeric_array(py, a.bind(py), "tile(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    if matches!(array.dtype(), DType::Complex64 | DType::Complex128) {
        return fallback();
    }
    let result = match array.tile(&reps_vec) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    build_numpy_array_from_ufunc(py, &result)
}

#[pyfunction]
#[pyo3(signature = (a1, a2, equal_nan=false))]
fn array_equal(
    py: Python<'_>,
    a1: Py<PyAny>,
    a2: Py<PyAny>,
    equal_nan: bool,
) -> PyResult<Py<PyAny>> {
    // Native array_equal via UFuncArray::array_equal_nan. Falls back to
    // numpy for complex / integer-sidecar / mixed-dtype / non-numeric
    // inputs so numpy's dispatch surface (object arrays, strings, etc.)
    // stays exact. The return is a builtin Python bool (not np.bool_),
    // matching numpy's documented return type.
    let numpy = py.import("numpy")?;
    let array_equal_fn = numpy.getattr("array_equal")?;
    let a1_for_fallback = a1.clone_ref(py);
    let a2_for_fallback = a2.clone_ref(py);
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        kwargs.set_item("equal_nan", equal_nan)?;
        Ok(array_equal_fn
            .call(
                (a1_for_fallback.bind(py), a2_for_fallback.bind(py)),
                Some(&kwargs),
            )?
            .unbind())
    };
    let array_a = match extract_precise_numeric_array(py, a1.bind(py), "array_equal(a1)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let array_b = match extract_precise_numeric_array(py, a2.bind(py), "array_equal(a2)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    if array_a.has_integer_sidecar()
        || array_b.has_integer_sidecar()
        || matches!(array_a.dtype(), DType::Complex64 | DType::Complex128)
        || matches!(array_b.dtype(), DType::Complex64 | DType::Complex128)
    {
        return fallback();
    }
    let verdict = array_a.array_equal_nan(&array_b, equal_nan);
    Ok(pyo3::types::PyBool::new(py, verdict)
        .to_owned()
        .into_any()
        .unbind())
}

#[pyfunction]
#[pyo3(signature = (a1, a2))]
fn array_equiv(py: Python<'_>, a1: Py<PyAny>, a2: Py<PyAny>) -> PyResult<Py<PyAny>> {
    // Native array_equiv: broadcast a1 and a2, check all corresponding
    // entries agree. Non-broadcastable shapes return False (matches numpy);
    // non-numeric / complex / integer-sidecar inputs defer to numpy so the
    // object-dtype / structured surfaces stay exact.
    let numpy = py.import("numpy")?;
    let fallback = |py: Python<'_>| -> PyResult<Py<PyAny>> {
        Ok(numpy
            .getattr("array_equiv")?
            .call1((a1.bind(py), a2.bind(py)))?
            .unbind())
    };
    let array_a = match extract_precise_numeric_array(py, a1.bind(py), "array_equiv(a1)") {
        Ok(value) => value,
        Err(_) => return fallback(py),
    };
    let array_b = match extract_precise_numeric_array(py, a2.bind(py), "array_equiv(a2)") {
        Ok(value) => value,
        Err(_) => return fallback(py),
    };
    if array_a.has_integer_sidecar()
        || array_b.has_integer_sidecar()
        || matches!(array_a.dtype(), DType::Complex64 | DType::Complex128)
        || matches!(array_b.dtype(), DType::Complex64 | DType::Complex128)
    {
        return fallback(py);
    }
    // Shapes must be broadcast-compatible; any mismatch → False.
    if broadcast_shapes(&[array_a.shape(), array_b.shape()]).is_err() {
        return Ok(pyo3::types::PyBool::new(py, false)
            .to_owned()
            .into_any()
            .unbind());
    }
    let comparison = match array_a.elementwise_binary(&array_b, BinaryOp::Equal) {
        Ok(value) => value,
        Err(_) => return fallback(py),
    };
    let all_equal = comparison.values().iter().all(|&v| v != 0.0);
    Ok(pyo3::types::PyBool::new(py, all_equal)
        .to_owned()
        .into_any()
        .unbind())
}

