#[pyfunction]
#[pyo3(signature = (arr, axis=None))]
fn count_masked(py: Python<'_>, arr: Py<PyAny>, axis: Option<Py<PyAny>>) -> PyResult<Py<PyAny>> {
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let count_masked_fn = numpy.getattr("ma")?.getattr("count_masked")?;
        Ok(match &axis {
            Some(axis) => count_masked_fn.call1((arr.bind(py), axis.bind(py)))?,
            None => count_masked_fn.call1((arr.bind(py),))?,
        }
        .unbind())
    };

    let axis_for_parse = axis.as_ref().map(|value| value.clone_ref(py));
    let (_, mask, shape) = match extract_mask_metadata(py, arr.bind(py), "count_masked") {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    let mask = match mask {
        Some(mask) => mask,
        None => build_boolean_array(&shape, false, "count_masked")?,
    };
    let axes = match extract_axis_spec(py, axis_for_parse, "count_masked") {
        Ok(axes) => axes,
        Err(_) => return fallback(),
    };
    if let Some(axes) = axes.as_ref() {
        // numpy.ma.count_masked raises AxisError (a subclass of
        // ValueError) on out-of-bounds / duplicate axes. Fall back
        // to numpy so the error type and message match exactly.
        let ndim = mask.shape().len();
        if ensure_unique_axes(axes, ndim).is_err() {
            return fallback();
        }
        for &ax in axes {
            if try_normalize_axis(ax, ndim).is_none() {
                return fallback();
            }
        }
    }
    let result = match axes.as_ref() {
        None => mask.count_nonzero(None, false),
        Some(axes) if axes.len() == 1 => mask.count_nonzero(Some(axes[0]), false),
        Some(axes) => mask.count_nonzero_axes(axes, false),
    }
    .map_err(map_ufunc_error)?;
    let output = build_numpy_array_from_ufunc(py, &result)?;
    if result.shape().is_empty() {
        return Ok(output.bind(py).get_item(())?.unbind());
    }
    Ok(output)
}

#[pyfunction]
#[pyo3(signature = (a, b))]
fn kron(py: Python<'_>, a: Py<PyAny>, b: Py<PyAny>) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let kron_fn = numpy.getattr("kron")?;
    let fallback =
        || -> PyResult<Py<PyAny>> { Ok(kron_fn.call1((a.bind(py), b.bind(py)))?.unbind()) };

    let a = match extract_precise_numeric_array(py, a.bind(py), "kron(a)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let b = match extract_precise_numeric_array(py, b.bind(py), "kron(b)") {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    if a.has_integer_sidecar()
        || b.has_integer_sidecar()
        || matches!(a.dtype(), DType::Complex64 | DType::Complex128)
        || matches!(b.dtype(), DType::Complex64 | DType::Complex128)
    {
        return fallback();
    }
    let result = match a.kron(&b) {
        Ok(result) => result,
        Err(_) => return fallback(),
    };
    build_numpy_array_from_ufunc(py, &result)
}

