#[pyo3(signature = (x, axes=None))]
fn fftshift(py: Python<'_>, x: Py<PyAny>, axes: Option<Py<PyAny>>) -> PyResult<Py<PyAny>> {
    // Native fftshift via UFuncArray::roll{,_multi}: for every axis ax,
    // shift the array by shape[ax] // 2. Falls back to np.fft.fftshift for
    // non-numeric dtypes or unusual axis encodings (e.g. duplicate axes,
    // negative-axis tuples that numpy rejects) so error surface matches.
    fft_shift_impl(py, x, axes, /*inverse=*/ false, "fftshift")
}

#[pyfunction]
#[pyo3(signature = (x, axes=None))]
fn ifftshift(py: Python<'_>, x: Py<PyAny>, axes: Option<Py<PyAny>>) -> PyResult<Py<PyAny>> {
    // Native ifftshift — same as fftshift with negated shifts. On odd-length
    // arrays ifftshift is the true inverse of fftshift.
    fft_shift_impl(py, x, axes, /*inverse=*/ true, "ifftshift")
}

fn fft_shift_impl(
    py: Python<'_>,
    x: Py<PyAny>,
    axes: Option<Py<PyAny>>,
    inverse: bool,
    numpy_name: &'static str,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    let np_fn = numpy.getattr("fft")?.getattr(numpy_name)?;
    let x_for_fallback = x.clone_ref(py);
    let axes_for_fallback = axes.as_ref().map(|v| v.clone_ref(py));
    let fallback = || -> PyResult<Py<PyAny>> {
        let kwargs = PyDict::new(py);
        if let Some(value) = axes_for_fallback.as_ref() {
            kwargs.set_item("axes", value.bind(py))?;
        }
        Ok(np_fn
            .call((x_for_fallback.bind(py),), Some(&kwargs))?
            .unbind())
    };

    let array = match extract_precise_numeric_array(py, x.bind(py), numpy_name) {
        Ok(array) => array,
        Err(_) => return fallback(),
    };
    let shape = array.shape();
    let ndim = shape.len() as isize;
    // Determine the axes list and per-axis shift counts.
    let (shifts, ax_list): (Vec<isize>, Vec<isize>) = match axes.as_ref() {
        None => {
            let list: Vec<isize> = (0..ndim).collect();
            let shifts: Vec<isize> = shape
                .iter()
                .map(|&d| {
                    let mut s = (d / 2) as isize;
                    if inverse {
                        s = -s;
                    }
                    s
                })
                .collect();
            (shifts, list)
        }
        Some(value) => {
            let bound = value.bind(py);
            if bound.is_none() {
                let list: Vec<isize> = (0..ndim).collect();
                let shifts: Vec<isize> = shape
                    .iter()
                    .map(|&d| {
                        let mut s = (d / 2) as isize;
                        if inverse {
                            s = -s;
                        }
                        s
                    })
                    .collect();
                (shifts, list)
            } else if let Ok(single) = bound.extract::<i64>() {
                let ax = single as isize;
                let normalized = if ax < 0 { ax + ndim } else { ax };
                if normalized < 0 || normalized >= ndim {
                    return fallback();
                }
                let dim = shape[normalized as usize];
                let mut s = (dim / 2) as isize;
                if inverse {
                    s = -s;
                }
                (vec![s], vec![ax])
            } else if let Ok(multi) = bound.extract::<Vec<i64>>() {
                let mut shifts = Vec::with_capacity(multi.len());
                for &ax in &multi {
                    let normalized = if ax < 0 {
                        ax as isize + ndim
                    } else {
                        ax as isize
                    };
                    if normalized < 0 || normalized >= ndim {
                        return fallback();
                    }
                    let dim = shape[normalized as usize];
                    let mut s = (dim / 2) as isize;
                    if inverse {
                        s = -s;
                    }
                    shifts.push(s);
                }
                (shifts, multi.into_iter().map(|a| a as isize).collect())
            } else {
                return fallback();
            }
        }
    };

    let result = if ax_list.len() == 1 {
        match array.roll(shifts[0], Some(ax_list[0])) {
            Ok(result) => result,
            Err(_) => return fallback(),
        }
    } else {
        match array.roll_multi(&shifts, &ax_list) {
            Ok(result) => result,
            Err(_) => return fallback(),
        }
    };
    build_numpy_array_from_ufunc(py, &result)
}

#[pyfunction]
#[pyo3(signature = (n, d=1.0, device=None))]
fn rfftfreq(py: Python<'_>, n: usize, d: f64, device: Option<Py<PyAny>>) -> PyResult<Py<PyAny>> {
    validate_cpu_device_kwarg(py, device)?;
    if n == 0 || d == 0.0 {
        return Err(PyZeroDivisionError::new_err("float division by zero"));
    }
    let result = UFuncArray::rfftfreq(n, d);
    build_numpy_array_from_ufunc(py, &result)
}

