#[pyfunction]
#[pyo3(signature = (arr, indices, values, axis=Some(-1)))]
fn put_along_axis(
    py: Python<'_>,
    arr: Py<PyAny>,
    indices: Py<PyAny>,
    values: Py<PyAny>,
    axis: Option<isize>,
) -> PyResult<Py<PyAny>> {
    let arr_for_fallback = arr.clone_ref(py);
    let indices_for_fallback = indices.clone_ref(py);
    let values_for_fallback = values.clone_ref(py);
    let invoke_fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item(
            "axis",
            match axis {
                Some(axis) => axis.into_pyobject(py)?.into_any(),
                None => py.None().into_bound(py),
            },
        )?;
        Ok(numpy
            .getattr("put_along_axis")?
            .call(
                (
                    arr_for_fallback.bind(py),
                    indices_for_fallback.bind(py),
                    values_for_fallback.bind(py),
                ),
                Some(&kwargs),
            )?
            .unbind())
    };
    let arr = arr.bind(py);
    let _ = arr.getattr("ndim")?;
    let original_shape = arr.getattr("shape")?.extract::<Vec<usize>>()?;
    let mut array = extract_numeric_array(py, arr, "put_along_axis(arr)")?;

    let indices_obj = indices.bind(py);
    let _ = indices_obj.getattr("ndim")?;
    let indices = extract_integer_array(py, indices_obj, "put_along_axis(indices)")?;
    let values = extract_numeric_array(py, values.bind(py), "put_along_axis(values)")?;

    // numpy.put_along_axis raises IndexError (not ValueError) on
    // out-of-bounds indices. Our ufunc layer returns Msg which
    // map_ufunc_error flattens to PyValueError — fall back to numpy so
    // the exception type matches. The fallback re-runs the full op
    // through numpy including the in-place write, which is a no-op
    // when numpy also errors.
    match axis {
        Some(axis) => {
            let values = reshape_with_leading_singletons(
                values,
                array.shape().len(),
                "put_along_axis(values)",
            )?;
            if array.put_along_axis(&indices, &values, axis).is_err() {
                return invoke_fallback();
            }
        }
        None => {
            if indices.shape().len() != 1 {
                return Err(PyValueError::new_err(
                    "when axis=None, `indices` must have a single dimension.",
                ));
            }

            let values = values.flatten();
            let mut flattened = array.flatten();
            if flattened.put_along_axis(&indices, &values, 0).is_err() {
                return invoke_fallback();
            }

            let reshaped_shape = original_shape
                .iter()
                .map(|&dim| {
                    isize::try_from(dim).map_err(|_| {
                        PyValueError::new_err(format!(
                            "put_along_axis(arr): dimension {dim} exceeds signed pointer range",
                        ))
                    })
                })
                .collect::<PyResult<Vec<_>>>()?;
            array = flattened
                .reshape(&reshaped_shape)
                .map_err(map_ufunc_error)?;
        }
    }

    copy_result_into_numpy_array(py, arr, &array)?;
    Ok(py.None())
}

#[pyfunction]
#[pyo3(signature = (arr, indices, axis=Some(-1)))]
fn take_along_axis(
    py: Python<'_>,
    arr: Py<PyAny>,
    indices: Py<PyAny>,
    axis: Option<isize>,
) -> PyResult<Py<PyAny>> {
    let arr_for_fallback = arr.clone_ref(py);
    let indices_for_fallback = indices.clone_ref(py);
    let fallback = || -> PyResult<Py<PyAny>> {
        let numpy = py.import("numpy")?;
        let kwargs = PyDict::new(py);
        kwargs.set_item(
            "axis",
            match axis {
                Some(axis) => axis.into_pyobject(py)?.into_any(),
                None => py.None().into_bound(py),
            },
        )?;
        Ok(numpy
            .getattr("take_along_axis")?
            .call(
                (arr_for_fallback.bind(py), indices_for_fallback.bind(py)),
                Some(&kwargs),
            )?
            .unbind())
    };
    let arr = extract_numeric_array(py, arr.bind(py), "take_along_axis(arr)")?;
    let indices = extract_integer_array(py, indices.bind(py), "take_along_axis(indices)")?;

    // numpy.take_along_axis raises IndexError (not ValueError) on
    // out-of-bounds indices. Our ufunc layer returns Msg which
    // map_ufunc_error flattens to PyValueError — fall back to numpy so
    // the exception type, message, and traceback match verbatim.
    let result = match axis {
        Some(axis) => match arr.take_along_axis(&indices, axis) {
            Ok(result) => result,
            Err(_) => return fallback(),
        },
        None => {
            if indices.shape().len() != 1 {
                return Err(PyValueError::new_err(
                    "take_along_axis: when axis=None, indices must have a single dimension",
                ));
            }
            match arr.flatten().take_along_axis(&indices, 0) {
                Ok(result) => result,
                Err(_) => return fallback(),
            }
        }
    };

    build_numpy_array_from_ufunc(py, &result)
}

// ---------------------------------------------------------------------------
// Reality-check (k74v.8) — 31 core numpy passthrough wrappers.
//
// Each wrapper forwards all args + kwargs to `numpy.<name>`, preserving the
// full numpy signature surface without re-typing it. Coverage goal: closes
// ~31 of the 183-name numpy.__all__ gap identified in vhd5's audit (pushes
// fnp_python from 63.9% → ~70% of numpy.__all__). The helper `core_numpy_passthrough`
// amortises the common work so each #[pyfunction] is a 3-line trampoline.
// ---------------------------------------------------------------------------

fn core_numpy_passthrough(
    py: Python<'_>,
    name: &str,
    args: &Bound<'_, PyTuple>,
    kwargs: Option<&Bound<'_, PyDict>>,
) -> PyResult<Py<PyAny>> {
    let numpy = py.import("numpy")?;
    Ok(numpy.getattr(name)?.call(args, kwargs)?.unbind())
}

