    #[test]
    fn random_state_get_set_state_matches_numpy_oracles() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test_random_state_state")?;
            fnp_python(&module)?;
            let random = module.getattr("random")?;
            let numpy_random = py.import("numpy")?.getattr("random")?;
            let shape = PyTuple::new(py, [2_usize, 3_usize])?;

            let ours = random.getattr("RandomState")?.call1((7_u64,))?;
            let theirs = numpy_random.getattr("RandomState")?.call1((7_u64,))?;
            let ours_state = ours.call_method0("get_state")?;
            let theirs_state = theirs.call_method0("get_state")?;
            let ours_tuple = ours_state.cast::<PyTuple>()?;
            let theirs_tuple = theirs_state.cast::<PyTuple>()?;
            assert_eq!(ours_tuple.len()?, 5);
            assert_eq!(
                ours_tuple.get_item(0)?.extract::<String>()?,
                theirs_tuple.get_item(0)?.extract::<String>()?
            );
            assert_random_sample_matches_numpy(
                &ours_tuple.get_item(1)?,
                &theirs_tuple.get_item(1)?,
            )?;
            assert_eq!(
                ours_tuple.get_item(2)?.extract::<usize>()?,
                theirs_tuple.get_item(2)?.extract::<usize>()?
            );
            assert_eq!(
                ours_tuple.get_item(3)?.extract::<i64>()?,
                theirs_tuple.get_item(3)?.extract::<i64>()?
            );
            assert_eq!(
                ours_tuple.get_item(4)?.extract::<f64>()?,
                theirs_tuple.get_item(4)?.extract::<f64>()?
            );

            let ours_dict = ours.call_method1("get_state", (false,))?;
            let theirs_dict = theirs.call_method1("get_state", (false,))?;
            let ours_dict = ours_dict.cast::<PyDict>()?;
            let theirs_dict = theirs_dict.cast::<PyDict>()?;
            assert_eq!(
                required_dict_item(ours_dict, "bit_generator")?.extract::<String>()?,
                required_dict_item(theirs_dict, "bit_generator")?.extract::<String>()?
            );
            let ours_nested = required_dict_item(ours_dict, "state")?;
            let theirs_nested = required_dict_item(theirs_dict, "state")?;
            let ours_nested = ours_nested.cast::<PyDict>()?;
            let theirs_nested = theirs_nested.cast::<PyDict>()?;
            assert_random_sample_matches_numpy(
                &required_dict_item(ours_nested, "key")?,
                &required_dict_item(theirs_nested, "key")?,
            )?;
            assert_eq!(
                required_dict_item(ours_nested, "pos")?.extract::<usize>()?,
                required_dict_item(theirs_nested, "pos")?.extract::<usize>()?
            );

            let ours_restore = random.getattr("RandomState")?.call1((99_u64,))?;
            let theirs_restore = numpy_random.getattr("RandomState")?.call1((99_u64,))?;
            ours_restore.call_method1("random_sample", (4_usize,))?;
            theirs_restore.call_method1("random_sample", (4_usize,))?;
            let ours_saved = ours_restore.call_method0("get_state")?;
            let theirs_saved = theirs_restore.call_method0("get_state")?;
            ours_restore.call_method1("random_sample", (3_usize,))?;
            theirs_restore.call_method1("random_sample", (3_usize,))?;
            ours_restore.call_method1("set_state", (ours_saved,))?;
            theirs_restore.call_method1("set_state", (theirs_saved,))?;
            assert_random_sample_matches_numpy(
                &ours_restore.call_method1("random_sample", (shape.clone(),))?,
                &theirs_restore.call_method1("random_sample", (shape.clone(),))?,
            )?;

            let ours_tuple_import = random.getattr("RandomState")?.call1((1_u64,))?;
            let theirs_tuple_import = numpy_random.getattr("RandomState")?.call1((123_u64,))?;
            theirs_tuple_import.call_method1("random_sample", (5_usize,))?;
            let imported_tuple = theirs_tuple_import.call_method0("get_state")?;
            ours_tuple_import.call_method1("set_state", (imported_tuple,))?;
            assert_random_sample_matches_numpy(
                &ours_tuple_import.call_method1("random_sample", (shape.clone(),))?,
                &theirs_tuple_import.call_method1("random_sample", (shape.clone(),))?,
            )?;

            let ours_dict_import = random.getattr("RandomState")?.call1((1_u64,))?;
            let theirs_dict_import = numpy_random.getattr("RandomState")?.call1((321_u64,))?;
            theirs_dict_import.call_method1("random_sample", (5_usize,))?;
            let imported_dict = theirs_dict_import.call_method1("get_state", (false,))?;
            ours_dict_import.call_method1("set_state", (imported_dict,))?;
            assert_random_sample_matches_numpy(
                &ours_dict_import.call_method1("random_sample", (shape.clone(),))?,
                &theirs_dict_import.call_method1("random_sample", (shape,))?,
            )?;

            Ok(())
        });
    }

    #[test]
    fn random_seed_sequence_matches_numpy_oracles() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test_seed_sequence")?;
            fnp_python(&module)?;
            let random = module.getattr("random")?;
            let numpy = py.import("numpy")?;
            let numpy_random = numpy.getattr("random")?;

            let ours = random.getattr("SeedSequence")?.call1((42_u64,))?;
            let theirs = numpy_random.getattr("SeedSequence")?.call1((42_u64,))?;
            assert_eq!(
                repr_string(&ours.getattr("entropy")?),
                repr_string(&theirs.getattr("entropy")?)
            );
            assert_eq!(
                repr_string(&ours.getattr("spawn_key")?),
                repr_string(&theirs.getattr("spawn_key")?)
            );
            assert_eq!(
                ours.getattr("pool_size")?.extract::<usize>()?,
                theirs.getattr("pool_size")?.extract::<usize>()?
            );
            assert_eq!(
                ours.getattr("n_children_spawned")?.extract::<u64>()?,
                theirs.getattr("n_children_spawned")?.extract::<u64>()?
            );
            assert_array_matches_numpy(&ours.getattr("pool")?, &theirs.getattr("pool")?)?;
            assert_array_matches_numpy(
                &ours.call_method1("generate_state", (4_usize,))?,
                &theirs.call_method1("generate_state", (4_usize,))?,
            )?;

            let uint64_kwargs = PyDict::new(py);
            uint64_kwargs.set_item("dtype", numpy.getattr("uint64")?)?;
            assert_array_matches_numpy(
                &ours.call_method("generate_state", (3_usize,), Some(&uint64_kwargs))?,
                &theirs.call_method("generate_state", (3_usize,), Some(&uint64_kwargs))?,
            )?;

            assert_eq!(ours.call_method1("spawn", (0_usize,))?.len()?, 0);
            assert_eq!(theirs.call_method1("spawn", (0_usize,))?.len()?, 0);
            let ours_children = ours.call_method1("spawn", (2_usize,))?;
            let theirs_children = theirs.call_method1("spawn", (2_usize,))?;
            assert_eq!(ours_children.len()?, theirs_children.len()?);
            for index in 0..ours_children.len()? {
                let ours_child = ours_children.get_item(index)?;
                let theirs_child = theirs_children.get_item(index)?;
                assert_eq!(
                    repr_string(&ours_child.getattr("spawn_key")?),
                    repr_string(&theirs_child.getattr("spawn_key")?)
                );
                assert_array_matches_numpy(
                    &ours_child.call_method1("generate_state", (4_usize,))?,
                    &theirs_child.call_method1("generate_state", (4_usize,))?,
                )?;
            }
            assert_eq!(
                ours.getattr("n_children_spawned")?.extract::<u64>()?,
                theirs.getattr("n_children_spawned")?.extract::<u64>()?
            );

            let kwargs = PyDict::new(py);
            kwargs.set_item("spawn_key", PyTuple::new(py, [4_u32])?)?;
            kwargs.set_item("n_children_spawned", 3_u64)?;
            let entropy = PyList::new(py, [1_u32, 2_u32, 3_u32])?;
            let ours = random
                .getattr("SeedSequence")?
                .call((entropy.clone(),), Some(&kwargs))?;
            let theirs = numpy_random
                .getattr("SeedSequence")?
                .call((entropy,), Some(&kwargs))?;
            assert_eq!(
                repr_string(&ours.getattr("state")?),
                repr_string(&theirs.getattr("state")?)
            );
            assert_array_matches_numpy(
                &ours.call_method1("generate_state", (4_usize,))?,
                &theirs.call_method1("generate_state", (4_usize,))?,
            )?;

            Ok(())
        });
    }

    #[test]
    fn random_bit_generator_state_setter_matches_numpy_oracles() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test_random_state_setter")?;
            fnp_python(&module)?;
            let random = module.getattr("random")?;
            let numpy_random = py.import("numpy")?.getattr("random")?;

            for name in ["MT19937", "PCG64", "PCG64DXSM", "Philox", "SFC64"] {
                let ours = random.getattr(name)?.call1((987_u64,))?;
                let theirs = numpy_random.getattr(name)?.call1((987_u64,))?;
                let _ = ours.call_method1("random_raw", (3_usize,))?;
                let _ = theirs.call_method1("random_raw", (3_usize,))?;

                let ours_state = ours.getattr("state")?;
                let theirs_state = theirs.getattr("state")?;
                let ours_expected = ours.call_method1("random_raw", (5_usize,))?;
                let theirs_expected = theirs.call_method1("random_raw", (5_usize,))?;

                ours.setattr("state", ours_state)?;
                theirs.setattr("state", theirs_state)?;
                let ours_restored = ours.call_method1("random_raw", (5_usize,))?;
                let theirs_restored = theirs.call_method1("random_raw", (5_usize,))?;

                assert_array_matches_numpy(&ours_restored, &ours_expected)?;
                assert_array_matches_numpy(&theirs_restored, &theirs_expected)?;
            }

            for name in ["PCG64", "PCG64DXSM"] {
                let ours = random.getattr(name)?.call1((2468_u64,))?;
                let theirs = numpy_random.getattr(name)?.call1((2468_u64,))?;
                let _ = ours.call_method1("random_raw", (2_usize,))?;
                let _ = theirs.call_method1("random_raw", (2_usize,))?;
                ours.setattr("state", theirs.getattr("state")?)?;
                assert_array_matches_numpy(
                    &ours.call_method1("random_raw", (6_usize,))?,
                    &theirs.call_method1("random_raw", (6_usize,))?,
                )?;
            }

            Ok(())
        });
    }

