    #[test]
    fn k74v_2_function_passthroughs_match_numpy_family_oracles() {
        // Family-level parity for the k74v.2 passthrough wrappers: one
        // representative case per family (casting predicates, rounding
        // aliases, atleast_Nd, array-API aliases, nan-aware cumulatives,
        // busday, datetime-as-string, format helpers, repr helpers).
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }
            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let numpy = py.import("numpy")?;
            let array_equal = numpy.getattr("array_equal")?;

            // Casting predicates — compare scalar booleans via repr.
            // can_cast takes (from, to) dtypes.
            for (name, ok_args) in [
                ("can_cast", ("int32", "float64")),
                ("issubdtype", ("int32", "int32")),
            ] {
                let ours = module.getattr(name)?.call1(ok_args)?;
                let theirs = numpy.getattr(name)?.call1(ok_args)?;
                assert_eq!(
                    ours.repr()?.extract::<String>()?,
                    theirs.repr()?.extract::<String>()?,
                    "{name} diverged"
                );
            }
            // isdtype requires a numpy dtype object (not a string) for the
            // first argument; pass numpy.int32 directly.
            let int32_dtype = numpy.getattr("int32")?;
            let ours_isdt = module
                .getattr("isdtype")?
                .call1((int32_dtype.clone(), "integral"))?;
            let theirs_isdt = numpy.getattr("isdtype")?.call1((int32_dtype, "integral"))?;
            assert_eq!(
                ours_isdt.repr()?.extract::<String>()?,
                theirs_isdt.repr()?.extract::<String>()?,
                "isdtype diverged"
            );
            let ours_pt = module
                .getattr("promote_types")?
                .call1(("int32", "float64"))?;
            let theirs_pt = numpy
                .getattr("promote_types")?
                .call1(("int32", "float64"))?;
            assert_eq!(
                ours_pt.repr()?.extract::<String>()?,
                theirs_pt.repr()?.extract::<String>()?,
                "promote_types diverged"
            );
            let ours_rt = module.getattr("result_type")?.call1(("int32", "float64"))?;
            let theirs_rt = numpy.getattr("result_type")?.call1(("int32", "float64"))?;
            assert_eq!(
                ours_rt.repr()?.extract::<String>()?,
                theirs_rt.repr()?.extract::<String>()?,
                "result_type diverged"
            );

            // Rounding aliases on a float vector.
            let x = numpy
                .getattr("array")?
                .call1((PyList::new(py, [1.4_f64, 2.6, -0.5, 3.5])?,))?;
            for name in ["around", "round"] {
                let ours = module.getattr(name)?.call1((x.clone(),))?;
                let theirs = numpy.getattr(name)?.call1((x.clone(),))?;
                let ok: bool = array_equal.call1((&ours, &theirs))?.extract()?;
                assert!(ok, "{name} diverged");
            }

            // atleast_Nd family.
            for name in ["atleast_1d", "atleast_2d", "atleast_3d"] {
                let ours = module.getattr(name)?.call1((5.0_f64,))?;
                let theirs = numpy.getattr(name)?.call1((5.0_f64,))?;
                assert!(
                    array_equal.call1((&ours, &theirs))?.extract::<bool>()?,
                    "{name} diverged"
                );
            }

            // Unique array-API aliases.
            let u_in = numpy
                .getattr("array")?
                .call1((PyList::new(py, [3_i64, 1, 2, 1, 3])?,))?;
            let ours_uv = module.getattr("unique_values")?.call1((u_in.clone(),))?;
            let theirs_uv = numpy.getattr("unique_values")?.call1((u_in,))?;
            assert!(
                array_equal
                    .call1((&ours_uv, &theirs_uv))?
                    .extract::<bool>()?,
                "unique_values diverged"
            );

            // Cumulative Array-API aliases on a small vector.
            let c_in = numpy
                .getattr("array")?
                .call1((PyList::new(py, [1_i64, 2, 3, 4])?,))?;
            for name in ["cumulative_sum", "cumulative_prod"] {
                let ours = module.getattr(name)?.call1((c_in.clone(),))?;
                let theirs = numpy.getattr(name)?.call1((c_in.clone(),))?;
                assert!(
                    array_equal.call1((&ours, &theirs))?.extract::<bool>()?,
                    "{name} diverged"
                );
            }

            // isclose on a float pair.
            let l = numpy
                .getattr("array")?
                .call1((PyList::new(py, [1.0_f64, 2.0])?,))?;
            let r = numpy
                .getattr("array")?
                .call1((PyList::new(py, [1.0_f64, 2.0000001])?,))?;
            let ours_ic = module.getattr("isclose")?.call1((l.clone(), r.clone()))?;
            let theirs_ic = numpy.getattr("isclose")?.call1((l, r))?;
            assert!(
                array_equal
                    .call1((&ours_ic, &theirs_ic))?
                    .extract::<bool>()?,
                "isclose diverged"
            );

            // Convolve / correlate on small integer arrays.
            let a = numpy
                .getattr("array")?
                .call1((PyList::new(py, [1_i64, 2, 3])?,))?;
            let b = numpy
                .getattr("array")?
                .call1((PyList::new(py, [0_i64, 1, 0])?,))?;
            for name in ["convolve", "correlate"] {
                let ours = module.getattr(name)?.call1((a.clone(), b.clone()))?;
                let theirs = numpy.getattr(name)?.call1((a.clone(), b.clone()))?;
                assert!(
                    array_equal.call1((&ours, &theirs))?.extract::<bool>()?,
                    "{name} diverged"
                );
            }

            // NaN cumulative variants on a small NaN-containing vector.
            let nan_in = numpy
                .getattr("array")?
                .call1((PyList::new(py, [1.0_f64, f64::NAN, 3.0, 4.0])?,))?;
            for name in ["nancumsum", "nancumprod"] {
                let ours = module.getattr(name)?.call1((nan_in.clone(),))?;
                let theirs = numpy.getattr(name)?.call1((nan_in.clone(),))?;
                assert!(
                    array_equal.call1((&ours, &theirs))?.extract::<bool>()?,
                    "{name} diverged"
                );
            }

            // shape.
            let s_in = numpy
                .getattr("zeros")?
                .call1((PyTuple::new(py, [2_i64, 3, 4])?,))?;
            let ours_s = module.getattr("shape")?.call1((s_in.clone(),))?;
            let theirs_s = numpy.getattr("shape")?.call1((s_in,))?;
            assert_eq!(
                ours_s.repr()?.extract::<String>()?,
                theirs_s.repr()?.extract::<String>()?,
                "shape diverged"
            );

            // Busday.
            let d1 = numpy
                .getattr("array")?
                .call1((PyList::new(py, ["2024-01-01"])?,))?
                .call_method1("astype", ("datetime64[D]",))?;
            let d2 = numpy
                .getattr("array")?
                .call1((PyList::new(py, ["2024-01-08"])?,))?
                .call_method1("astype", ("datetime64[D]",))?;
            let ours_bc = module
                .getattr("busday_count")?
                .call1((d1.clone(), d2.clone()))?;
            let theirs_bc = numpy
                .getattr("busday_count")?
                .call1((d1.clone(), d2.clone()))?;
            assert!(
                array_equal
                    .call1((&ours_bc, &theirs_bc))?
                    .extract::<bool>()?,
                "busday_count diverged"
            );

            // binary_repr / base_repr.
            let ours_br = module.getattr("binary_repr")?.call1((42_i64,))?;
            let theirs_br = numpy.getattr("binary_repr")?.call1((42_i64,))?;
            assert_eq!(
                ours_br.repr()?.extract::<String>()?,
                theirs_br.repr()?.extract::<String>()?,
                "binary_repr diverged"
            );
            let ours_baser = module.getattr("base_repr")?.call1((42_i64, 5_i64))?;
            let theirs_baser = numpy.getattr("base_repr")?.call1((42_i64, 5_i64))?;
            assert_eq!(
                ours_baser.repr()?.extract::<String>()?,
                theirs_baser.repr()?.extract::<String>()?,
                "base_repr diverged"
            );

            // format_float_positional.
            let ours_ff = module
                .getattr("format_float_positional")?
                .call1((std::f64::consts::PI,))?;
            let theirs_ff = numpy
                .getattr("format_float_positional")?
                .call1((std::f64::consts::PI,))?;
            assert_eq!(
                ours_ff.repr()?.extract::<String>()?,
                theirs_ff.repr()?.extract::<String>()?,
                "format_float_positional diverged"
            );

            Ok(())
        });
    }

    #[test]
    fn k74v_5_nested_submodules_expose_numpy_native_names() {
        // Verifies the k74v.5 namespace-strategy resolution: fnp_python
        // exposes .fft / .linalg / .ma / .testing / .lib.recfunctions and
        // .lib.stride_tricks as real nested submodules so
        // `import fnp_python as np; np.linalg.svd(...)` works verbatim
        // against numpy-native spellings.
        with_python(|py| {
            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;

            // fft submodule.
            let fft = module.getattr("fft")?;
            for name in [
                "fft",
                "ifft",
                "fft2",
                "ifft2",
                "fftn",
                "ifftn",
                "rfft",
                "irfft",
                "rfftn",
                "irfftn",
                "hfft",
                "ihfft",
                "rfft2",
                "irfft2",
                "fftfreq",
                "rfftfreq",
                "fftshift",
                "ifftshift",
            ] {
                assert!(fft.getattr(name).is_ok(), "fnp_python.fft.{name} missing");
            }
            let callable = py.import("builtins")?.getattr("callable")?;
            assert!(
                callable.call1((&fft,))?.extract::<bool>()?,
                "fnp_python.fft must remain callable as a flat fft(...) compatibility path",
            );
            let registered_fft = py
                .import("sys")?
                .getattr("modules")?
                .get_item("fnp_python_test.fft")?;
            assert!(
                registered_fft.is(&fft),
                "fnp_python.fft submodule should be registered under sys.modules",
            );

            // linalg submodule.
            let linalg = module.getattr("linalg")?;
            let mut linalg_names: Vec<&str> = vec![
                "eig",
                "matrix_norm",
                "vecdot",
                "svd",
                "svdvals",
                "qr",
                "lstsq",
                "solve",
                "inv",
                "cholesky",
                "slogdet",
                "matrix_rank",
                "matrix_power",
                "matrix_transpose",
                "pinv",
                "norm",
                "cond",
                "tensorinv",
                "tensorsolve",
                "multi_dot",
                "det",
                "solve_triangular",
                "eigh",
                "eigvals",
                "eigvalsh",
                "cross",
                "tensordot",
                "matmul",
                "diagonal",
                "outer",
                "trace",
                "vector_norm",
            ];
            // LinAlgError is a numpy type re-export — only verify when numpy
            // is actually importable on the host Python. On numpy-less CI
            // workers the lazy __getattr__ fallback can't resolve it.
            if numpy_available(py) {
                linalg_names.push("LinAlgError");
            }
            for name in linalg_names {
                assert!(
                    linalg.getattr(name).is_ok(),
                    "fnp_python.linalg.{name} missing"
                );
            }

            // ma submodule.
            let ma = module.getattr("ma")?;
            for name in [
                "count",
                "argmax",
                "argmin",
                "average",
                "ediff1d",
                "masked_where",
                "masked_equal",
                "masked_not_equal",
                "masked_less",
                "masked_greater",
                "masked_less_equal",
                "masked_greater_equal",
                "masked_inside",
                "masked_outside",
                "masked_values",
                "masked_invalid",
                "masked_all",
                "masked_all_like",
                "compressed",
                "getmask",
                "getmaskarray",
                "is_masked",
                "mask_or",
                "make_mask",
                "allequal",
                "count_masked",
                "minimum_fill_value",
                "maximum_fill_value",
                "filled",
                "fix_invalid",
            ] {
                assert!(ma.getattr(name).is_ok(), "fnp_python.ma.{name} missing");
            }

            // testing submodule.
            let testing = module.getattr("testing")?;
            for name in [
                "assert_allclose",
                "assert_equal",
                "assert_almost_equal",
                "assert_array_almost_equal",
                "assert_array_less",
                "assert_approx_equal",
                "assert_string_equal",
                "assert_array_equal",
            ] {
                assert!(
                    testing.getattr(name).is_ok(),
                    "fnp_python.testing.{name} missing"
                );
            }

            // lib.recfunctions submodule (two-level nesting).
            let lib_mod = module.getattr("lib")?;
            let recfunctions = lib_mod.getattr("recfunctions")?;
            for name in [
                "drop_fields",
                "rename_fields",
                "append_fields",
                "merge_arrays",
                "unstructured_to_structured",
            ] {
                assert!(
                    recfunctions.getattr(name).is_ok(),
                    "fnp_python.lib.recfunctions.{name} missing"
                );
            }
            let stride_tricks = lib_mod.getattr("stride_tricks")?;
            for name in ["sliding_window_view", "as_strided"] {
                assert!(
                    stride_tricks.getattr(name).is_ok(),
                    "fnp_python.lib.stride_tricks.{name} missing"
                );
            }
            let sys_modules = py.import("sys")?.getattr("modules")?;
            assert!(
                sys_modules.get_item("fnp_python_test.lib")?.is(&lib_mod),
                "fnp_python.lib should be registered under sys.modules",
            );
            assert!(
                sys_modules
                    .get_item("fnp_python_test.lib.stride_tricks")?
                    .is(&stride_tricks),
                "fnp_python.lib.stride_tricks should be registered under sys.modules",
            );

            // Sanity-check an actual call round-trips through the submodule.
            if numpy_available(py) {
                let numpy = py.import("numpy")?;
                let signal = numpy
                    .getattr("array")?
                    .call1((PyList::new(py, [1.0_f64, 2.0, 3.0, 4.0])?,))?;
                let numpy_fft = numpy.getattr("fft")?.getattr("fft")?;
                let allclose = numpy.getattr("allclose")?;
                let expected_fft = numpy_fft.call1((signal.clone(),))?;
                let flat_fft = fft.call1((signal.clone(),))?;
                assert!(
                    allclose
                        .call1((&flat_fft, &expected_fft))?
                        .extract::<bool>()?,
                    "callable fnp_python.fft(...) diverges from numpy.fft.fft(...)",
                );
                let nested_fft = fft.getattr("fft")?.call1((signal,))?;
                assert!(
                    allclose
                        .call1((&nested_fft, &expected_fft))?
                        .extract::<bool>()?,
                    "fnp_python.fft.fft(...) diverges from numpy.fft.fft(...)",
                );
                let base = numpy.getattr("arange")?.call1((5_i64,))?;
                let ours_window = stride_tricks
                    .getattr("sliding_window_view")?
                    .call1((base.clone(), 3_i64))?;
                let theirs_window = numpy
                    .getattr("lib")?
                    .getattr("stride_tricks")?
                    .getattr("sliding_window_view")?
                    .call1((base, 3_i64))?;
                assert_array_matches_numpy(&ours_window, &theirs_window)?;

                let eye3 = numpy.getattr("eye")?.call1((3_i64,))?;
                let our_svd = linalg.getattr("svd")?.call1((eye3.clone(),))?;
                let their_svd = numpy.getattr("linalg")?.getattr("svd")?.call1((eye3,))?;
                // Both return SVDResult; compare their repr prefixes to
                // avoid hash / pointer equality noise.
                assert_eq!(
                    our_svd.get_type().name()?.extract::<String>()?,
                    their_svd.get_type().name()?.extract::<String>()?,
                    "fnp_python.linalg.svd return type diverges from numpy.linalg.svd"
                );

                // linalg.cross must REJECT 2-D input (stricter than top-
                // level np.cross which accepts both 2-D and 3-D). Our
                // submodule wires linalg.cross directly to numpy.linalg.cross
                // to preserve that contract — regressing to np.cross here
                // would silently accept 2-D vectors and trip this assert.
                let a2 = numpy
                    .getattr("array")?
                    .call1((PyList::new(py, [1.0_f64, 2.0])?,))?;
                let b2 = numpy
                    .getattr("array")?
                    .call1((PyList::new(py, [3.0_f64, 4.0])?,))?;
                let ours_cross_err = linalg
                    .getattr("cross")?
                    .call1((a2.clone(), b2.clone()))
                    .expect_err("fnp_python.linalg.cross must reject 2-D vectors");
                let theirs_cross_err = numpy
                    .getattr("linalg")?
                    .getattr("cross")?
                    .call1((a2, b2))
                    .expect_err("numpy.linalg.cross must reject 2-D vectors");
                assert_eq!(
                    ours_cross_err.get_type(py).name()?.extract::<String>()?,
                    theirs_cross_err.get_type(py).name()?.extract::<String>()?,
                    "linalg.cross error type diverges from numpy.linalg.cross"
                );
            }
            Ok(())
        });
    }

    #[test]
    fn k74v_1_ufunc_passthroughs_match_numpy_family_oracles() {
        // Family-level parity for the k74v.1 passthrough wrappers: one
        // representative case per family (trig, bitwise, comparison, logical,
        // elementwise min/max, modular arithmetic, datetime, matrix gufunc).
        // Each case runs through BOTH our module's passthrough and numpy's
        // canonical attribute, then compares with np.array_equal so any
        // future drift (wrong attribute lookup, typo in passthrough name,
        // etc.) trips the test.
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }
            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let numpy = py.import("numpy")?;
            let array_equal = numpy.getattr("array_equal")?;

            let x = numpy
                .getattr("array")?
                .call1((PyList::new(py, [0.5_f64, -0.5, 1.0])?,))?;
            let y = numpy
                .getattr("array")?
                .call1((PyList::new(py, [1.0_f64, 2.0, 3.0])?,))?;
            let xi = numpy
                .getattr("array")?
                .call1((PyList::new(py, [6_i64, 10, 15])?,))?;
            let yi = numpy
                .getattr("array")?
                .call1((PyList::new(py, [4_i64, 6, 10])?,))?;

            // Array-API trig aliases: one from each family.
            for (name, input) in [
                ("acos", &x),
                ("acosh", &y),
                ("asin", &x),
                ("asinh", &x),
                ("atan", &x),
                ("atanh", &x),
                ("tan", &x),
            ] {
                let ours = module.getattr(name)?.call1((input.clone(),))?;
                let theirs = numpy.getattr(name)?.call1((input.clone(),))?;
                let ok: bool = array_equal.call1((&ours, &theirs))?.extract()?;
                assert!(ok, "{name} passthrough diverged from numpy");
            }

            // Binary arithmetic / comparison families.
            for name in [
                "atan2",
                "bitwise_and",
                "bitwise_or",
                "bitwise_xor",
                "bitwise_left_shift",
                "bitwise_right_shift",
                "left_shift",
                "right_shift",
                "gcd",
                "lcm",
                "equal",
                "not_equal",
                "greater",
                "greater_equal",
                "less",
                "less_equal",
                "logical_and",
                "logical_or",
                "logical_xor",
                "fmax",
                "fmin",
                "maximum",
                "minimum",
                "float_power",
                "mod",
                "remainder",
            ] {
                let ours = module.getattr(name)?.call1((xi.clone(), yi.clone()))?;
                let theirs = numpy.getattr(name)?.call1((xi.clone(), yi.clone()))?;
                let ok: bool = array_equal.call1((&ours, &theirs))?.extract()?;
                assert!(ok, "{name} passthrough diverged from numpy");
            }

            // Unary: logical_not, bitwise_not, bitwise_invert, bitwise_count.
            for name in [
                "logical_not",
                "bitwise_not",
                "bitwise_invert",
                "bitwise_count",
            ] {
                let ours = module.getattr(name)?.call1((xi.clone(),))?;
                let theirs = numpy.getattr(name)?.call1((xi.clone(),))?;
                let ok: bool = array_equal.call1((&ours, &theirs))?.extract()?;
                assert!(ok, "{name} passthrough diverged from numpy");
            }

            // divmod returns a 2-tuple; compare each element.
            let ours_dm = module.getattr("divmod")?.call1((xi.clone(), yi.clone()))?;
            let theirs_dm = numpy.getattr("divmod")?.call1((xi.clone(), yi.clone()))?;
            let ours_q = ours_dm.get_item(0)?;
            let ours_r = ours_dm.get_item(1)?;
            let theirs_q = theirs_dm.get_item(0)?;
            let theirs_r = theirs_dm.get_item(1)?;
            assert!(
                array_equal.call1((&ours_q, &theirs_q))?.extract::<bool>()?,
                "divmod quotient diverged"
            );
            assert!(
                array_equal.call1((&ours_r, &theirs_r))?.extract::<bool>()?,
                "divmod remainder diverged"
            );

            // isnat on a datetime64 input.
            let dates = numpy.getattr("array")?.call(
                (PyList::new(py, ["NaT", "2026-04-23"])?,),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("dtype", "datetime64[D]")?;
                    kw
                }),
            )?;
            let ours_nat = module.getattr("isnat")?.call1((dates.clone(),))?;
            let theirs_nat = numpy.getattr("isnat")?.call1((dates,))?;
            assert!(
                array_equal
                    .call1((&ours_nat, &theirs_nat))?
                    .extract::<bool>()?,
                "isnat passthrough diverged"
            );

            // ptp reduction.
            let pt_in = numpy
                .getattr("array")?
                .call1((PyList::new(py, [1_i64, 5, 3, 8, 2])?,))?;
            let ours_ptp = module.getattr("ptp")?.call1((pt_in.clone(),))?;
            let theirs_ptp = numpy.getattr("ptp")?.call1((pt_in,))?;
            assert_eq!(
                ours_ptp.repr()?.extract::<String>()?,
                theirs_ptp.repr()?.extract::<String>()?,
                "ptp passthrough diverged"
            );

            // Matrix gufunc siblings: vecmat (M,) @ (M, N) -> (N,),
            // matvec (M, N) @ (N,) -> (M,).
            let mat = numpy.getattr("array")?.call1((PyList::new(
                py,
                [
                    PyList::new(py, [1.0_f64, 2.0])?,
                    PyList::new(py, [3.0, 4.0])?,
                ],
            )?,))?;
            let vec = numpy
                .getattr("array")?
                .call1((PyList::new(py, [1.0_f64, 2.0])?,))?;
            let ours_vm = module
                .getattr("vecmat")?
                .call1((vec.clone(), mat.clone()))?;
            let theirs_vm = numpy.getattr("vecmat")?.call1((vec.clone(), mat.clone()))?;
            assert!(
                array_equal
                    .call1((&ours_vm, &theirs_vm))?
                    .extract::<bool>()?,
                "vecmat passthrough diverged"
            );
            let ours_mv = module
                .getattr("matvec")?
                .call1((mat.clone(), vec.clone()))?;
            let theirs_mv = numpy.getattr("matvec")?.call1((mat, vec))?;
            assert!(
                array_equal
                    .call1((&ours_mv, &theirs_mv))?
                    .extract::<bool>()?,
                "matvec passthrough diverged"
            );

            Ok(())
        });
    }

    #[test]
    fn frompyfunc_live_callable_matches_numpy_single_output() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let functools = py.import("functools")?;
            let operator = py.import("operator")?;
            let callable = functools
                .getattr("partial")?
                .call1((operator.getattr("mul")?, "x"))?
                .unbind();
            let ufunc = PyFromPyFunc::new_checked(callable.clone_ref(py), 1, 1, None, py)?;

            let values = object_array(py, vec![1, 2, 3]);
            let args = PyTuple::new(py, [values.clone()])?;

            let actual = ufunc.call_bound(py, &args)?;
            let numpy = py.import("numpy")?;
            let expected_args = PyTuple::new(py, [values])?;
            let expected = numpy
                .getattr("frompyfunc")?
                .call1((callable.bind(py), 1, 1))?
                .call1(expected_args)?;

            assert_eq!(
                actual.bind(py).getattr("shape")?.extract::<Vec<usize>>()?,
                vec![3]
            );
            assert_eq!(
                repr_string(&actual.bind(py).call_method0("tolist")?),
                repr_string(&expected.call_method0("tolist")?)
            );
            Ok(())
        });
    }

    #[test]
    fn frompyfunc_live_callable_matches_numpy_multi_output() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let builtins = py.import("builtins")?;
            let callable = builtins.getattr("divmod")?.unbind();
            let ufunc = PyFromPyFunc::new_checked(callable.clone_ref(py), 2, 2, None, py)?;

            let lhs = object_array(py, vec![10, 11, 12]);
            let rhs = object_array(py, vec![3]);
            let args = PyTuple::new(py, [lhs.clone(), rhs.clone()])?;

            let actual = ufunc.call_bound(py, &args)?;
            let numpy = py.import("numpy")?;
            let expected_args = PyTuple::new(py, [lhs, rhs])?;
            let expected = numpy
                .getattr("frompyfunc")?
                .call1((callable.bind(py), 2, 2))?
                .call1(expected_args)?;

            let actual_tuple = actual.bind(py).cast::<PyTuple>()?;
            let expected_tuple = expected.cast::<PyTuple>()?;
            assert_eq!(actual_tuple.len()?, 2);
            assert_eq!(expected_tuple.len()?, 2);

            for (actual_item, expected_item) in
                actual_tuple.try_iter()?.zip(expected_tuple.try_iter()?)
            {
                let actual_item = actual_item?;
                let expected_item = expected_item?;
                assert_eq!(
                    actual_item.getattr("shape")?.extract::<Vec<usize>>()?,
                    vec![3]
                );
                assert_eq!(
                    repr_string(&actual_item.call_method0("tolist")?),
                    repr_string(&expected_item.call_method0("tolist")?)
                );
            }
            Ok(())
        });
    }

    #[test]
    fn frompyfunc_live_callable_matches_numpy_zero_output_side_effects() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let callable = py.get_type::<PyList>().getattr("reverse")?.unbind();
            let actual_values = object_array(py, vec![vec![1, 2, 3], vec![4, 5], vec![6, 7, 8, 9]]);
            let expected_values =
                object_array(py, vec![vec![1, 2, 3], vec![4, 5], vec![6, 7, 8, 9]]);
            let ufunc = PyFromPyFunc::new_checked(callable.clone_ref(py), 1, 0, None, py)?;

            let actual_args = PyTuple::new(py, [actual_values.clone()])?;
            let actual = ufunc.call_bound(py, &actual_args)?;

            let numpy = py.import("numpy")?;
            let expected_args = PyTuple::new(py, [expected_values.clone()])?;
            let expected = numpy
                .getattr("frompyfunc")?
                .call1((callable.bind(py), 1, 0))?
                .call1(expected_args)?;

            let actual_repr = repr_string(actual.bind(py));
            let expected_repr = repr_string(&expected);
            let actual_tuple = actual.bind(py).cast::<PyTuple>()?;
            let expected_tuple = expected.cast::<PyTuple>()?;
            assert_eq!(actual_tuple.len()?, 0);
            assert_eq!(expected_tuple.len()?, 0);
            assert_eq!(actual_repr, expected_repr);
            assert_eq!(
                repr_string(&actual_values.call_method0("tolist")?),
                repr_string(&expected_values.call_method0("tolist")?)
            );
            Ok(())
        });
    }

    #[test]
    fn frompyfunc_live_callable_matches_numpy_identity_and_reduce() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;

            let operator = py.import("operator")?;
            let numpy = py.import("numpy")?;
            let callable = operator.getattr("mul")?.unbind();
            let reduce_input = object_array(py, vec![vec![1_i64, 1_i64], vec![1_i64, 1_i64]]);
            let empty_input = object_array(py, Vec::<i64>::new());
            let list_input = vec![2_i64, 3_i64, 4_i64];

            let none_kwargs = PyDict::new(py);
            none_kwargs.set_item("identity", py.None())?;
            let one_kwargs = PyDict::new(py);
            one_kwargs.set_item("identity", 1_i64)?;
            let axis_kwargs = PyDict::new(py);
            axis_kwargs.set_item("axis", (0_i64, 1_i64))?;

            let actual_omitted = module
                .getattr("frompyfunc")?
                .call1((callable.bind(py), 2, 1))?;
            let expected_omitted = numpy
                .getattr("frompyfunc")?
                .call1((callable.bind(py), 2, 1))?;

            let actual_none = module
                .getattr("frompyfunc")?
                .call((callable.bind(py), 2, 1), Some(&none_kwargs))?;
            let expected_none = numpy
                .getattr("frompyfunc")?
                .call((callable.bind(py), 2, 1), Some(&none_kwargs))?;

            let actual_one = module
                .getattr("frompyfunc")?
                .call((callable.bind(py), 2, 1), Some(&one_kwargs))?;
            let expected_one = numpy
                .getattr("frompyfunc")?
                .call((callable.bind(py), 2, 1), Some(&one_kwargs))?;

            for (actual, expected) in [
                (&actual_omitted, &expected_omitted),
                (&actual_none, &expected_none),
                (&actual_one, &expected_one),
            ] {
                assert_eq!(
                    repr_string(&actual.getattr("identity")?),
                    repr_string(&expected.getattr("identity")?)
                );
            }

            for (actual, expected) in [
                (&actual_omitted, &expected_omitted),
                (&actual_none, &expected_none),
                (&actual_one, &expected_one),
            ] {
                assert_eq!(
                    reduce_outcome(py, actual, &object_array(py, list_input.clone()), None)?,
                    reduce_outcome(py, expected, &object_array(py, list_input.clone()), None)?,
                );
            }

            assert_eq!(
                reduce_outcome(py, &actual_omitted, &reduce_input, Some(&axis_kwargs))?,
                reduce_outcome(py, &expected_omitted, &reduce_input, Some(&axis_kwargs))?,
            );
            assert_eq!(
                reduce_outcome(py, &actual_none, &reduce_input, Some(&axis_kwargs))?,
                reduce_outcome(py, &expected_none, &reduce_input, Some(&axis_kwargs))?,
            );
            assert_eq!(
                reduce_outcome(py, &actual_one, &reduce_input, Some(&axis_kwargs))?,
                reduce_outcome(py, &expected_one, &reduce_input, Some(&axis_kwargs))?,
            );

            assert_eq!(
                reduce_outcome(py, &actual_omitted, &empty_input, None)?,
                reduce_outcome(py, &expected_omitted, &empty_input, None)?,
            );
            assert_eq!(
                reduce_outcome(py, &actual_none, &empty_input, None)?,
                reduce_outcome(py, &expected_none, &empty_input, None)?,
            );
            assert_eq!(
                reduce_outcome(py, &actual_one, &empty_input, None)?,
                reduce_outcome(py, &expected_one, &empty_input, None)?,
            );

            Ok(())
        });
    }

    #[test]
    fn frompyfunc_live_callable_matches_numpy_reduce_kwargs_and_out() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;

            let operator = py.import("operator")?;
            let numpy = py.import("numpy")?;
            let callable = operator.getattr("mul")?.unbind();
            let reduce_input = object_array(
                py,
                vec![vec![2_i64, 3_i64, 4_i64], vec![5_i64, 6_i64, 7_i64]],
            );

            let actual = module
                .getattr("frompyfunc")?
                .call1((callable.bind(py), 2, 1))?;
            let expected = numpy
                .getattr("frompyfunc")?
                .call1((callable.bind(py), 2, 1))?;

            let keepdims_kwargs = PyDict::new(py);
            keepdims_kwargs.set_item("axis", 1_i64)?;
            keepdims_kwargs.set_item("keepdims", true)?;
            assert_eq!(
                reduce_outcome(py, &actual, &reduce_input, Some(&keepdims_kwargs))?,
                reduce_outcome(py, &expected, &reduce_input, Some(&keepdims_kwargs))?,
            );

            let where_mask = numeric_array(py, vec![true, false, true], "bool");
            let where_kwargs = PyDict::new(py);
            where_kwargs.set_item("axis", 0_i64)?;
            where_kwargs.set_item("where", where_mask.clone())?;
            where_kwargs.set_item("initial", 11_i64)?;
            assert_eq!(
                reduce_outcome(py, &actual, &reduce_input, Some(&where_kwargs))?,
                reduce_outcome(py, &expected, &reduce_input, Some(&where_kwargs))?,
            );

            let where_error_kwargs = PyDict::new(py);
            where_error_kwargs.set_item("axis", 0_i64)?;
            where_error_kwargs.set_item("where", where_mask)?;
            assert_eq!(
                reduce_outcome(py, &actual, &reduce_input, Some(&where_error_kwargs))?,
                reduce_outcome(py, &expected, &reduce_input, Some(&where_error_kwargs))?,
            );

            let actual_out = object_array(py, vec![0_i64, 0_i64, 0_i64]);
            let expected_out = object_array(py, vec![0_i64, 0_i64, 0_i64]);
            let actual_out_kwargs = PyDict::new(py);
            let expected_out_kwargs = PyDict::new(py);
            actual_out_kwargs.set_item("axis", 0_i64)?;
            expected_out_kwargs.set_item("axis", 0_i64)?;
            actual_out_kwargs.set_item("out", PyTuple::new(py, [actual_out.clone()])?)?;
            expected_out_kwargs.set_item("out", PyTuple::new(py, [expected_out.clone()])?)?;

            let actual_result =
                actual.call_method("reduce", (reduce_input.clone(),), Some(&actual_out_kwargs))?;
            let expected_result =
                expected.call_method("reduce", (reduce_input,), Some(&expected_out_kwargs))?;

            assert_array_matches_numpy(&actual_result, &expected_result)?;
            assert_array_matches_numpy(&actual_out, &expected_out)?;
            Ok(())
        });
    }

