    #[test]
    fn frexp_matches_numpy_basic() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let x = numeric_array(py, vec![0.0, 1.0, -2.5, 8.0], "float64");
            let actual = frexp(py, x.clone().unbind())?;

            let numpy = py.import("numpy")?;
            let expected = numpy.getattr("frexp")?.call1((x,))?;

            let actual_tuple = actual.bind(py).cast::<PyTuple>()?;
            let expected_tuple = expected.cast::<PyTuple>()?;
            assert_eq!(actual_tuple.len()?, 2);
            assert_eq!(expected_tuple.len()?, 2);

            let actual_mantissa = actual_tuple.get_item(0)?;
            let actual_exponent = actual_tuple.get_item(1)?;
            let expected_mantissa = expected_tuple.get_item(0)?;
            let expected_exponent = expected_tuple.get_item(1)?;

            assert_eq!(
                actual_mantissa
                    .call_method0("tolist")?
                    .extract::<Vec<f64>>()?,
                expected_mantissa
                    .call_method0("tolist")?
                    .extract::<Vec<f64>>()?
            );
            assert_eq!(
                actual_exponent
                    .getattr("dtype")?
                    .str()?
                    .extract::<String>()?,
                expected_exponent
                    .getattr("dtype")?
                    .str()?
                    .extract::<String>()?
            );
            assert_eq!(
                actual_exponent
                    .call_method0("tolist")?
                    .extract::<Vec<i32>>()?,
                expected_exponent
                    .call_method0("tolist")?
                    .extract::<Vec<i32>>()?
            );
            Ok(())
        });
    }

