    #[test]
    fn nanmin_matches_numpy_across_axis_keepdims_and_all_nan() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let nanmin_fn = module.getattr("nanmin")?;
            let numpy = py.import("numpy")?;
            let numpy_nanmin = numpy.getattr("nanmin")?;
            let isclose = numpy.getattr("isclose")?;
            let allclose = numpy.getattr("allclose")?;
            let isnan_fn = numpy.getattr("isnan")?;
            let warnings = py.import("warnings")?;

            // 1-D no NaN matches min.
            let clean = numpy
                .getattr("array")?
                .call1((vec![3.0_f64, 1.0, 4.0, 1.0, 5.0, 9.0, 2.0],))?;
            let ours_c = nanmin_fn.call1((clean.clone(),))?;
            let theirs_c = numpy_nanmin.call1((clean.clone(),))?;
            let ok_c: bool = isclose.call1((&ours_c, &theirs_c))?.extract()?;
            assert!(ok_c, "nanmin no-NaN 1-D mismatch");

            // 1-D with NaN ignored.
            let with_nan =
                numpy
                    .getattr("array")?
                    .call1((vec![4.0_f64, 2.0, f64::NAN, 1.0, 3.0],))?;
            let ours_n = nanmin_fn.call1((with_nan.clone(),))?;
            let theirs_n = numpy_nanmin.call1((with_nan.clone(),))?;
            let ok_n: bool = isclose.call1((&ours_n, &theirs_n))?.extract()?;
            assert!(ok_n, "nanmin 1-D with NaN mismatch");

            // 2-D mixed NaN, axis=0 and axis=1.
            let two_d = numpy.getattr("array")?.call1((vec![
                vec![1.0_f64, f64::NAN, 3.0],
                vec![4.0, 2.0, f64::NAN],
                vec![f64::NAN, 8.0, 9.0],
            ],))?;
            for axis in [0_i64, 1] {
                let ours = nanmin_fn.call(
                    (two_d.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("axis", axis)?;
                        kw
                    }),
                )?;
                let theirs = numpy_nanmin.call(
                    (two_d.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("axis", axis)?;
                        kw
                    }),
                )?;
                let ok_ax: bool = allclose.call1((&ours, &theirs))?.extract()?;
                assert!(ok_ax, "nanmin 2-D axis={} mismatch", axis);
            }

            // Fully-NaN slice -> NaN (warnings silenced on both sides).
            let all_nan = numpy
                .getattr("array")?
                .call1((vec![f64::NAN, f64::NAN, f64::NAN],))?;
            let catch_warnings = warnings.getattr("catch_warnings")?;
            let suppressed_ours = {
                let ctx = catch_warnings.call0()?;
                ctx.call_method0("__enter__")?;
                warnings.call_method1("simplefilter", ("ignore",))?;
                let result = nanmin_fn.call1((all_nan.clone(),))?;
                ctx.call_method1("__exit__", (py.None(), py.None(), py.None()))?;
                result
            };
            let suppressed_theirs = {
                let ctx = catch_warnings.call0()?;
                ctx.call_method0("__enter__")?;
                warnings.call_method1("simplefilter", ("ignore",))?;
                let result = numpy_nanmin.call1((all_nan.clone(),))?;
                ctx.call_method1("__exit__", (py.None(), py.None(), py.None()))?;
                result
            };
            let ours_is_nan: bool = isnan_fn.call1((&suppressed_ours,))?.extract()?;
            let theirs_is_nan: bool = isnan_fn.call1((&suppressed_theirs,))?.extract()?;
            assert!(ours_is_nan && theirs_is_nan, "fully-NaN nanmin must be NaN");

            // Integer input matches plain min.
            let ints = numpy
                .getattr("array")?
                .call1((vec![3_i64, 1, 4, 1, 5, 9, 2, 6],))?;
            let ours_i = nanmin_fn.call1((ints.clone(),))?;
            let theirs_i = numpy_nanmin.call1((ints.clone(),))?;
            let ours_i_val: i64 = ours_i.extract()?;
            let theirs_i_val: i64 = theirs_i.extract()?;
            assert_eq!(ours_i_val, theirs_i_val, "nanmin integer mismatch");

            // keepdims=True preserves length-1 reduction axis.
            let ours_kd = nanmin_fn.call(
                (two_d.clone(),),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("axis", 1_i64)?;
                    kw.set_item("keepdims", true)?;
                    kw
                }),
            )?;
            let theirs_kd = numpy_nanmin.call(
                (two_d.clone(),),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("axis", 1_i64)?;
                    kw.set_item("keepdims", true)?;
                    kw
                }),
            )?;
            let ok_kd: bool = allclose.call1((&ours_kd, &theirs_kd))?.extract()?;
            assert!(ok_kd, "nanmin keepdims=True mismatch");
            let ours_shape = ours_kd.getattr("shape")?.str()?.to_string();
            let theirs_shape = theirs_kd.getattr("shape")?.str()?.to_string();
            assert_eq!(
                ours_shape, theirs_shape,
                "nanmin keepdims shape must match numpy",
            );

            Ok(())
        });
    }

    #[test]
    fn nanstd_matches_numpy_across_axis_ddof_keepdims_and_dtype() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let nanstd_fn = module.getattr("nanstd")?;
            let numpy = py.import("numpy")?;
            let numpy_nanstd = numpy.getattr("nanstd")?;
            let isclose = numpy.getattr("isclose")?;

            // 1-D no NaN matches np.std.
            let clean = numpy
                .getattr("array")?
                .call1((vec![1.0_f64, 2.0, 3.0, 4.0, 5.0],))?;
            let ours_clean = nanstd_fn.call1((clean.clone(),))?;
            let theirs_clean = numpy_nanstd.call1((clean.clone(),))?;
            let ok_clean: bool = isclose.call1((&ours_clean, &theirs_clean))?.extract()?;
            assert!(ok_clean, "nanstd clean 1-D mismatch");

            // 1-D with NaN ignores NaN values.
            let with_nan =
                numpy
                    .getattr("array")?
                    .call1((vec![1.0_f64, 2.0, f64::NAN, 4.0, 8.0],))?;
            let ours_nan = nanstd_fn.call1((with_nan.clone(),))?;
            let theirs_nan = numpy_nanstd.call1((with_nan.clone(),))?;
            let ok_nan: bool = isclose.call1((&ours_nan, &theirs_nan))?.extract()?;
            assert!(ok_nan, "nanstd NaN-filtering 1-D mismatch");

            // ddof=1 switches to sample standard deviation.
            let ours_ddof = nanstd_fn.call(
                (with_nan.clone(),),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("ddof", 1_i64)?;
                    kw
                }),
            )?;
            let theirs_ddof = numpy_nanstd.call(
                (with_nan.clone(),),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("ddof", 1_i64)?;
                    kw
                }),
            )?;
            let ok_ddof: bool = isclose.call1((&ours_ddof, &theirs_ddof))?.extract()?;
            assert!(ok_ddof, "nanstd ddof=1 mismatch");

            // 2-D mixed NaN with axis reductions.
            let two_d = numpy.getattr("array")?.call1((vec![
                vec![1.0_f64, f64::NAN, 3.0],
                vec![4.0, 5.0, f64::NAN],
                vec![7.0, 8.0, 9.0],
            ],))?;
            for axis in [0_i64, 1] {
                let ours = nanstd_fn.call(
                    (two_d.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("axis", axis)?;
                        kw
                    }),
                )?;
                let theirs = numpy_nanstd.call(
                    (two_d.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("axis", axis)?;
                        kw
                    }),
                )?;
                assert_array_matches_numpy(&ours, &theirs)?;
            }

            // keepdims=True preserves reduced axes.
            let ours_kd = nanstd_fn.call(
                (two_d.clone(),),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("axis", 1_i64)?;
                    kw.set_item("keepdims", true)?;
                    kw
                }),
            )?;
            let theirs_kd = numpy_nanstd.call(
                (two_d.clone(),),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("axis", 1_i64)?;
                    kw.set_item("keepdims", true)?;
                    kw
                }),
            )?;
            assert_array_matches_numpy(&ours_kd, &theirs_kd)?;
            let ours_shape = ours_kd.getattr("shape")?.str()?.to_string();
            let theirs_shape = theirs_kd.getattr("shape")?.str()?.to_string();
            assert_eq!(
                ours_shape, theirs_shape,
                "nanstd keepdims shape must match numpy",
            );

            // Integer input promotes to the same floating dtype as numpy.
            let ints = numpy.getattr("array")?.call1((vec![2_i64, 4, 6, 8],))?;
            let ours_int = nanstd_fn.call1((ints.clone(),))?;
            let theirs_int = numpy_nanstd.call1((ints.clone(),))?;
            let ok_int: bool = isclose.call1((&ours_int, &theirs_int))?.extract()?;
            assert!(ok_int, "nanstd integer input mismatch");
            let ours_dtype = ours_int.getattr("dtype")?.str()?.to_string();
            let theirs_dtype = theirs_int.getattr("dtype")?.str()?.to_string();
            assert_eq!(
                ours_dtype, theirs_dtype,
                "nanstd integer result dtype must match numpy",
            );

            // Identical non-NaN inputs return zero.
            let identical = numpy
                .getattr("array")?
                .call1((vec![5.0_f64, 5.0, 5.0, 5.0],))?;
            let ours_zero = nanstd_fn.call1((identical.clone(),))?;
            let theirs_zero = numpy_nanstd.call1((identical.clone(),))?;
            let ok_zero: bool = isclose.call1((&ours_zero, &theirs_zero))?.extract()?;
            assert!(ok_zero, "nanstd identical-input mismatch");
            let ours_zero_ok: bool = isclose.call1((&ours_zero, 0.0_f64))?.extract()?;
            assert!(ours_zero_ok, "nanstd identical-input must return 0");

            Ok(())
        });
    }

