    #[test]
    fn lexsort_matches_numpy_across_keys_axis_and_ties() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let lexsort_fn = module.getattr("lexsort")?;
            let numpy = py.import("numpy")?;
            let numpy_lexsort = numpy.getattr("lexsort")?;

            // Tuple of two 1-D keys: secondary first, primary last.
            let secondary = numpy.getattr("array")?.call1((vec![1_i64, 2, 1, 2, 1],))?;
            let primary = numpy.getattr("array")?.call1((vec![3_i64, 1, 4, 1, 5],))?;
            let keys_tuple = PyTuple::new(py, [secondary.clone(), primary.clone()])?;
            let ours = lexsort_fn.call1((keys_tuple.clone(),))?;
            let theirs = numpy_lexsort.call1((keys_tuple.clone(),))?;
            assert_array_matches_numpy(&ours, &theirs)?;

            // 2-D keys array: each row is a key (last row is primary).
            let two_d_keys = numpy
                .getattr("array")?
                .call1((vec![vec![5_i64, 4, 3, 2, 1], vec![1_i64, 1, 1, 1, 1]],))?;
            assert_array_matches_numpy(
                &lexsort_fn.call1((two_d_keys.clone(),))?,
                &numpy_lexsort.call1((two_d_keys.clone(),))?,
            )?;

            // Ties broken by the secondary key: when primary values
            // tie at indices, the secondary key determines order.
            let primary_with_ties = numpy.getattr("array")?.call1((vec![1_i64, 2, 2, 1, 3],))?;
            let secondary_breaker = numpy.getattr("array")?.call1((vec![5_i64, 4, 3, 6, 0],))?;
            let tie_keys =
                PyTuple::new(py, [secondary_breaker.clone(), primary_with_ties.clone()])?;
            let ours_ties = lexsort_fn.call1((tie_keys.clone(),))?;
            let theirs_ties = numpy_lexsort.call1((tie_keys.clone(),))?;
            assert_array_matches_numpy(&ours_ties, &theirs_ties)?;
            // Verify the resulting permutation actually sorts the keys.
            let primary_sorted = primary_with_ties.get_item(theirs_ties.clone())?;
            let expected_sorted = numpy.getattr("array")?.call1((vec![1_i64, 1, 2, 2, 3],))?;
            assert_array_matches_numpy(&primary_sorted, &expected_sorted)?;

            // Single-key input via length-1 tuple matches numpy.
            let single_key = numpy
                .getattr("array")?
                .call1((vec![3_i64, 1, 4, 1, 5, 9, 2, 6],))?;
            let single_tuple = PyTuple::new(py, [single_key.clone()])?;
            assert_array_matches_numpy(
                &lexsort_fn.call1((single_tuple.clone(),))?,
                &numpy_lexsort.call1((single_tuple.clone(),))?,
            )?;

            // axis=0 on 2-D keys (each column treated as an entry along axis 0).
            let axis_keys = numpy
                .getattr("array")?
                .call1((vec![vec![3_i64, 1, 2], vec![5_i64, 5, 5]],))?;
            let kwargs_axis0 = PyDict::new(py);
            kwargs_axis0.set_item("axis", 0_i64)?;
            assert_array_matches_numpy(
                &lexsort_fn.call((axis_keys.clone(),), Some(&kwargs_axis0))?,
                &numpy_lexsort.call((axis_keys.clone(),), Some(&kwargs_axis0))?,
            )?;

            // String keys.
            let string_secondary = numpy
                .getattr("array")?
                .call1((vec!["b", "a", "c", "b", "a"],))?;
            let string_primary = numpy
                .getattr("array")?
                .call1((vec!["one", "one", "two", "two", "three"],))?;
            let string_keys = PyTuple::new(py, [string_secondary.clone(), string_primary.clone()])?;
            assert_array_matches_numpy(
                &lexsort_fn.call1((string_keys.clone(),))?,
                &numpy_lexsort.call1((string_keys.clone(),))?,
            )?;

            Ok(())
        });
    }

    #[test]
    fn rfftn_matches_numpy_across_nd_shape_axes_and_norm() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let rfftn_fn = module.getattr("rfftn")?;
            let irfftn_fn = module.getattr("irfftn")?;
            let numpy = py.import("numpy")?;
            let numpy_rfftn = numpy.getattr("fft")?.getattr("rfftn")?;
            let numpy_irfftn = numpy.getattr("fft")?.getattr("irfftn")?;
            let allclose = numpy.getattr("allclose")?;

            // 3-D real input, default all-axes transform.
            let three_d = numpy.getattr("array")?.call(
                (vec![
                    vec![vec![1.0_f64, 2.0, 3.0, 4.0], vec![5.0, 6.0, 7.0, 8.0]],
                    vec![vec![9.0, 10.0, 11.0, 12.0], vec![13.0, 14.0, 15.0, 16.0]],
                ],),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("dtype", numpy.getattr("float64")?)?;
                    kw
                }),
            )?;
            let ours = rfftn_fn.call1((three_d.clone(),))?;
            let theirs = numpy_rfftn.call1((three_d.clone(),))?;
            let ok: bool = allclose.call1((&ours, &theirs))?.extract()?;
            assert!(ok, "rfftn 3-D default mismatch");

            // Last transformed axis must be n//2+1 along axis -1.
            // Input shape (2, 2, 4) → output (2, 2, 3).
            let out_shape: (usize, usize, usize) = ours.getattr("shape")?.extract()?;
            assert_eq!(out_shape, (2, 2, 3), "rfftn output shape must match n//2+1");

            // Explicit s=(4, 4, 8) zero-pads each transform axis.
            let s_tuple = PyTuple::new(py, [4_usize, 4, 8])?;
            let ours_s = rfftn_fn.call(
                (three_d.clone(),),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("s", &s_tuple)?;
                    kw
                }),
            )?;
            let theirs_s = numpy_rfftn.call(
                (three_d.clone(),),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("s", &s_tuple)?;
                    kw
                }),
            )?;
            let ok_s: bool = allclose.call1((&ours_s, &theirs_s))?.extract()?;
            assert!(ok_s, "rfftn s=(4,4,8) mismatch");

            // Subset axes=(-1, -2) reverses the rfftn axis order.
            let axes_subset = PyTuple::new(py, [-1_i64, -2])?;
            let ours_axes = rfftn_fn.call(
                (three_d.clone(),),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("axes", &axes_subset)?;
                    kw
                }),
            )?;
            let theirs_axes = numpy_rfftn.call(
                (three_d.clone(),),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("axes", &axes_subset)?;
                    kw
                }),
            )?;
            let ok_axes: bool = allclose.call1((&ours_axes, &theirs_axes))?.extract()?;
            assert!(ok_axes, "rfftn axes=(-1,-2) mismatch");

            // norm='ortho' and norm='forward'.
            for norm_tag in ["ortho", "forward"] {
                let ours_n = rfftn_fn.call(
                    (three_d.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("norm", norm_tag)?;
                        kw
                    }),
                )?;
                let theirs_n = numpy_rfftn.call(
                    (three_d.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("norm", norm_tag)?;
                        kw
                    }),
                )?;
                let ok_n: bool = allclose.call1((&ours_n, &theirs_n))?.extract()?;
                assert!(ok_n, "rfftn norm={} mismatch", norm_tag);
            }

            // Output dtype is complex.
            let ours_dtype = ours.getattr("dtype")?.str()?.to_string();
            let theirs_dtype = theirs.getattr("dtype")?.str()?.to_string();
            assert_eq!(
                ours_dtype, theirs_dtype,
                "rfftn output dtype must match numpy (complex128)",
            );

            // Round-trip: irfftn(rfftn(x)) ≈ x for even-shape input.
            let s_for_inv = PyTuple::new(py, [2_usize, 2, 4])?;
            let round_trip = irfftn_fn.call(
                (rfftn_fn.call1((three_d.clone(),))?,),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("s", &s_for_inv)?;
                    kw
                }),
            )?;
            let ok_rt: bool = allclose.call1((&round_trip, &three_d))?.extract()?;
            assert!(ok_rt, "irfftn(rfftn(x)) must round-trip for even-shape x");

            let ours_inv = irfftn_fn.call(
                (ours.clone(),),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("s", &s_for_inv)?;
                    kw
                }),
            )?;
            let theirs_inv = numpy_irfftn.call(
                (theirs.clone(),),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("s", &s_for_inv)?;
                    kw
                }),
            )?;
            assert_array_matches_numpy(&ours_inv, &theirs_inv)?;

            let axes_inv = PyTuple::new(py, [-1_i64, -2])?;
            let shape_inv = PyTuple::new(py, [4_usize, 4])?;
            let ours_axes_inv = irfftn_fn.call(
                (ours_axes.clone(),),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("s", &shape_inv)?;
                    kw.set_item("axes", &axes_inv)?;
                    kw.set_item("norm", "ortho")?;
                    kw
                }),
            )?;
            let theirs_axes_inv = numpy_irfftn.call(
                (theirs_axes.clone(),),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("s", &shape_inv)?;
                    kw.set_item("axes", &axes_inv)?;
                    kw.set_item("norm", "ortho")?;
                    kw
                }),
            )?;
            assert_array_matches_numpy(&ours_axes_inv, &theirs_axes_inv)?;

            let all_axes = PyTuple::new(py, [0_i64, 1, 2])?;
            let inv_out_expected = numpy_irfftn.call(
                (theirs.clone(),),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("s", &s_for_inv)?;
                    kw.set_item("axes", &all_axes)?;
                    kw
                }),
            )?;
            let inv_out_buf = numpy
                .getattr("empty_like")?
                .call1((inv_out_expected.clone(),))?;
            let expected_inv_out_buf = numpy
                .getattr("empty_like")?
                .call1((inv_out_expected.clone(),))?;
            let ours_out = irfftn_fn.call(
                (ours.clone(),),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("s", &s_for_inv)?;
                    kw.set_item("axes", &all_axes)?;
                    kw.set_item("out", inv_out_buf.clone())?;
                    kw
                }),
            )?;
            let theirs_out = numpy_irfftn.call(
                (theirs.clone(),),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("s", &s_for_inv)?;
                    kw.set_item("axes", &all_axes)?;
                    kw.set_item("out", expected_inv_out_buf.clone())?;
                    kw
                }),
            )?;
            assert_array_matches_numpy(&ours_out, &theirs_out)?;
            assert_array_matches_numpy(&inv_out_buf, &expected_inv_out_buf)?;

            let mismatched_shape_axes = PyDict::new(py);
            mismatched_shape_axes.set_item("s", PyTuple::new(py, [2_usize, 2])?)?;
            mismatched_shape_axes.set_item("axes", PyTuple::new(py, [0_i64])?)?;
            let ir_args = PyTuple::new(py, [ours.clone()])?;
            assert_eq!(
                call_outcome(py, &irfftn_fn, &ir_args, Some(&mismatched_shape_axes),)?,
                call_outcome(py, &numpy_irfftn, &ir_args, Some(&mismatched_shape_axes),)?,
                "irfftn mismatched s/axes error surface diverged"
            );

            Ok(())
        });
    }

    #[test]
    fn flip_matches_numpy_across_axis_dims_and_dtype() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let flip_fn = module.getattr("flip")?;
            let numpy = py.import("numpy")?;
            let numpy_flip = numpy.getattr("flip")?;

            // 1-D reverse.
            let one_d = numpy.getattr("array")?.call1((vec![1_i64, 2, 3, 4, 5],))?;
            assert_array_matches_numpy(
                &flip_fn.call1((one_d.clone(),))?,
                &numpy_flip.call1((one_d.clone(),))?,
            )?;

            // 2-D axis=0 (row reversal) and axis=1 (column reversal).
            let two_d = numpy.getattr("array")?.call1((vec![
                vec![1_i64, 2, 3],
                vec![4, 5, 6],
                vec![7, 8, 9],
            ],))?;
            for axis in [0_i64, 1] {
                assert_array_matches_numpy(
                    &flip_fn.call(
                        (two_d.clone(),),
                        Some(&{
                            let kw = PyDict::new(py);
                            kw.set_item("axis", axis)?;
                            kw
                        }),
                    )?,
                    &numpy_flip.call(
                        (two_d.clone(),),
                        Some(&{
                            let kw = PyDict::new(py);
                            kw.set_item("axis", axis)?;
                            kw
                        }),
                    )?,
                )?;
            }

            // axis=None reverses all dimensions.
            assert_array_matches_numpy(
                &flip_fn.call1((two_d.clone(),))?,
                &numpy_flip.call1((two_d.clone(),))?,
            )?;

            // axis tuple selects a subset of axes.
            let axis_tuple = PyTuple::new(py, [0_i64, 1])?;
            assert_array_matches_numpy(
                &flip_fn.call(
                    (two_d.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("axis", &axis_tuple)?;
                        kw
                    }),
                )?,
                &numpy_flip.call(
                    (two_d.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("axis", &axis_tuple)?;
                        kw
                    }),
                )?,
            )?;

            // 3-D mixed-axis flip.
            let three_d = numpy.getattr("array")?.call1((vec![
                vec![vec![1_i64, 2], vec![3, 4]],
                vec![vec![5, 6], vec![7, 8]],
                vec![vec![9, 10], vec![11, 12]],
            ],))?;
            for axis in [0_i64, 1, 2, -1] {
                assert_array_matches_numpy(
                    &flip_fn.call(
                        (three_d.clone(),),
                        Some(&{
                            let kw = PyDict::new(py);
                            kw.set_item("axis", axis)?;
                            kw
                        }),
                    )?,
                    &numpy_flip.call(
                        (three_d.clone(),),
                        Some(&{
                            let kw = PyDict::new(py);
                            kw.set_item("axis", axis)?;
                            kw
                        }),
                    )?,
                )?;
            }

            // Float dtype preserved.
            let floats = numpy.getattr("array")?.call(
                (vec![1.5_f64, 2.5, 3.5, 4.5],),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("dtype", numpy.getattr("float64")?)?;
                    kw
                }),
            )?;
            let ours_f = flip_fn.call1((floats.clone(),))?;
            let theirs_f = numpy_flip.call1((floats.clone(),))?;
            assert_array_matches_numpy(&ours_f, &theirs_f)?;
            let ours_dtype = ours_f.getattr("dtype")?.str()?.to_string();
            let theirs_dtype = theirs_f.getattr("dtype")?.str()?.to_string();
            assert_eq!(ours_dtype, theirs_dtype, "flip dtype must match numpy");

            Ok(())
        });
    }

    #[test]
    fn quantile_matches_numpy_across_q_axis_method_and_dtype() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let quantile_fn = module.getattr("quantile")?;
            let numpy = py.import("numpy")?;
            let numpy_quantile = numpy.getattr("quantile")?;
            let isclose = numpy.getattr("isclose")?;
            let allclose = numpy.getattr("allclose")?;

            // Scalar q on 1-D: q=0.5 (median).
            let one_d = numpy
                .getattr("array")?
                .call1((vec![3.0_f64, 1.0, 4.0, 1.0, 5.0, 9.0, 2.0, 6.0],))?;
            let ours = quantile_fn.call1((one_d.clone(), 0.5_f64))?;
            let theirs = numpy_quantile.call1((one_d.clone(), 0.5_f64))?;
            let ok: bool = isclose.call1((&ours, &theirs))?.extract()?;
            assert!(ok, "quantile q=0.5 1-D mismatch");

            // Vector q (quartiles in [0, 1]).
            let qs = numpy
                .getattr("array")?
                .call1((vec![0.25_f64, 0.5, 0.75],))?;
            let ours_qs = quantile_fn.call1((one_d.clone(), qs.clone()))?;
            let theirs_qs = numpy_quantile.call1((one_d.clone(), qs.clone()))?;
            let ok_qs: bool = allclose.call1((&ours_qs, &theirs_qs))?.extract()?;
            assert!(ok_qs, "quantile vector q mismatch");

            // 2-D axis=0 and axis=1.
            let two_d = numpy.getattr("array")?.call1((vec![
                vec![1.0_f64, 5.0, 3.0, 7.0],
                vec![4.0, 2.0, 6.0, 8.0],
                vec![7.0, 8.0, 9.0, 1.0],
            ],))?;
            for axis in [0_i64, 1] {
                let ours_ax = quantile_fn.call(
                    (two_d.clone(), 0.5_f64),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("axis", axis)?;
                        kw
                    }),
                )?;
                let theirs_ax = numpy_quantile.call(
                    (two_d.clone(), 0.5_f64),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("axis", axis)?;
                        kw
                    }),
                )?;
                let ok_ax: bool = allclose.call1((&ours_ax, &theirs_ax))?.extract()?;
                assert!(ok_ax, "quantile 2-D axis={} mismatch", axis);
            }

            // Each documented method at q=0.5.
            for method in ["linear", "lower", "higher", "nearest", "midpoint"] {
                let ours_m = quantile_fn.call(
                    (one_d.clone(), 0.5_f64),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("method", method)?;
                        kw
                    }),
                )?;
                let theirs_m = numpy_quantile.call(
                    (one_d.clone(), 0.5_f64),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("method", method)?;
                        kw
                    }),
                )?;
                let ok_m: bool = isclose.call1((&ours_m, &theirs_m))?.extract()?;
                assert!(ok_m, "quantile method={} mismatch", method);
            }

            // keepdims=True preserves length-1 reduction axis.
            let ours_kd = quantile_fn.call(
                (two_d.clone(), 0.5_f64),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("axis", 1_i64)?;
                    kw.set_item("keepdims", true)?;
                    kw
                }),
            )?;
            let theirs_kd = numpy_quantile.call(
                (two_d.clone(), 0.5_f64),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("axis", 1_i64)?;
                    kw.set_item("keepdims", true)?;
                    kw
                }),
            )?;
            let ok_kd: bool = allclose.call1((&ours_kd, &theirs_kd))?.extract()?;
            assert!(ok_kd, "quantile keepdims=True mismatch");
            let ours_shape = ours_kd.getattr("shape")?.str()?.to_string();
            let theirs_shape = theirs_kd.getattr("shape")?.str()?.to_string();
            assert_eq!(
                ours_shape, theirs_shape,
                "quantile keepdims shape must match numpy",
            );

            // Integer input dtype promoted to float.
            let ints = numpy
                .getattr("array")?
                .call1((vec![1_i64, 2, 3, 4, 5, 6, 7, 8, 9, 10],))?;
            let ours_i = quantile_fn.call1((ints.clone(), 0.5_f64))?;
            let theirs_i = numpy_quantile.call1((ints.clone(), 0.5_f64))?;
            let ok_i: bool = isclose.call1((&ours_i, &theirs_i))?.extract()?;
            assert!(ok_i, "quantile integer mismatch");
            let ours_dtype = ours_i.getattr("dtype")?.str()?.to_string();
            let theirs_dtype = theirs_i.getattr("dtype")?.str()?.to_string();
            assert_eq!(
                ours_dtype, theirs_dtype,
                "quantile integer must produce numpy's dtype",
            );

            // q=0 (min) and q=1 (max) edges.
            let ours_min = quantile_fn.call1((one_d.clone(), 0.0_f64))?;
            let theirs_min = numpy_quantile.call1((one_d.clone(), 0.0_f64))?;
            let ok_min: bool = isclose.call1((&ours_min, &theirs_min))?.extract()?;
            assert!(ok_min, "quantile q=0 (min) mismatch");
            let ours_max = quantile_fn.call1((one_d.clone(), 1.0_f64))?;
            let theirs_max = numpy_quantile.call1((one_d.clone(), 1.0_f64))?;
            let ok_max: bool = isclose.call1((&ours_max, &theirs_max))?.extract()?;
            assert!(ok_max, "quantile q=1 (max) mismatch");

            // q=0.5 must equal np.percentile(a, 50): cross-check semantic
            // equivalence between quantile and percentile.
            let percentile_fn_module = module.getattr("percentile")?;
            let q_via_quant = quantile_fn.call1((one_d.clone(), 0.5_f64))?;
            let q_via_pct = percentile_fn_module.call1((one_d.clone(), 50.0_f64))?;
            let ok_cross: bool = isclose.call1((&q_via_quant, &q_via_pct))?.extract()?;
            assert!(ok_cross, "quantile(0.5) must equal percentile(50)");

            Ok(())
        });
    }

    #[test]
    fn flipud_matches_numpy_across_1d_2d_3d_and_dtype() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let flipud_fn = module.getattr("flipud")?;
            let numpy = py.import("numpy")?;
            let numpy_flipud = numpy.getattr("flipud")?;

            // 1-D reverse (matches axis=0 flip).
            let one_d = numpy.getattr("array")?.call1((vec![1_i64, 2, 3, 4, 5],))?;
            assert_array_matches_numpy(
                &flipud_fn.call1((one_d.clone(),))?,
                &numpy_flipud.call1((one_d.clone(),))?,
            )?;

            // 2-D row reversal.
            let two_d = numpy.getattr("array")?.call1((vec![
                vec![1_i64, 2, 3],
                vec![4, 5, 6],
                vec![7, 8, 9],
            ],))?;
            assert_array_matches_numpy(
                &flipud_fn.call1((two_d.clone(),))?,
                &numpy_flipud.call1((two_d.clone(),))?,
            )?;

            // 3-D leaves non-leading axes intact.
            let three_d = numpy.getattr("array")?.call1((vec![
                vec![vec![1_i64, 2], vec![3, 4]],
                vec![vec![5, 6], vec![7, 8]],
                vec![vec![9, 10], vec![11, 12]],
            ],))?;
            assert_array_matches_numpy(
                &flipud_fn.call1((three_d.clone(),))?,
                &numpy_flipud.call1((three_d.clone(),))?,
            )?;

            // Float dtype preservation.
            let floats = numpy.getattr("array")?.call(
                (vec![1.5_f64, 2.5, 3.5, 4.5],),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("dtype", numpy.getattr("float64")?)?;
                    kw
                }),
            )?;
            let ours_f = flipud_fn.call1((floats.clone(),))?;
            let theirs_f = numpy_flipud.call1((floats.clone(),))?;
            assert_array_matches_numpy(&ours_f, &theirs_f)?;
            let ours_dtype = ours_f.getattr("dtype")?.str()?.to_string();
            let theirs_dtype = theirs_f.getattr("dtype")?.str()?.to_string();
            assert_eq!(ours_dtype, theirs_dtype, "flipud dtype must match numpy");

            // 0-D input must raise the same error in both implementations.
            let scalar_zero_d = numpy.getattr("array")?.call1((42_i64,))?;
            let ours_err = flipud_fn.call1((scalar_zero_d.clone(),)).err();
            let theirs_err = numpy_flipud.call1((scalar_zero_d.clone(),)).err();
            assert_eq!(
                ours_err.is_some(),
                theirs_err.is_some(),
                "flipud 0-D must raise iff numpy does",
            );

            // Cross-check: flipud(x) ≡ flip(x, axis=0).
            let flip_fn = module.getattr("flip")?;
            let via_flip = flip_fn.call(
                (two_d.clone(),),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("axis", 0_i64)?;
                    kw
                }),
            )?;
            assert_array_matches_numpy(&flipud_fn.call1((two_d.clone(),))?, &via_flip)?;

            Ok(())
        });
    }

    #[test]
    fn fliplr_matches_numpy_across_2d_3d_dtype_and_error() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let fliplr_fn = module.getattr("fliplr")?;
            let numpy = py.import("numpy")?;
            let numpy_fliplr = numpy.getattr("fliplr")?;

            // 2-D column reversal.
            let two_d = numpy.getattr("array")?.call1((vec![
                vec![1_i64, 2, 3],
                vec![4, 5, 6],
                vec![7, 8, 9],
            ],))?;
            assert_array_matches_numpy(
                &fliplr_fn.call1((two_d.clone(),))?,
                &numpy_fliplr.call1((two_d.clone(),))?,
            )?;

            // 3-D leaves leading axis intact.
            let three_d = numpy.getattr("array")?.call1((vec![
                vec![vec![1_i64, 2], vec![3, 4]],
                vec![vec![5, 6], vec![7, 8]],
                vec![vec![9, 10], vec![11, 12]],
            ],))?;
            assert_array_matches_numpy(
                &fliplr_fn.call1((three_d.clone(),))?,
                &numpy_fliplr.call1((three_d.clone(),))?,
            )?;

            // Float dtype preservation.
            let floats = numpy.getattr("array")?.call(
                (vec![vec![1.5_f64, 2.5], vec![3.5, 4.5]],),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("dtype", numpy.getattr("float64")?)?;
                    kw
                }),
            )?;
            let ours_f = fliplr_fn.call1((floats.clone(),))?;
            let theirs_f = numpy_fliplr.call1((floats.clone(),))?;
            assert_array_matches_numpy(&ours_f, &theirs_f)?;
            let ours_dtype = ours_f.getattr("dtype")?.str()?.to_string();
            let theirs_dtype = theirs_f.getattr("dtype")?.str()?.to_string();
            assert_eq!(ours_dtype, theirs_dtype, "fliplr dtype must match numpy");

            // 1-D input must raise the same error in both implementations.
            let one_d = numpy.getattr("array")?.call1((vec![1_i64, 2, 3],))?;
            let ours_err = fliplr_fn.call1((one_d.clone(),)).err();
            let theirs_err = numpy_fliplr.call1((one_d.clone(),)).err();
            assert_eq!(
                ours_err.is_some(),
                theirs_err.is_some(),
                "fliplr 1-D must raise iff numpy does",
            );

            // Cross-check: fliplr(x) ≡ flip(x, axis=1).
            let flip_fn = module.getattr("flip")?;
            let via_flip = flip_fn.call(
                (two_d.clone(),),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("axis", 1_i64)?;
                    kw
                }),
            )?;
            assert_array_matches_numpy(&fliplr_fn.call1((two_d.clone(),))?, &via_flip)?;

            Ok(())
        });
    }

    #[test]
    fn intersect1d_matches_numpy_across_duplicates_indices_strings_and_flattening() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let intersect1d_fn = module.getattr("intersect1d")?;
            let numpy = py.import("numpy")?;
            let numpy_intersect1d = numpy.getattr("intersect1d")?;

            // Duplicate handling collapses to a sorted unique
            // intersection.
            let ar1 = numpy.getattr("array")?.call1((vec![1_i64, 3, 4, 3],))?;
            let ar2 = numpy.getattr("array")?.call1((vec![3_i64, 1, 2, 1],))?;
            assert_array_matches_numpy(
                &intersect1d_fn.call1((ar1.clone(), ar2.clone()))?,
                &numpy_intersect1d.call1((ar1.clone(), ar2.clone()))?,
            )?;

            // assume_unique fast path with already-unique inputs.
            let unique_left = numpy.getattr("array")?.call1((vec![1_i64, 2, 4, 7],))?;
            let unique_right = numpy.getattr("array")?.call1((vec![0_i64, 1, 4, 6],))?;
            assert_array_matches_numpy(
                &intersect1d_fn.call(
                    (unique_left.clone(), unique_right.clone()),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("assume_unique", true)?;
                        kw
                    }),
                )?,
                &numpy_intersect1d.call(
                    (unique_left.clone(), unique_right.clone()),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("assume_unique", true)?;
                        kw
                    }),
                )?,
            )?;

            // return_indices=True yields the intersected values plus the
            // first matching indices from both inputs.
            let x = numpy.getattr("array")?.call1((vec![1_i64, 1, 2, 3, 4],))?;
            let y = numpy.getattr("array")?.call1((vec![2_i64, 1, 4, 6],))?;
            assert_index_tuple_matches_numpy(
                &intersect1d_fn.call(
                    (x.clone(), y.clone()),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("return_indices", true)?;
                        kw
                    }),
                )?,
                &numpy_intersect1d.call(
                    (x.clone(), y.clone()),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("return_indices", true)?;
                        kw
                    }),
                )?,
            )?;

            // Empty intersection stays a 1-D empty array of the expected
            // dtype.
            let empty_left = numpy.getattr("array")?.call1((vec![5_i64, 6],))?;
            let empty_right = numpy.getattr("array")?.call1((vec![1_i64, 2],))?;
            assert_array_matches_numpy(
                &intersect1d_fn.call1((empty_left.clone(), empty_right.clone()))?,
                &numpy_intersect1d.call1((empty_left.clone(), empty_right.clone()))?,
            )?;

            // String arrays follow the same sorted-unique semantics.
            let strings_left = numpy.getattr("array")?.call1((vec!["b", "a", "c", "a"],))?;
            let strings_right = numpy.getattr("array")?.call1((vec!["c", "a", "d", "a"],))?;
            assert_array_matches_numpy(
                &intersect1d_fn.call1((strings_left.clone(), strings_right.clone()))?,
                &numpy_intersect1d.call1((strings_left.clone(), strings_right.clone()))?,
            )?;

            // Non-1-D input is flattened before intersection.
            let two_d_left = numpy
                .getattr("array")?
                .call1((vec![vec![1_i64, 2], vec![3, 4]],))?;
            let two_d_right = numpy
                .getattr("array")?
                .call1((vec![vec![0_i64, 2], vec![3, 5]],))?;
            assert_array_matches_numpy(
                &intersect1d_fn.call1((two_d_left.clone(), two_d_right.clone()))?,
                &numpy_intersect1d.call1((two_d_left.clone(), two_d_right.clone()))?,
            )?;

            Ok(())
        });
    }

    #[test]
    fn union1d_matches_numpy_across_disjoint_overlap_empty_string_and_flattened_inputs() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let union1d_fn = module.getattr("union1d")?;
            let numpy = py.import("numpy")?;
            let numpy_union1d = numpy.getattr("union1d")?;

            // Two disjoint integer arrays become a sorted unique union.
            let disjoint_left = numpy.getattr("array")?.call1((vec![5_i64, 1, 3],))?;
            let disjoint_right = numpy.getattr("array")?.call1((vec![2_i64, 4, 6],))?;
            assert_array_matches_numpy(
                &union1d_fn.call1((disjoint_left.clone(), disjoint_right.clone()))?,
                &numpy_union1d.call1((disjoint_left.clone(), disjoint_right.clone()))?,
            )?;

            // Overlapping arrays are deduplicated.
            let overlap_left = numpy.getattr("array")?.call1((vec![1_i64, 2, 2, 4],))?;
            let overlap_right = numpy.getattr("array")?.call1((vec![2_i64, 3, 4, 4],))?;
            assert_array_matches_numpy(
                &union1d_fn.call1((overlap_left.clone(), overlap_right.clone()))?,
                &numpy_union1d.call1((overlap_left.clone(), overlap_right.clone()))?,
            )?;

            // Empty left operand returns sorted-unique(right).
            let empty = numpy.getattr("array")?.call1((Vec::<i64>::new(),))?;
            let right = numpy.getattr("array")?.call1((vec![3_i64, 1, 3, 2],))?;
            assert_array_matches_numpy(
                &union1d_fn.call1((empty.clone(), right.clone()))?,
                &numpy_union1d.call1((empty.clone(), right.clone()))?,
            )?;

            // String arrays follow the same sorted-unique semantics.
            let strings_left = numpy.getattr("array")?.call1((vec!["b", "a", "c"],))?;
            let strings_right = numpy.getattr("array")?.call1((vec!["d", "a", "b"],))?;
            assert_array_matches_numpy(
                &union1d_fn.call1((strings_left.clone(), strings_right.clone()))?,
                &numpy_union1d.call1((strings_left.clone(), strings_right.clone()))?,
            )?;

            // 2-D inputs are flattened before union.
            let two_d_left = numpy
                .getattr("array")?
                .call1((vec![vec![1_i64, 2], vec![2, 3]],))?;
            let two_d_right = numpy
                .getattr("array")?
                .call1((vec![vec![3_i64, 4], vec![4, 5]],))?;
            assert_array_matches_numpy(
                &union1d_fn.call1((two_d_left.clone(), two_d_right.clone()))?,
                &numpy_union1d.call1((two_d_left.clone(), two_d_right.clone()))?,
            )?;

            // Float arrays with NaN preserve numpy's ordering and dtype.
            let float_left = numpy
                .getattr("array")?
                .call1((vec![1.5_f64, f64::NAN, 2.5, 1.5],))?;
            let float_right = numpy
                .getattr("array")?
                .call1((vec![2.5_f64, 3.5, f64::NAN],))?;
            assert_array_matches_numpy(
                &union1d_fn.call1((float_left.clone(), float_right.clone()))?,
                &numpy_union1d.call1((float_left.clone(), float_right.clone()))?,
            )?;

            Ok(())
        });
    }

    #[test]
    fn isin_matches_numpy_across_shapes_invert_kind_and_empty_tests() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let isin_fn = module.getattr("isin")?;
            let numpy = py.import("numpy")?;
            let numpy_isin = numpy.getattr("isin")?;

            // 1-D integer membership.
            let one_d = numpy.getattr("array")?.call1((vec![1_i64, 2, 3, 4],))?;
            let test = numpy.getattr("array")?.call1((vec![2_i64, 4],))?;
            assert_array_matches_numpy(
                &isin_fn.call1((one_d.clone(), test.clone()))?,
                &numpy_isin.call1((one_d.clone(), test.clone()))?,
            )?;

            // 2-D input preserves the original shape.
            let two_d = numpy
                .getattr("array")?
                .call1((vec![vec![1_i64, 2], vec![3, 4]],))?;
            let two_d_test = numpy.getattr("array")?.call1((vec![2_i64, 3],))?;
            assert_array_matches_numpy(
                &isin_fn.call1((two_d.clone(), two_d_test.clone()))?,
                &numpy_isin.call1((two_d.clone(), two_d_test.clone()))?,
            )?;

            // invert=True negates the membership mask.
            assert_array_matches_numpy(
                &isin_fn.call(
                    (one_d.clone(), test.clone()),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("invert", true)?;
                        kw
                    }),
                )?,
                &numpy_isin.call(
                    (one_d.clone(), test.clone()),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("invert", true)?;
                        kw
                    }),
                )?,
            )?;

            // assume_unique=True fast path with already-unique inputs.
            let unique = numpy.getattr("array")?.call1((vec![1_i64, 5, 9, 11],))?;
            let unique_test = numpy.getattr("array")?.call1((vec![0_i64, 5, 11],))?;
            assert_array_matches_numpy(
                &isin_fn.call(
                    (unique.clone(), unique_test.clone()),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("assume_unique", true)?;
                        kw
                    }),
                )?,
                &numpy_isin.call(
                    (unique.clone(), unique_test.clone()),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("assume_unique", true)?;
                        kw
                    }),
                )?,
            )?;

            // Explicit backend choices stay parity-aligned.
            let backend_input = numpy.getattr("array")?.call1((vec![1_i64, 2, 4, 8],))?;
            let backend_test = numpy.getattr("array")?.call1((vec![0_i64, 2, 8],))?;
            for kind_name in ["sort", "table"] {
                assert_array_matches_numpy(
                    &isin_fn.call(
                        (backend_input.clone(), backend_test.clone()),
                        Some(&{
                            let kw = PyDict::new(py);
                            kw.set_item("kind", kind_name)?;
                            kw
                        }),
                    )?,
                    &numpy_isin.call(
                        (backend_input.clone(), backend_test.clone()),
                        Some(&{
                            let kw = PyDict::new(py);
                            kw.set_item("kind", kind_name)?;
                            kw
                        }),
                    )?,
                )?;
            }

            // String arrays compare elementwise like numpy.
            let strings = numpy
                .getattr("array")?
                .call1((vec!["pear", "apple", "banana", "pear"],))?;
            let string_test = numpy.getattr("array")?.call1((vec!["apple", "kiwi"],))?;
            assert_array_matches_numpy(
                &isin_fn.call1((strings.clone(), string_test.clone()))?,
                &numpy_isin.call1((strings.clone(), string_test.clone()))?,
            )?;

            // Empty test_elements yields an all-false mask.
            let empty = numpy.getattr("array")?.call1((Vec::<i64>::new(),))?;
            assert_array_matches_numpy(
                &isin_fn.call1((one_d.clone(), empty.clone()))?,
                &numpy_isin.call1((one_d.clone(), empty.clone()))?,
            )?;

            Ok(())
        });
    }

    #[test]
    fn setdiff1d_matches_numpy_across_overlap_empty_string_and_flattened_inputs() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let setdiff1d_fn = module.getattr("setdiff1d")?;
            let numpy = py.import("numpy")?;
            let numpy_setdiff1d = numpy.getattr("setdiff1d")?;

            // Disjoint inputs yield sorted-unique(ar1).
            let disjoint_left = numpy.getattr("array")?.call1((vec![5_i64, 1, 3],))?;
            let disjoint_right = numpy.getattr("array")?.call1((vec![10_i64, 8],))?;
            assert_array_matches_numpy(
                &setdiff1d_fn.call1((disjoint_left.clone(), disjoint_right.clone()))?,
                &numpy_setdiff1d.call1((disjoint_left.clone(), disjoint_right.clone()))?,
            )?;

            // Overlap removes any value present in ar2.
            let overlap_left = numpy.getattr("array")?.call1((vec![1_i64, 2, 2, 4, 5],))?;
            let overlap_right = numpy.getattr("array")?.call1((vec![2_i64, 4, 7],))?;
            assert_array_matches_numpy(
                &setdiff1d_fn.call1((overlap_left.clone(), overlap_right.clone()))?,
                &numpy_setdiff1d.call1((overlap_left.clone(), overlap_right.clone()))?,
            )?;

            // assume_unique=True fast path with pre-sorted unique input.
            let unique_left = numpy.getattr("array")?.call1((vec![1_i64, 3, 5, 7],))?;
            let unique_right = numpy.getattr("array")?.call1((vec![3_i64, 8],))?;
            assert_array_matches_numpy(
                &setdiff1d_fn.call(
                    (unique_left.clone(), unique_right.clone()),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("assume_unique", true)?;
                        kw
                    }),
                )?,
                &numpy_setdiff1d.call(
                    (unique_left.clone(), unique_right.clone()),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("assume_unique", true)?;
                        kw
                    }),
                )?,
            )?;

            // Empty ar1 yields an empty result.
            let empty = numpy.getattr("array")?.call1((Vec::<i64>::new(),))?;
            let nonempty = numpy.getattr("array")?.call1((vec![1_i64, 2, 3],))?;
            assert_array_matches_numpy(
                &setdiff1d_fn.call1((empty.clone(), nonempty.clone()))?,
                &numpy_setdiff1d.call1((empty.clone(), nonempty.clone()))?,
            )?;

            // Empty ar2 returns sorted-unique(ar1).
            let dup_left = numpy.getattr("array")?.call1((vec![4_i64, 1, 4, 2],))?;
            assert_array_matches_numpy(
                &setdiff1d_fn.call1((dup_left.clone(), empty.clone()))?,
                &numpy_setdiff1d.call1((dup_left.clone(), empty.clone()))?,
            )?;

            // String arrays use the same sorted-unique semantics.
            let strings_left = numpy
                .getattr("array")?
                .call1((vec!["pear", "apple", "pear"],))?;
            let strings_right = numpy.getattr("array")?.call1((vec!["apple", "kiwi"],))?;
            assert_array_matches_numpy(
                &setdiff1d_fn.call1((strings_left.clone(), strings_right.clone()))?,
                &numpy_setdiff1d.call1((strings_left.clone(), strings_right.clone()))?,
            )?;

            // Non-1-D input is flattened before differencing.
            let two_d_left = numpy
                .getattr("array")?
                .call1((vec![vec![1_i64, 2], vec![2, 3]],))?;
            let two_d_right = numpy
                .getattr("array")?
                .call1((vec![vec![2_i64, 4], vec![5, 6]],))?;
            assert_array_matches_numpy(
                &setdiff1d_fn.call1((two_d_left.clone(), two_d_right.clone()))?,
                &numpy_setdiff1d.call1((two_d_left.clone(), two_d_right.clone()))?,
            )?;

            Ok(())
        });
    }

    #[test]
    fn vander_matches_numpy_across_width_order_dtype_empty_and_error_surface() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let vander_fn = module.getattr("vander")?;
            let numpy = py.import("numpy")?;
            let numpy_vander = numpy.getattr("vander")?;

            // Default width is len(x) and integer input preserves dtype.
            let ints = numpy.getattr("array")?.call1((vec![1_i64, 2, 3],))?;
            assert_array_matches_numpy(
                &vander_fn.call1((ints.clone(),))?,
                &numpy_vander.call1((ints.clone(),))?,
            )?;

            // Explicit N larger than len(x) pads the leading columns.
            assert_array_matches_numpy(
                &vander_fn.call(
                    (ints.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("N", 5_usize)?;
                        kw
                    }),
                )?,
                &numpy_vander.call(
                    (ints.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("N", 5_usize)?;
                        kw
                    }),
                )?,
            )?;

            // Explicit N smaller than len(x) truncates to the requested width.
            assert_array_matches_numpy(
                &vander_fn.call(
                    (ints.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("N", 2_usize)?;
                        kw
                    }),
                )?,
                &numpy_vander.call(
                    (ints.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("N", 2_usize)?;
                        kw
                    }),
                )?,
            )?;

            // increasing=True reverses the power order.
            assert_array_matches_numpy(
                &vander_fn.call(
                    (ints.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("increasing", true)?;
                        kw
                    }),
                )?,
                &numpy_vander.call(
                    (ints.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("increasing", true)?;
                        kw
                    }),
                )?,
            )?;

            // Float input preserves dtype and values.
            let floats = numpy.getattr("array")?.call1((vec![0.5_f64, 1.5, 2.5],))?;
            assert_array_matches_numpy(
                &vander_fn.call1((floats.clone(),))?,
                &numpy_vander.call1((floats.clone(),))?,
            )?;

            // Empty input with explicit width returns an empty 2-D result.
            let empty = numpy.getattr("array")?.call1((Vec::<i64>::new(),))?;
            assert_array_matches_numpy(
                &vander_fn.call(
                    (empty.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("N", 3_usize)?;
                        kw
                    }),
                )?,
                &numpy_vander.call(
                    (empty.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("N", 3_usize)?;
                        kw
                    }),
                )?,
            )?;

            // Non-1-D input must raise the same ValueError surface.
            let two_d = numpy
                .getattr("array")?
                .call1((vec![vec![1_i64, 2], vec![3, 4]],))?;
            let actual_err = vander_fn.call1((two_d.clone(),)).unwrap_err();
            let expected_err = numpy_vander.call1((two_d.clone(),)).unwrap_err();
            assert!(actual_err.is_instance_of::<PyValueError>(py));
            assert!(expected_err.is_instance_of::<PyValueError>(py));
            assert_eq!(actual_err.to_string(), expected_err.to_string());

            Ok(())
        });
    }

    #[test]
    fn histogram_bin_edges_matches_numpy_across_bins_range_weights_and_errors() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let histogram_bin_edges_fn = module.getattr("histogram_bin_edges")?;
            let numpy = py.import("numpy")?;
            let numpy_histogram_bin_edges = numpy.getattr("histogram_bin_edges")?;

            // Default integer bin count.
            let ints = numpy
                .getattr("array")?
                .call1((vec![0.0_f64, 1.0, 1.5, 2.0, 4.0],))?;
            assert_array_matches_numpy(
                &histogram_bin_edges_fn.call1((ints.clone(),))?,
                &numpy_histogram_bin_edges.call1((ints.clone(),))?,
            )?;

            // Explicit edge array passthrough.
            let explicit_edges = numpy
                .getattr("array")?
                .call1((vec![0.0_f64, 1.0, 3.0, 5.0],))?;
            assert_array_matches_numpy(
                &histogram_bin_edges_fn.call(
                    (ints.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("bins", explicit_edges.clone())?;
                        kw
                    }),
                )?,
                &numpy_histogram_bin_edges.call(
                    (ints.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("bins", explicit_edges.clone())?;
                        kw
                    }),
                )?,
            )?;

            // Explicit range clipping with an integer bin count.
            assert_array_matches_numpy(
                &histogram_bin_edges_fn.call(
                    (ints.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("bins", 4_i64)?;
                        kw.set_item("range", (0.0_f64, 2.0_f64))?;
                        kw
                    }),
                )?,
                &numpy_histogram_bin_edges.call(
                    (ints.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("bins", 4_i64)?;
                        kw.set_item("range", (0.0_f64, 2.0_f64))?;
                        kw
                    }),
                )?,
            )?;

            // Estimator string parity.
            let estimator_input = numpy
                .getattr("array")?
                .call1((vec![0.1_f64, 0.4, 0.7, 1.8, 2.0, 2.4, 2.7],))?;
            assert_array_matches_numpy(
                &histogram_bin_edges_fn.call(
                    (estimator_input.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("bins", "fd")?;
                        kw
                    }),
                )?,
                &numpy_histogram_bin_edges.call(
                    (estimator_input.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("bins", "fd")?;
                        kw
                    }),
                )?,
            )?;

            // Weights parity on supported numeric-bin paths.
            let weighted = numpy
                .getattr("array")?
                .call1((vec![0.0_f64, 0.5, 1.5, 2.0, 2.5],))?;
            let weights = numpy
                .getattr("array")?
                .call1((vec![1.0_f64, 2.0, 1.0, 3.0, 4.0],))?;
            assert_array_matches_numpy(
                &histogram_bin_edges_fn.call(
                    (weighted.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("bins", 3_i64)?;
                        kw.set_item("weights", weights.clone())?;
                        kw
                    }),
                )?,
                &numpy_histogram_bin_edges.call(
                    (weighted.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("bins", 3_i64)?;
                        kw.set_item("weights", weights.clone())?;
                        kw
                    }),
                )?,
            )?;

            // Empty input parity.
            let empty = numpy.getattr("array")?.call1((Vec::<f64>::new(),))?;
            assert_array_matches_numpy(
                &histogram_bin_edges_fn.call(
                    (empty.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("bins", 4_i64)?;
                        kw
                    }),
                )?,
                &numpy_histogram_bin_edges.call(
                    (empty.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("bins", 4_i64)?;
                        kw
                    }),
                )?,
            )?;

            // Non-finite input with an automatic estimator must raise
            // the same error surface.
            let nonfinite = numpy
                .getattr("array")?
                .call1((vec![0.0_f64, 1.0, f64::INFINITY],))?;
            let actual_err = histogram_bin_edges_fn
                .call(
                    (nonfinite.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("bins", "auto")?;
                        kw
                    }),
                )
                .unwrap_err();
            let expected_err = numpy_histogram_bin_edges
                .call(
                    (nonfinite.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("bins", "auto")?;
                        kw
                    }),
                )
                .unwrap_err();
            assert_pyerr_matches_numpy(py, actual_err, expected_err)?;

            Ok(())
        });
    }

    #[test]
    fn histogram_matches_numpy_across_bins_range_density_weights_and_empty() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let histogram_fn = module.getattr("histogram")?;
            let numpy = py.import("numpy")?;
            let numpy_histogram = numpy.getattr("histogram")?;

            let values = numpy
                .getattr("array")?
                .call1((vec![0.0_f64, 0.5, 1.0, 1.5, 2.0, 3.0],))?;

            // Default 10-bin path.
            let actual_default = histogram_fn.call1((values.clone(),))?;
            let expected_default = numpy_histogram.call1((values.clone(),))?;
            assert_index_tuple_matches_numpy(&actual_default, &expected_default)?;
            let actual_default_tuple = actual_default.cast::<PyTuple>()?;
            assert_eq!(actual_default_tuple.len()?, 2);
            let counts = actual_default_tuple.get_item(0)?;
            let edges = actual_default_tuple.get_item(1)?;
            assert_eq!(counts.len()?, 10);
            assert_eq!(edges.len()?, 11);

            // Explicit integer bin count.
            assert_index_tuple_matches_numpy(
                &histogram_fn.call(
                    (values.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("bins", 4_i64)?;
                        kw
                    }),
                )?,
                &numpy_histogram.call(
                    (values.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("bins", 4_i64)?;
                        kw
                    }),
                )?,
            )?;

            // Explicit bin edges.
            let explicit_edges = numpy
                .getattr("array")?
                .call1((vec![0.0_f64, 1.0, 2.0, 4.0],))?;
            assert_index_tuple_matches_numpy(
                &histogram_fn.call(
                    (values.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("bins", explicit_edges.clone())?;
                        kw
                    }),
                )?,
                &numpy_histogram.call(
                    (values.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("bins", explicit_edges.clone())?;
                        kw
                    }),
                )?,
            )?;

            // Range clipping with density normalization.
            assert_index_tuple_matches_numpy(
                &histogram_fn.call(
                    (values.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("bins", 3_i64)?;
                        kw.set_item("range", (0.0_f64, 2.5_f64))?;
                        kw.set_item("density", true)?;
                        kw
                    }),
                )?,
                &numpy_histogram.call(
                    (values.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("bins", 3_i64)?;
                        kw.set_item("range", (0.0_f64, 2.5_f64))?;
                        kw.set_item("density", true)?;
                        kw
                    }),
                )?,
            )?;

            // Weighted accumulation.
            let weights = numpy
                .getattr("array")?
                .call1((vec![1.0_f64, 0.5, 2.0, 1.5, 1.0, 3.0],))?;
            assert_index_tuple_matches_numpy(
                &histogram_fn.call(
                    (values.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("bins", 5_i64)?;
                        kw.set_item("weights", weights.clone())?;
                        kw
                    }),
                )?,
                &numpy_histogram.call(
                    (values.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("bins", 5_i64)?;
                        kw.set_item("weights", weights.clone())?;
                        kw
                    }),
                )?,
            )?;

            // Empty input parity.
            let empty = numpy.getattr("array")?.call1((Vec::<f64>::new(),))?;
            let actual_empty = histogram_fn.call(
                (empty.clone(),),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("bins", 4_i64)?;
                    kw
                }),
            )?;
            let expected_empty = numpy_histogram.call(
                (empty.clone(),),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("bins", 4_i64)?;
                    kw
                }),
            )?;
            assert_index_tuple_matches_numpy(&actual_empty, &expected_empty)?;

            Ok(())
        });
    }

    #[test]
    fn ravel_matches_numpy_across_order_ndim_scalar_and_object() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let ravel_fn = module.getattr("ravel")?;
            let numpy = py.import("numpy")?;
            let numpy_ravel = numpy.getattr("ravel")?;

            let two_d = numpy
                .getattr("array")?
                .call1((vec![vec![1_i64, 2], vec![3_i64, 4]],))?;

            // Default C-order flattening on 2-D input.
            assert_array_matches_numpy(
                &ravel_fn.call1((two_d.clone(),))?,
                &numpy_ravel.call1((two_d.clone(),))?,
            )?;

            // Fortran-order flattening traverses columns first.
            assert_array_matches_numpy(
                &ravel_fn.call1((two_d.clone(), "F"))?,
                &numpy_ravel.call1((two_d.clone(), "F"))?,
            )?;

            // 3-D inputs preserve NumPy's order-sensitive flattening.
            let three_d = numpy
                .getattr("arange")?
                .call1((8_i64,))?
                .call_method1("reshape", ((2_i64, 2_i64, 2_i64),))?;
            assert_array_matches_numpy(
                &ravel_fn.call1((three_d.clone(), "F"))?,
                &numpy_ravel.call1((three_d.clone(), "F"))?,
            )?;

            // Scalar/0-D input becomes a length-1 result with matching
            // shape and dtype.
            let scalar = numpy.getattr("array")?.call1((7_i64,))?;
            let ours_scalar = ravel_fn.call1((scalar.clone(),))?;
            let theirs_scalar = numpy_ravel.call1((scalar.clone(),))?;
            assert_array_matches_numpy(&ours_scalar, &theirs_scalar)?;
            assert_eq!(
                ours_scalar.getattr("shape")?.str()?.to_string(),
                theirs_scalar.getattr("shape")?.str()?.to_string(),
                "ravel scalar shape must match numpy",
            );
            assert_eq!(
                ours_scalar.getattr("dtype")?.str()?.to_string(),
                theirs_scalar.getattr("dtype")?.str()?.to_string(),
                "ravel scalar dtype must match numpy",
            );

            // Object arrays preserve dtype and value parity.
            let object_arr = object_array(py, vec!["north", "south"]);
            let ours_object = ravel_fn.call1((object_arr.clone(),))?;
            let theirs_object = numpy_ravel.call1((object_arr.clone(),))?;
            assert_array_matches_numpy(&ours_object, &theirs_object)?;
            assert_eq!(
                ours_object.getattr("shape")?.str()?.to_string(),
                theirs_object.getattr("shape")?.str()?.to_string(),
                "ravel object-array shape must match numpy",
            );
            assert_eq!(
                ours_object.getattr("dtype")?.str()?.to_string(),
                theirs_object.getattr("dtype")?.str()?.to_string(),
                "ravel object-array dtype must match numpy",
            );

            Ok(())
        });
    }

    #[test]
    fn reshape_matches_numpy_across_inferred_order_scalar_object_and_errors() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let reshape_fn = module.getattr("reshape")?;
            let numpy = py.import("numpy")?;
            let numpy_reshape = numpy.getattr("reshape")?;

            // Simple 1-D to 2-D reshape.
            let one_d = numeric_array(py, vec![1_i64, 2, 3, 4], "int64");
            assert_array_matches_numpy(
                &reshape_fn.call1((one_d.clone(), (2_i64, 2_i64)))?,
                &numpy_reshape.call1((one_d.clone(), (2_i64, 2_i64)))?,
            )?;

            // -1 infers the remaining dimension.
            let infer_source = numeric_array(py, vec![1_i64, 2, 3, 4, 5, 6], "int64");
            assert_array_matches_numpy(
                &reshape_fn.call1((infer_source.clone(), (2_i64, -1_i64)))?,
                &numpy_reshape.call1((infer_source.clone(), (2_i64, -1_i64)))?,
            )?;

            // Fortran-order reshape traverses in column-major order.
            assert_array_matches_numpy(
                &reshape_fn.call1((one_d.clone(), (2_i64, 2_i64), "F"))?,
                &numpy_reshape.call1((one_d.clone(), (2_i64, 2_i64), "F"))?,
            )?;

            // Scalar/0-D input parity.
            let scalar = numpy.getattr("array")?.call1((7_i64,))?;
            let ours_scalar = reshape_fn.call1((scalar.clone(), (1_i64,)))?;
            let theirs_scalar = numpy_reshape.call1((scalar.clone(), (1_i64,)))?;
            assert_array_matches_numpy(&ours_scalar, &theirs_scalar)?;
            assert_eq!(
                ours_scalar.getattr("shape")?.str()?.to_string(),
                theirs_scalar.getattr("shape")?.str()?.to_string(),
                "reshape scalar shape must match numpy",
            );
            assert_eq!(
                ours_scalar.getattr("dtype")?.str()?.to_string(),
                theirs_scalar.getattr("dtype")?.str()?.to_string(),
                "reshape scalar dtype must match numpy",
            );

            // Object dtype parity.
            let object_source = object_array(py, vec!["a", "b", "c", "d"]);
            let ours_object = reshape_fn.call1((object_source.clone(), (2_i64, 2_i64)))?;
            let theirs_object = numpy_reshape.call1((object_source.clone(), (2_i64, 2_i64)))?;
            assert_array_matches_numpy(&ours_object, &theirs_object)?;
            assert_eq!(
                ours_object.getattr("shape")?.str()?.to_string(),
                theirs_object.getattr("shape")?.str()?.to_string(),
                "reshape object-array shape must match numpy",
            );
            assert_eq!(
                ours_object.getattr("dtype")?.str()?.to_string(),
                theirs_object.getattr("dtype")?.str()?.to_string(),
                "reshape object-array dtype must match numpy",
            );

            // Invalid shapes surface NumPy's exact ValueError.
            let bad_source = numeric_array(py, vec![1_i64, 2, 3], "int64");
            let actual_err = reshape_fn
                .call1((bad_source.clone(), (2_i64, 2_i64)))
                .unwrap_err();
            let expected_err = numpy_reshape
                .call1((bad_source.clone(), (2_i64, 2_i64)))
                .unwrap_err();
            assert_pyerr_matches_numpy(py, actual_err, expected_err)?;

            Ok(())
        });
    }

    #[test]
    fn transpose_matches_numpy_across_axes_scalar_object_and_error_surface() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let transpose_fn = module.getattr("transpose")?;
            let numpy = py.import("numpy")?;
            let numpy_transpose = numpy.getattr("transpose")?;

            // 2-D default transpose.
            let two_d = numpy
                .getattr("array")?
                .call1((vec![vec![1_i64, 2, 3], vec![4, 5, 6]],))?;
            assert_array_matches_numpy(
                &transpose_fn.call1((two_d.clone(),))?,
                &numpy_transpose.call1((two_d.clone(),))?,
            )?;

            // Explicit axes on 3-D input.
            let three_d = numpy.getattr("array")?.call1((vec![
                vec![vec![1_i64, 2], vec![3, 4], vec![5, 6]],
                vec![vec![7_i64, 8], vec![9, 10], vec![11, 12]],
            ],))?;
            assert_array_matches_numpy(
                &transpose_fn.call(
                    (three_d.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("axes", (1_i64, 2_i64, 0_i64))?;
                        kw
                    }),
                )?,
                &numpy_transpose.call(
                    (three_d.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("axes", (1_i64, 2_i64, 0_i64))?;
                        kw
                    }),
                )?,
            )?;

            // Negative axes normalize like numpy.
            assert_array_matches_numpy(
                &transpose_fn.call(
                    (three_d.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("axes", (-1_i64, -3_i64, -2_i64))?;
                        kw
                    }),
                )?,
                &numpy_transpose.call(
                    (three_d.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("axes", (-1_i64, -3_i64, -2_i64))?;
                        kw
                    }),
                )?,
            )?;

            // Scalar and 1-D inputs are shape-preserving no-ops.
            let scalar = numpy.getattr("array")?.call1((7_i64,))?;
            assert_array_matches_numpy(
                &transpose_fn.call1((scalar.clone(),))?,
                &numpy_transpose.call1((scalar.clone(),))?,
            )?;
            let one_d = numpy.getattr("array")?.call1((vec![1_i64, 2, 3],))?;
            assert_array_matches_numpy(
                &transpose_fn.call1((one_d.clone(),))?,
                &numpy_transpose.call1((one_d.clone(),))?,
            )?;

            // Object dtype parity.
            let objects = numpy
                .getattr("array")?
                .call1((vec![vec!["a", "bb"], vec!["ccc", "dddd"]],))?;
            assert_array_matches_numpy(
                &transpose_fn.call1((objects.clone(),))?,
                &numpy_transpose.call1((objects.clone(),))?,
            )?;

            // Invalid repeated axis must raise the same error surface.
            let actual_err = transpose_fn
                .call(
                    (three_d.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("axes", (0_i64, 0_i64, 1_i64))?;
                        kw
                    }),
                )
                .unwrap_err();
            let expected_err = numpy_transpose
                .call(
                    (three_d.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("axes", (0_i64, 0_i64, 1_i64))?;
                        kw
                    }),
                )
                .unwrap_err();
            assert_pyerr_matches_numpy(py, actual_err, expected_err)?;

            Ok(())
        });
    }

    #[test]
    fn swapaxes_matches_numpy_across_dims_negative_axes_and_error_surface() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let swapaxes_fn = module.getattr("swapaxes")?;
            let numpy = py.import("numpy")?;
            let numpy_swapaxes = numpy.getattr("swapaxes")?;

            // 2-D swap matches transpose.
            let two_d = numpy
                .getattr("array")?
                .call1((vec![vec![1_i64, 2, 3], vec![4, 5, 6]],))?;
            assert_array_matches_numpy(
                &swapaxes_fn.call1((two_d.clone(), 0_i64, 1_i64))?,
                &numpy_swapaxes.call1((two_d.clone(), 0_i64, 1_i64))?,
            )?;

            // 3-D non-adjacent axis swap.
            let three_d = numpy.getattr("array")?.call1((vec![
                vec![vec![1_i64, 2], vec![3, 4], vec![5, 6]],
                vec![vec![7_i64, 8], vec![9, 10], vec![11, 12]],
            ],))?;
            assert_array_matches_numpy(
                &swapaxes_fn.call1((three_d.clone(), 0_i64, 2_i64))?,
                &numpy_swapaxes.call1((three_d.clone(), 0_i64, 2_i64))?,
            )?;

            // Negative axes normalize like numpy.
            assert_array_matches_numpy(
                &swapaxes_fn.call1((three_d.clone(), -1_i64, -3_i64))?,
                &numpy_swapaxes.call1((three_d.clone(), -1_i64, -3_i64))?,
            )?;

            // Scalar input raises the same axis error surface.
            let scalar = numpy.getattr("array")?.call1((7_i64,))?;
            let actual_scalar_err = swapaxes_fn
                .call1((scalar.clone(), 0_i64, 0_i64))
                .unwrap_err();
            let expected_scalar_err = numpy_swapaxes
                .call1((scalar.clone(), 0_i64, 0_i64))
                .unwrap_err();
            assert_pyerr_matches_numpy(py, actual_scalar_err, expected_scalar_err)?;

            // 1-D with axis 0 is an identity operation.
            let one_d = numpy.getattr("array")?.call1((vec![1_i64, 2, 3],))?;
            assert_array_matches_numpy(
                &swapaxes_fn.call1((one_d.clone(), 0_i64, 0_i64))?,
                &numpy_swapaxes.call1((one_d.clone(), 0_i64, 0_i64))?,
            )?;

            // Object dtype parity.
            let objects = numpy
                .getattr("array")?
                .call1((vec![vec!["a", "bb"], vec!["ccc", "dddd"]],))?;
            assert_array_matches_numpy(
                &swapaxes_fn.call1((objects.clone(), 0_i64, 1_i64))?,
                &numpy_swapaxes.call1((objects.clone(), 0_i64, 1_i64))?,
            )?;

            // Out-of-range axis must raise the same error surface.
            let actual_err = swapaxes_fn
                .call1((three_d.clone(), 0_i64, 3_i64))
                .unwrap_err();
            let expected_err = numpy_swapaxes
                .call1((three_d.clone(), 0_i64, 3_i64))
                .unwrap_err();
            assert_pyerr_matches_numpy(py, actual_err, expected_err)?;

            Ok(())
        });
    }

    #[test]
    fn moveaxis_matches_numpy_across_tuple_negative_axes_and_errors() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let moveaxis_fn = module.getattr("moveaxis")?;
            let numpy = py.import("numpy")?;
            let numpy_moveaxis = numpy.getattr("moveaxis")?;

            // Single-axis move on 3-D input.
            let three_d = numpy.getattr("array")?.call1((vec![
                vec![vec![1_i64, 2], vec![3, 4], vec![5, 6]],
                vec![vec![7_i64, 8], vec![9, 10], vec![11, 12]],
            ],))?;
            assert_array_matches_numpy(
                &moveaxis_fn.call1((three_d.clone(), 0_i64, 2_i64))?,
                &numpy_moveaxis.call1((three_d.clone(), 0_i64, 2_i64))?,
            )?;

            // Tuple-based simultaneous reordering.
            assert_array_matches_numpy(
                &moveaxis_fn.call1((three_d.clone(), (0_i64, 2_i64), (2_i64, 0_i64)))?,
                &numpy_moveaxis.call1((three_d.clone(), (0_i64, 2_i64), (2_i64, 0_i64)))?,
            )?;

            // Negative axes normalize like numpy.
            assert_array_matches_numpy(
                &moveaxis_fn.call1((three_d.clone(), -1_i64, -3_i64))?,
                &numpy_moveaxis.call1((three_d.clone(), -1_i64, -3_i64))?,
            )?;

            // No-op move must preserve values and shape.
            assert_array_matches_numpy(
                &moveaxis_fn.call1((three_d.clone(), (0_i64, 2_i64), (0_i64, 2_i64)))?,
                &numpy_moveaxis.call1((three_d.clone(), (0_i64, 2_i64), (0_i64, 2_i64)))?,
            )?;

            // Object dtype parity.
            let objects = numpy.getattr("array")?.call1((vec![
                vec![vec!["aa", "bbb"], vec!["cccc", "ddddd"]],
                vec![vec!["eeeeee", "fffffff"], vec!["gggggggg", "hhhhhhhhh"]],
            ],))?;
            assert_array_matches_numpy(
                &moveaxis_fn.call1((objects.clone(), 0_i64, -1_i64))?,
                &numpy_moveaxis.call1((objects.clone(), 0_i64, -1_i64))?,
            )?;

            // Source/destination length mismatch must raise the same error.
            let actual_err = moveaxis_fn
                .call1((three_d.clone(), (0_i64, 2_i64), (1_i64,)))
                .unwrap_err();
            let expected_err = numpy_moveaxis
                .call1((three_d.clone(), (0_i64, 2_i64), (1_i64,)))
                .unwrap_err();
            assert_pyerr_matches_numpy(py, actual_err, expected_err)?;

            Ok(())
        });
    }

    #[test]
    fn rollaxis_matches_numpy_across_axis_start_object_and_errors() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let rollaxis_fn = module.getattr("rollaxis")?;
            let numpy = py.import("numpy")?;
            let numpy_rollaxis = numpy.getattr("rollaxis")?;

            // Moving the trailing axis to the front on 3-D input.
            let three_d = numpy.getattr("array")?.call1((vec![
                vec![vec![1_i64, 2], vec![3, 4], vec![5, 6]],
                vec![vec![7_i64, 8], vec![9, 10], vec![11, 12]],
            ],))?;
            assert_array_matches_numpy(
                &rollaxis_fn.call1((three_d.clone(), 2_i64))?,
                &numpy_rollaxis.call1((three_d.clone(), 2_i64))?,
            )?;

            // Nonzero start inserts the moved axis before the requested position.
            assert_array_matches_numpy(
                &rollaxis_fn.call1((three_d.clone(), 2_i64, 1_i64))?,
                &numpy_rollaxis.call1((three_d.clone(), 2_i64, 1_i64))?,
            )?;

            // Negative axes normalize like numpy.
            assert_array_matches_numpy(
                &rollaxis_fn.call1((three_d.clone(), -1_i64, -2_i64))?,
                &numpy_rollaxis.call1((three_d.clone(), -1_i64, -2_i64))?,
            )?;

            // 2-D input parity.
            let two_d = numpy
                .getattr("array")?
                .call1((vec![vec![1_i64, 2, 3], vec![4, 5, 6]],))?;
            assert_array_matches_numpy(
                &rollaxis_fn.call1((two_d.clone(), 1_i64))?,
                &numpy_rollaxis.call1((two_d.clone(), 1_i64))?,
            )?;

            // Object dtype parity.
            let objects = numpy.getattr("array")?.call1((vec![
                vec![vec!["aa", "bbb"], vec!["cccc", "ddddd"]],
                vec![vec!["eeeeee", "fffffff"], vec!["gggggggg", "hhhhhhhhh"]],
            ],))?;
            assert_array_matches_numpy(
                &rollaxis_fn.call1((objects.clone(), 2_i64, 1_i64))?,
                &numpy_rollaxis.call1((objects.clone(), 2_i64, 1_i64))?,
            )?;

            // Out-of-range axis must raise the same error surface.
            let actual_axis_err = rollaxis_fn.call1((three_d.clone(), 3_i64)).unwrap_err();
            let expected_axis_err = numpy_rollaxis.call1((three_d.clone(), 3_i64)).unwrap_err();
            assert_pyerr_matches_numpy(py, actual_axis_err, expected_axis_err)?;

            // Out-of-range start must also match numpy's validation error.
            let actual_start_err = rollaxis_fn
                .call1((three_d.clone(), 0_i64, 5_i64))
                .unwrap_err();
            let expected_start_err = numpy_rollaxis
                .call1((three_d.clone(), 0_i64, 5_i64))
                .unwrap_err();
            assert_pyerr_matches_numpy(py, actual_start_err, expected_start_err)?;

            Ok(())
        });
    }

    #[test]
    fn squeeze_matches_numpy_across_axes_scalar_and_error_surface() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let squeeze_fn = module.getattr("squeeze")?;
            let numpy = py.import("numpy")?;
            let numpy_squeeze = numpy.getattr("squeeze")?;

            // Default squeeze removes all singleton axes.
            let values = numpy
                .getattr("array")?
                .call1((vec![vec![vec![1_i64, 2, 3]]],))?;
            assert_array_matches_numpy(
                &squeeze_fn.call1((values.clone(),))?,
                &numpy_squeeze.call1((values.clone(),))?,
            )?;

            // Explicit single axis.
            let shaped = numpy.getattr("array")?.call1((vec![vec![
                vec![1_i64],
                vec![2_i64],
                vec![3_i64],
            ]],))?;
            assert_array_matches_numpy(
                &squeeze_fn.call(
                    (shaped.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("axis", 0_i64)?;
                        kw
                    }),
                )?,
                &numpy_squeeze.call(
                    (shaped.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("axis", 0_i64)?;
                        kw
                    }),
                )?,
            )?;

            // Explicit tuple of axes with negative-axis normalization.
            assert_array_matches_numpy(
                &squeeze_fn.call(
                    (shaped.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("axis", (0_i64, -1_i64))?;
                        kw
                    }),
                )?,
                &numpy_squeeze.call(
                    (shaped.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("axis", (0_i64, -1_i64))?;
                        kw
                    }),
                )?,
            )?;

            // Scalar input stays scalar.
            let scalar = numpy.getattr("array")?.call1((7_i64,))?;
            assert_array_matches_numpy(
                &squeeze_fn.call1((scalar.clone(),))?,
                &numpy_squeeze.call1((scalar.clone(),))?,
            )?;

            // Object dtype parity.
            let objects = numpy
                .getattr("array")?
                .call1((vec![vec!["aa", "bbb", "cccc"]],))?;
            assert_array_matches_numpy(
                &squeeze_fn.call1((objects.clone(),))?,
                &numpy_squeeze.call1((objects.clone(),))?,
            )?;

            // Non-singleton axis must raise the same error surface.
            let actual_err = squeeze_fn
                .call(
                    (shaped.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("axis", 1_i64)?;
                        kw
                    }),
                )
                .unwrap_err();
            let expected_err = numpy_squeeze
                .call(
                    (shaped.clone(),),
                    Some(&{
                        let kw = PyDict::new(py);
                        kw.set_item("axis", 1_i64)?;
                        kw
                    }),
                )
                .unwrap_err();
            assert_pyerr_matches_numpy(py, actual_err, expected_err)?;

            Ok(())
        });
    }

    #[test]
    fn rot90_matches_numpy_across_k_axes_and_error_surface() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let rot90_fn = module.getattr("rot90")?;
            let numpy = py.import("numpy")?;
            let numpy_rot90 = numpy.getattr("rot90")?;

            // Default k=1 on a non-square 2-D input.
            let rectangular = numpy
                .getattr("array")?
                .call1((vec![vec![1_i64, 2, 3], vec![4, 5, 6]],))?;
            assert_array_matches_numpy(
                &rot90_fn.call1((rectangular.clone(),))?,
                &numpy_rot90.call1((rectangular.clone(),))?,
            )?;

            // Repeated turns, including negative k.
            assert_array_matches_numpy(
                &rot90_fn.call1((rectangular.clone(), 2_i64))?,
                &numpy_rot90.call1((rectangular.clone(), 2_i64))?,
            )?;
            assert_array_matches_numpy(
                &rot90_fn.call1((rectangular.clone(), -1_i64))?,
                &numpy_rot90.call1((rectangular.clone(), -1_i64))?,
            )?;

            // 3-D rotation over a custom axis pair.
            let three_d = numpy.getattr("array")?.call1((vec![
                vec![vec![1_i64, 2], vec![3, 4], vec![5, 6]],
                vec![vec![7_i64, 8], vec![9, 10], vec![11, 12]],
            ],))?;
            assert_array_matches_numpy(
                &rot90_fn.call1((three_d.clone(), 1_i64, (0_i64, 2_i64)))?,
                &numpy_rot90.call1((three_d.clone(), 1_i64, (0_i64, 2_i64)))?,
            )?;

            // Reversing the axes flips the rotation direction.
            assert_array_matches_numpy(
                &rot90_fn.call1((three_d.clone(), 1_i64, (1_i64, 0_i64)))?,
                &numpy_rot90.call1((three_d.clone(), 1_i64, (1_i64, 0_i64)))?,
            )?;

            // Repeated axes must raise the same error surface.
            let actual_repeated_err = rot90_fn
                .call1((three_d.clone(), 1_i64, (1_i64, 1_i64)))
                .unwrap_err();
            let expected_repeated_err = numpy_rot90
                .call1((three_d.clone(), 1_i64, (1_i64, 1_i64)))
                .unwrap_err();
            assert_pyerr_matches_numpy(py, actual_repeated_err, expected_repeated_err)?;

            // Rotating a 1-D input with default axes is invalid.
            let one_d = numpy.getattr("array")?.call1((vec![1_i64, 2, 3],))?;
            let actual_dim_err = rot90_fn.call1((one_d.clone(),)).unwrap_err();
            let expected_dim_err = numpy_rot90.call1((one_d.clone(),)).unwrap_err();
            assert_pyerr_matches_numpy(py, actual_dim_err, expected_dim_err)?;

            Ok(())
        });
    }

    #[test]
    fn full_matches_numpy_across_shapes_dtype_object_order_zero_and_scalar_fill() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let full_fn = module.getattr("full")?;
            let numpy = py.import("numpy")?;
            let numpy_full = numpy.getattr("full")?;

            // Scalar shape input fills a 1-D array.
            assert_array_matches_numpy(
                &full_fn.call1((4_i64, 7_i64))?,
                &numpy_full.call1((4_i64, 7_i64))?,
            )?;

            // Tuple shape plus explicit dtype coercion.
            let ours_dtype = full_fn.call(
                ((2_i64, 3_i64), 1.25_f64),
                Some(&{
                    let kwargs = PyDict::new(py);
                    kwargs.set_item("dtype", numpy.getattr("int64")?)?;
                    kwargs
                }),
            )?;
            let theirs_dtype = numpy_full.call(
                ((2_i64, 3_i64), 1.25_f64),
                Some(&{
                    let kwargs = PyDict::new(py);
                    kwargs.set_item("dtype", numpy.getattr("int64")?)?;
                    kwargs
                }),
            )?;
            assert_array_matches_numpy(&ours_dtype, &theirs_dtype)?;
            assert_eq!(
                ours_dtype.getattr("dtype")?.str()?.extract::<String>()?,
                theirs_dtype.getattr("dtype")?.str()?.extract::<String>()?
            );

            // Object fill values should preserve object dtype and contents.
            let object_fill = PyDict::new(py);
            object_fill.set_item("direction", "north")?;
            let ours_object = full_fn.call(
                ((2_i64,), object_fill.clone()),
                Some(&{
                    let kwargs = PyDict::new(py);
                    kwargs.set_item("dtype", numpy.getattr("object_")?)?;
                    kwargs
                }),
            )?;
            let theirs_object = numpy_full.call(
                ((2_i64,), object_fill.clone()),
                Some(&{
                    let kwargs = PyDict::new(py);
                    kwargs.set_item("dtype", numpy.getattr("object_")?)?;
                    kwargs
                }),
            )?;
            assert_array_matches_numpy(&ours_object, &theirs_object)?;

            // order='F' should preserve NumPy's Fortran-layout request.
            let ours_fortran = full_fn.call(
                ((2_i64, 3_i64), 9_i64),
                Some(&{
                    let kwargs = PyDict::new(py);
                    kwargs.set_item("order", "F")?;
                    kwargs
                }),
            )?;
            let theirs_fortran = numpy_full.call(
                ((2_i64, 3_i64), 9_i64),
                Some(&{
                    let kw = PyDict::new(py);
                    kw.set_item("order", "F")?;
                    kw
                }),
            )?;
            assert_array_matches_numpy(&ours_fortran, &theirs_fortran)?;
            let ours_f: bool = ours_fortran
                .getattr("flags")?
                .get_item("F_CONTIGUOUS")?
                .extract()?;
            let theirs_f: bool = theirs_fortran
                .getattr("flags")?
                .get_item("F_CONTIGUOUS")?
                .extract()?;
            assert_eq!(ours_f, theirs_f, "Fortran-contiguous flag mismatch");

            // Zero-sized dimensions should still preserve dtype and shape parity.
            assert_array_matches_numpy(
                &full_fn.call1(((0_i64, 3_i64), 5_i64))?,
                &numpy_full.call1(((0_i64, 3_i64), 5_i64))?,
            )?;

            // Scalar-array fills broadcast exactly like NumPy.
            let scalar_fill = numpy.getattr("array")?.call1((11_i64,))?;
            let ours_scalar_fill = full_fn.call1(((2_i64, 2_i64), scalar_fill.clone()))?;
            let theirs_scalar_fill = numpy_full.call1(((2_i64, 2_i64), scalar_fill.clone()))?;
            assert_array_matches_numpy(&ours_scalar_fill, &theirs_scalar_fill)?;

            Ok(())
        });
    }

    #[test]
    fn full_like_matches_numpy_across_layout_dtype_shape_subok_object_and_zero() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let full_like_fn = module.getattr("full_like")?;
            let numpy = py.import("numpy")?;
            let numpy_full_like = numpy.getattr("full_like")?;

            // Default dtype/order should follow the input array.
            let fortran_source = numpy
                .getattr("asfortranarray")?
                .call1((vec![vec![1_i64, 2, 3], vec![4_i64, 5, 6]],))?;
            let ours_default = full_like_fn.call1((fortran_source.clone(), 9_i64))?;
            let theirs_default = numpy_full_like.call1((fortran_source.clone(), 9_i64))?;
            assert_array_matches_numpy(&ours_default, &theirs_default)?;
            assert_eq!(
                ours_default.getattr("dtype")?.str()?.extract::<String>()?,
                theirs_default
                    .getattr("dtype")?
                    .str()?
                    .extract::<String>()?
            );
            let ours_f: bool = ours_default
                .getattr("flags")?
                .get_item("F_CONTIGUOUS")?
                .extract()?;
            let theirs_f: bool = theirs_default
                .getattr("flags")?
                .get_item("F_CONTIGUOUS")?
                .extract()?;
            assert_eq!(ours_f, theirs_f, "default order inheritance mismatch");

            // Explicit dtype override must match NumPy's coercion.
            let ours_dtype = full_like_fn.call(
                (fortran_source.clone(), 1.5_f64),
                Some(&{
                    let kwargs = PyDict::new(py);
                    kwargs.set_item("dtype", numpy.getattr("float64")?)?;
                    kwargs
                }),
            )?;
            let theirs_dtype = numpy_full_like.call(
                (fortran_source.clone(), 1.5_f64),
                Some(&{
                    let kwargs = PyDict::new(py);
                    kwargs.set_item("dtype", numpy.getattr("float64")?)?;
                    kwargs
                }),
            )?;
            assert_array_matches_numpy(&ours_dtype, &theirs_dtype)?;

            // shape= overrides output shape while preserving fill semantics.
            let ours_shape = full_like_fn.call(
                (fortran_source.clone(), -2_i64),
                Some(&{
                    let kwargs = PyDict::new(py);
                    kwargs.set_item("shape", (3_i64,))?;
                    kwargs
                }),
            )?;
            let theirs_shape = numpy_full_like.call(
                (fortran_source.clone(), -2_i64),
                Some(&{
                    let kwargs = PyDict::new(py);
                    kwargs.set_item("shape", (3_i64,))?;
                    kwargs
                }),
            )?;
            assert_array_matches_numpy(&ours_shape, &theirs_shape)?;

            // Object fill values should preserve object dtype and contents.
            let object_source = object_array(py, vec!["east", "west"]);
            let object_fill = PyDict::new(py);
            object_fill.set_item("route", "north")?;
            let ours_object = full_like_fn.call(
                (object_source.clone(), object_fill.clone()),
                Some(&{
                    let kwargs = PyDict::new(py);
                    kwargs.set_item("dtype", numpy.getattr("object_")?)?;
                    kwargs
                }),
            )?;
            let theirs_object = numpy_full_like.call(
                (object_source.clone(), object_fill.clone()),
                Some(&{
                    let kwargs = PyDict::new(py);
                    kwargs.set_item("dtype", numpy.getattr("object_")?)?;
                    kwargs
                }),
            )?;
            assert_array_matches_numpy(&ours_object, &theirs_object)?;

            // subok controls whether ndarray subclasses are preserved.
            let matrix_type = numpy.getattr("matrix")?;
            let matrix_input = matrix_type.call1((vec![vec![1_i64, 2], vec![3, 4]],))?;
            let ours_subok = full_like_fn.call1((matrix_input.clone(), 5_i64))?;
            let theirs_subok = numpy_full_like.call1((matrix_input.clone(), 5_i64))?;
            assert_eq!(
                ours_subok.get_type().name()?.extract::<String>()?,
                theirs_subok.get_type().name()?.extract::<String>()?,
                "subok=True subclass preservation mismatch",
            );
            assert_array_matches_numpy(&ours_subok, &theirs_subok)?;

            let ours_no_subok = full_like_fn.call(
                (matrix_input.clone(), 6_i64),
                Some(&{
                    let kwargs = PyDict::new(py);
                    kwargs.set_item("subok", false)?;
                    kwargs
                }),
            )?;
            let theirs_no_subok = numpy_full_like.call(
                (matrix_input.clone(), 6_i64),
                Some(&{
                    let kwargs = PyDict::new(py);
                    kwargs.set_item("subok", false)?;
                    kwargs
                }),
            )?;
            assert_eq!(
                ours_no_subok.get_type().name()?.extract::<String>()?,
                theirs_no_subok.get_type().name()?.extract::<String>()?,
                "subok=False base-array surface mismatch",
            );
            assert_array_matches_numpy(&ours_no_subok, &theirs_no_subok)?;

            // Zero-sized inputs should still preserve dtype/layout parity.
            let zero_source = numpy.getattr("empty")?.call1(((0_i64, 3_i64),))?;
            let ours_zero = full_like_fn.call1((zero_source.clone(), 4_i64))?;
            let theirs_zero = numpy_full_like.call1((zero_source.clone(), 4_i64))?;
            assert_array_matches_numpy(&ours_zero, &theirs_zero)?;

            Ok(())
        });
    }

    #[test]
    fn arange_matches_numpy_across_stop_start_step_dtype_and_empty_ranges() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let arange_fn = module.getattr("arange")?;
            let numpy = py.import("numpy")?;
            let numpy_arange = numpy.getattr("arange")?;

            // Single-argument stop form.
            assert_array_matches_numpy(
                &arange_fn.call1((5_i64,))?,
                &numpy_arange.call1((5_i64,))?,
            )?;

            // Explicit start/stop/step traversal.
            assert_array_matches_numpy(
                &arange_fn.call1((1_i64, 8_i64, 2_i64))?,
                &numpy_arange.call1((1_i64, 8_i64, 2_i64))?,
            )?;

            // Negative-step parity.
            assert_array_matches_numpy(
                &arange_fn.call1((5_i64, -1_i64, -2_i64))?,
                &numpy_arange.call1((5_i64, -1_i64, -2_i64))?,
            )?;

            // Explicit dtype coercion should match NumPy exactly.
            let dtype_kwargs = PyDict::new(py);
            dtype_kwargs.set_item("dtype", numpy.getattr("float64")?)?;
            let ours_dtype = arange_fn.call((4_i64,), Some(&dtype_kwargs))?;
            let theirs_dtype = numpy_arange.call((4_i64,), Some(&dtype_kwargs))?;
            assert_array_matches_numpy(&ours_dtype, &theirs_dtype)?;

            // Float-step behavior, including endpoint rounding surface.
            assert_array_matches_numpy(
                &arange_fn.call1((0.5_f64, 2.5_f64, 0.5_f64))?,
                &numpy_arange.call1((0.5_f64, 2.5_f64, 0.5_f64))?,
            )?;

            // Empty-range parity should preserve dtype/shape exactly.
            assert_array_matches_numpy(
                &arange_fn.call1((3_i64, 3_i64))?,
                &numpy_arange.call1((3_i64, 3_i64))?,
            )?;

            Ok(())
        });
    }

    #[test]
    fn linspace_matches_numpy_across_endpoint_retstep_dtype_and_axis() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let linspace_fn = module.getattr("linspace")?;
            let numpy = py.import("numpy")?;
            let numpy_linspace = numpy.getattr("linspace")?;
            let isclose = numpy.getattr("isclose")?;

            // Default endpoint=True with integer endpoints.
            assert_array_matches_numpy(
                &linspace_fn.call1((0_i64, 5_i64))?,
                &numpy_linspace.call1((0_i64, 5_i64))?,
            )?;

            // endpoint=False with float endpoints.
            let endpoint_kwargs = PyDict::new(py);
            endpoint_kwargs.set_item("num", 5_i64)?;
            endpoint_kwargs.set_item("endpoint", false)?;
            assert_array_matches_numpy(
                &linspace_fn.call((0.5_f64, 2.5_f64), Some(&endpoint_kwargs))?,
                &numpy_linspace.call((0.5_f64, 2.5_f64), Some(&endpoint_kwargs))?,
            )?;

            // retstep=True must return the same array/step tuple surface.
            let retstep_kwargs = PyDict::new(py);
            retstep_kwargs.set_item("num", 5_i64)?;
            retstep_kwargs.set_item("retstep", true)?;
            let ours_retstep = linspace_fn.call((1.0_f64, 3.0_f64), Some(&retstep_kwargs))?;
            let theirs_retstep = numpy_linspace.call((1.0_f64, 3.0_f64), Some(&retstep_kwargs))?;
            let ours_tuple = ours_retstep.cast::<PyTuple>()?;
            let theirs_tuple = theirs_retstep.cast::<PyTuple>()?;
            assert_eq!(ours_tuple.len()?, theirs_tuple.len()?);
            assert_array_matches_numpy(&ours_tuple.get_item(0)?, &theirs_tuple.get_item(0)?)?;
            let step_ok: bool = isclose
                .call1((&ours_tuple.get_item(1)?, &theirs_tuple.get_item(1)?))?
                .extract()?;
            assert!(step_ok, "linspace retstep mismatch");

            // Explicit dtype override should match NumPy exactly.
            let dtype_kwargs = PyDict::new(py);
            dtype_kwargs.set_item("dtype", numpy.getattr("float32")?)?;
            dtype_kwargs.set_item("num", 4_i64)?;
            assert_array_matches_numpy(
                &linspace_fn.call((1_i64, 4_i64), Some(&dtype_kwargs))?,
                &numpy_linspace.call((1_i64, 4_i64), Some(&dtype_kwargs))?,
            )?;

            // Axis insertion on vectorized start/stop inputs.
            let starts = numpy.getattr("array")?.call1((vec![0.0_f64, 10.0_f64],))?;
            let stops = numpy.getattr("array")?.call1((vec![1.0_f64, 20.0_f64],))?;
            let axis_kwargs = PyDict::new(py);
            axis_kwargs.set_item("num", 4_i64)?;
            axis_kwargs.set_item("axis", -1_i64)?;
            assert_array_matches_numpy(
                &linspace_fn.call((starts.clone(), stops.clone()), Some(&axis_kwargs))?,
                &numpy_linspace.call((starts.clone(), stops.clone()), Some(&axis_kwargs))?,
            )?;

            Ok(())
        });
    }

    #[test]
    fn geomspace_matches_numpy_across_scalar_negative_complex_dtype_and_axis() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let geomspace_fn = module.getattr("geomspace")?;
            let numpy = py.import("numpy")?;
            let numpy_geomspace = numpy.getattr("geomspace")?;

            // Positive scalar endpoints.
            assert_array_matches_numpy(
                &geomspace_fn.call1((1.0_f64, 1000.0_f64))?,
                &numpy_geomspace.call1((1.0_f64, 1000.0_f64))?,
            )?;

            // Supported negative endpoints should match NumPy exactly.
            assert_array_matches_numpy(
                &geomspace_fn.call1((-1.0_f64, -1000.0_f64))?,
                &numpy_geomspace.call1((-1.0_f64, -1000.0_f64))?,
            )?;

            // Supported complex endpoint surface parity.
            let complex_start = py
                .import("builtins")?
                .getattr("complex")?
                .call1((0_i64, 1_i64))?;
            let complex_stop = py
                .import("builtins")?
                .getattr("complex")?
                .call1((0_i64, 1000_i64))?;
            assert_array_matches_numpy(
                &geomspace_fn.call1((complex_start.clone(), complex_stop.clone()))?,
                &numpy_geomspace.call1((complex_start.clone(), complex_stop.clone()))?,
            )?;

            // endpoint=False and explicit dtype override.
            let dtype_kwargs = PyDict::new(py);
            dtype_kwargs.set_item("num", 4_i64)?;
            dtype_kwargs.set_item("endpoint", false)?;
            dtype_kwargs.set_item("dtype", numpy.getattr("float32")?)?;
            assert_array_matches_numpy(
                &geomspace_fn.call((1_i64, 16_i64), Some(&dtype_kwargs))?,
                &numpy_geomspace.call((1_i64, 16_i64), Some(&dtype_kwargs))?,
            )?;

            // Axis insertion on vectorized start/stop inputs.
            let starts = numpy.getattr("array")?.call1((vec![1.0_f64, 10.0_f64],))?;
            let stops = numpy
                .getattr("array")?
                .call1((vec![100.0_f64, 1000.0_f64],))?;
            let axis_kwargs = PyDict::new(py);
            axis_kwargs.set_item("num", 4_i64)?;
            axis_kwargs.set_item("axis", -1_i64)?;
            assert_array_matches_numpy(
                &geomspace_fn.call((starts.clone(), stops.clone()), Some(&axis_kwargs))?,
                &numpy_geomspace.call((starts.clone(), stops.clone()), Some(&axis_kwargs))?,
            )?;

            Ok(())
        });
    }

    #[test]
    fn zeros_like_matches_numpy_across_layout_dtype_shape_object_scalar_and_zero() {
        with_python(|py| {
            if !numpy_available(py) {
                return Ok(());
            }

            let module = PyModule::new(py, "fnp_python_test")?;
            fnp_python(&module)?;
            let zeros_like_fn = module.getattr("zeros_like")?;
            let numpy = py.import("numpy")?;
            let numpy_zeros_like = numpy.getattr("zeros_like")?;

            // Default dtype/order should follow the input array.
            let fortran_source = numpy
                .getattr("asfortranarray")?
                .call1((vec![vec![1_i64, 2, 3], vec![4_i64, 5, 6]],))?;
            let ours_default = zeros_like_fn.call1((fortran_source.clone(),))?;
            let theirs_default = numpy_zeros_like.call1((fortran_source.clone(),))?;
            assert_array_matches_numpy(&ours_default, &theirs_default)?;
            let ours_f: bool = ours_default
                .getattr("flags")?
                .get_item("F_CONTIGUOUS")?
                .extract()?;
            let theirs_f: bool = theirs_default
                .getattr("flags")?
                .get_item("F_CONTIGUOUS")?
                .extract()?;
            assert_eq!(ours_f, theirs_f, "default order inheritance mismatch");

            // Explicit dtype override must match NumPy's coercion.
            let ours_dtype = zeros_like_fn.call(
                (fortran_source.clone(),),
                Some(&{
                    let kwargs = PyDict::new(py);
                    kwargs.set_item("dtype", numpy.getattr("float64")?)?;
                    kwargs
                }),
            )?;
            let theirs_dtype = numpy_zeros_like.call(
                (fortran_source.clone(),),
                Some(&{
                    let kwargs = PyDict::new(py);
                    kwargs.set_item("dtype", numpy.getattr("float64")?)?;
                    kwargs
                }),
            )?;
            assert_array_matches_numpy(&ours_dtype, &theirs_dtype)?;

            // shape= overrides output shape while preserving zero-fill semantics.
            let ours_shape = zeros_like_fn.call(
                (fortran_source.clone(),),
                Some(&{
                    let kwargs = PyDict::new(py);
                    kwargs.set_item("shape", (3_i64,))?;
                    kwargs
                }),
            )?;
            let theirs_shape = numpy_zeros_like.call(
                (fortran_source.clone(),),
                Some(&{
                    let kwargs = PyDict::new(py);
                    kwargs.set_item("shape", (3_i64,))?;
                    kwargs
                }),
            )?;
            assert_array_matches_numpy(&ours_shape, &theirs_shape)?;

            // Object dtype zero-fill should match NumPy's Python object payloads.
            let object_source = object_array(py, vec!["east", "west"]);
            let ours_object = zeros_like_fn.call(
                (object_source.clone(),),
                Some(&{
                    let kwargs = PyDict::new(py);
                    kwargs.set_item("dtype", numpy.getattr("object_")?)?;
                    kwargs
                }),
            )?;
            let theirs_object = numpy_zeros_like.call(
                (object_source.clone(),),
                Some(&{
                    let kwargs = PyDict::new(py);
                    kwargs.set_item("dtype", numpy.getattr("object_")?)?;
                    kwargs
                }),
            )?;
            assert_array_matches_numpy(&ours_object, &theirs_object)?;

            // Scalar input parity should match NumPy's 0-d output exactly.
            assert_array_matches_numpy(
                &zeros_like_fn.call1((7_i64,))?,
                &numpy_zeros_like.call1((7_i64,))?,
            )?;

            // Zero-sized inputs should still preserve dtype/layout parity.
            let zero_source = numpy.getattr("empty")?.call1(((0_i64, 3_i64),))?;
            let ours_zero = zeros_like_fn.call1((zero_source.clone(),))?;
            let theirs_zero = numpy_zeros_like.call1((zero_source.clone(),))?;
            assert_array_matches_numpy(&ours_zero, &theirs_zero)?;

            Ok(())
        });
    }

